INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_01', '柳州肥姨妈大骨螺蛳粉(邮电大学店)', 'restaurant', '', 'place_001', 39.9568523, 116.3532201, '学院南路甲7号', 263, '¥', 21.0, '15280008790', 'https://aos-comment.amap.com/B0KD2NKR92/comment/176953312260_1769533123313_99099561.jpg', '["https://aos-comment.amap.com/B0KD2NKR92/comment/176953312260_1769533123313_99099561.jpg", "https://aos-comment.amap.com/B0KD2NKR92/comment/content_media_external_file_1000075934_ss__1765124106833_35994957.jpg", "https://aos-comment.amap.com/B0KD2NKR92/comment/content_media_external_file_1000062705_ss__1762261200050_91918605.jpg"]', '["学生友好", "平价美食", "嗦粉圣地", "深夜营业", "网红打卡"]', 4.7, 0, 0, '邮电大学旁超人气螺蛳粉店，大骨熬汤鲜香浓郁，肥姨妈秘制配方让你一口入魂，人均21元就能吃撑！', '走进店里，酸笋的独特香气扑面而来，瞬间唤醒味蕾。招牌大骨螺蛳粉汤底用猪骨和螺蛳慢炖数小时，浓郁鲜甜，配上爽滑米粉、酸笋、花生、腐竹，每一口都是满足。店内环境干净明亮，座位紧凑但翻台快，饭点常排长队。适合下课后来一碗解馋，或和室友一起嗦粉聊天。学生党必打卡的平价美食。', 1, '招牌大骨螺蛳粉');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_02', '小三峡巫山烤鱼(邮大店)', 'restaurant', '', 'place_001', 39.9563865, 116.3524516, '北京城区学院南路32号', 328, '¥¥¥', 82.0, '010-62237127', 'https://store.is.autonavi.com/showpic/67e3b00663a823ef37c60a6cbc88ff9c', '["https://store.is.autonavi.com/showpic/67e3b00663a823ef37c60a6cbc88ff9c", "https://aos-comment.amap.com/B000A8VXDZ/comment/161cd3f1d0f2837348e33e420ab374dd_2048_2048_80.jpg", "https://store.is.autonavi.com/showpic/03c850b0b4406b9f0000001020488850?type=pic"]', '["学生友好", "适合聚会", "麻辣鲜香", "人气爆棚", "性价比高"]', 4.6, 0, 0, '邮大学子聚餐首选，烤鱼外焦里嫩，麻辣鲜香，人均82元享受巫山风味盛宴。', '这家店是北邮人的聚会根据地，暖黄灯光下木质桌椅透着温馨。招牌巫山烤鱼现杀现烤，鱼皮焦脆、鱼肉嫩滑，铺满辣椒和花椒，麻辣过瘾。还有多种配菜可选，如土豆、豆皮、藕片，吸满汤汁超下饭。服务热情，上菜快，适合社团聚餐、生日派对或周末小聚。价格适中，性价比高。', 0, '巫山麻辣烤鱼');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_03', '兰蕙餐厅', 'restaurant', 'restaurant', 'place_001', 39.9575689, 116.355405, '新街口外大街19号北京师范大学兰惠公寓2楼', 238, '¥¥', 41.0, '010-58804123;010-58807151', 'https://aos-comment.amap.com/B000A8Z1VE/comment/02db0492a92a9e07a090fe18693d9ee3_2048_2048_80.jpg', '["https://aos-comment.amap.com/B000A8Z1VE/comment/02db0492a92a9e07a090fe18693d9ee3_2048_2048_80.jpg", "https://aos-comment.amap.com/B000A8Z1VE/comment/943d3120ab8f9ab3d9ed8fb14f9f4b76_2048_2048_80.jpg", "https://store.is.autonavi.com/showpic/a1874c3b872249ad00960c6670ade3f5"]', '["学生友好", "环境优雅", "家常味道", "适合约会", "校园食堂"]', 4.5, 0, 0, '北师大兰蕙公寓内的宝藏餐厅，环境雅致，菜品丰富，人均41元享受校园里的精致味道。', '坐落在北师大校园内，兰蕙餐厅以温馨雅致的环境著称，落地窗旁绿植环绕，适合安静用餐或自习后放松。菜单涵盖家常菜、川菜、粤菜等，推荐糖醋里脊、宫保鸡丁和酸菜鱼，分量足味道正。服务细致，上菜快，是师生们日常改善伙食的好去处。适合约会、朋友小聚或家庭来访。', 1, '糖醋里脊');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_04', '杨记老门框百年卤煮(北邮店)', 'restaurant', 'restaurant', 'place_001', 39.9568657, 116.3535854, '北京城区学院南路5号', 260, '¥', 29.0, '15116973081', 'https://store.is.autonavi.com/showpic/ded6a09b240469440000002368516495?type=pic', '["https://store.is.autonavi.com/showpic/ded6a09b240469440000002368516495?type=pic", "https://aos-comment.amap.com/B0IBX5QW6F/comment/1a70f66689bd6aab0ddfdeec136ad623_2048_2048_80.jpg", "https://aos-comment.amap.com/B0IBX5QW6F/comment/content_media_external_file_100012302_1772679204364_73887789.jpg"]', '["学生友好", "老北京味道", "平价美食", "深夜营业", "地道小吃"]', 4.5, 0, 0, '北邮附近正宗老北京卤煮，百年老门框秘方，大肠软糯火烧劲道，人均29元吃地道京味儿。', '小店不大，但烟火气十足，墙上挂着老北京胡同照片，氛围感满满。卤煮火烧是招牌，大肠处理得干净软糯，肺头鲜嫩，火烧吸饱汤汁后外软内韧，配上蒜泥、香菜和辣椒油，一口下去超满足。老板热情实在，会贴心提醒加汤。适合想尝鲜的外地同学或怀念老味道的北京娃。', 1, '卤煮火烧');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_05', '刘文祥麻辣烫(邮电大学店)', 'restaurant', '', 'place_001', 39.9568847, 116.3529545, '学院南路9号1幢104号', 263, '¥', 25.0, '18511216789', 'http://store.is.autonavi.com/query_pic?id=stfe171cdc-f9a1-4339-928a-ae3f052947cc&user=search&operate=original', '["http://store.is.autonavi.com/query_pic?id=stfe171cdc-f9a1-4339-928a-ae3f052947cc&user=search&operate=original", "https://aos-comment.amap.com/B0K3JCG2TJ/comment/content_media_external_images_media_1000020233_ss__1742740518591_62990873.jpg", "https://aos-comment.amap.com/B0K3JCG2TJ/comment/content_media_external_images_media_1000019792_ss__1754474665561_31501919.jpg"]', '["学生友好", "平价美食", "麻辣鲜香", "自选搭配", "外卖首选"]', 4.5, 0, 0, '邮电大学门口的麻辣烫扛把子，刘文祥秘制汤底麻辣鲜香，人均25元自选食材吃到爽。', '一进门就能闻到浓郁的麻辣香气，冰柜里几十种食材任选，从蔬菜、丸子到肉类、豆制品，新鲜干净。汤底是灵魂，用多种香料熬制，辣而不燥，麻而不苦，配上芝麻酱更香浓。店内座位不多，但外卖订单火爆。适合一个人快速解决午餐，或和同学一起边涮边聊。', 1, '秘制麻辣汤底');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_06', '嘿!延边碳火烤肉', 'restaurant', 'restaurant', 'place_001', 39.9568747, 116.3529126, '北京城区学院南路9号', 265, '¥¥¥', 103.0, '13811695066', 'https://aos-comment.amap.com/B0JDMH3PJV/comment/content_media_external_file_100007674_1755839884089_52481133.jpg', '["https://aos-comment.amap.com/B0JDMH3PJV/comment/content_media_external_file_100007674_1755839884089_52481133.jpg", "http://store.is.autonavi.com/showpic/b62c9d866caabe1e24c8c5385e959c26", "https://aos-comment.amap.com/B0JDMH3PJV/comment/46a3263128899fe7f77e78e741a35eaf_2048_2048_80.jpg"]', '["适合聚会", "韩式烤肉", "深夜营业", "肉食天堂", "环境舒适"]', 4.5, 0, 0, '延边风味碳火烤肉，肉香四溢，人均103元享受正宗韩式烤肉体验，邮大旁的深夜食堂。', '店内装修充满韩式风情，碳火烤炉让每片肉都带着烟熏香。推荐五花肉、牛舌和调味牛排，肉质鲜嫩多汁，蘸上特制酱料用生菜包着吃，清爽解腻。还有延边特色冷面和石锅拌饭，可作主食。服务周到，服务员会帮忙烤肉。适合庆祝、约会或想大快朵颐的日子。', 0, '碳烤五花肉');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_07', '味多美(明光桥东店)', 'restaurant', 'bakery', 'place_001', 39.9568717, 116.3529386, '北京城区市学院南路9号(明光桥东邮电大学南门向东100米)', 265, '¥¥', 32.0, '010-62210110', 'https://store.is.autonavi.com/showpic/4d6f5dd8a2161352bc1950f2cba2da87?operate=original', '["https://store.is.autonavi.com/showpic/4d6f5dd8a2161352bc1950f2cba2da87?operate=original", "http://store.is.autonavi.com/showpic/944b5f745da9643f1523c6c4152ea82a", "http://store.is.autonavi.com/showpic/eec444393a9655ad9e30f5ce93f4b70c"]', '["学生友好", "平价美食", "面包甜点", "早餐首选", "下午茶"]', 4.5, 0, 0, '邮电大学南门旁的烘焙天堂，蛋挞、面包、蛋糕琳琅满目，人均32元甜蜜满格。', '明光桥东的味多美是北邮人的甜蜜补给站，店面明亮整洁，玻璃柜里摆满刚出炉的面包和甜点。招牌蛋挞外酥里嫩，奶香浓郁；老婆饼皮薄馅甜；还有各种吐司、蛋糕和饮品。适合早餐买杯豆浆配三明治，或下午茶来块蛋糕解馋。价格亲民，是学生党日常囤粮的好地方。', 1, '招牌蛋挞');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_08', '莫小卤桂林米粉', 'restaurant', 'restaurant', 'place_001', 39.956818, 116.3533947, '学院南路7号平房', 265, '¥', 24.0, '13120259946', 'https://store.is.autonavi.com/showpic/621369360cd2e5b50000002348498640?type=pic', '["https://store.is.autonavi.com/showpic/621369360cd2e5b50000002348498640?type=pic", "https://store.is.autonavi.com/showpic/788bfb02b4b728d40000002248232173?type=pic", "https://aos-comment.amap.com/B0LKYU3MS0/comment/content_media_external_file_59256_ss__1766987028604_15894161.jpg"]', '["学生友好", "平价美食", "正宗桂林味", "快速简餐", "外卖友好"]', 4.5, 0, 0, '学院南路上的桂林米粉小馆，卤水浓郁，米粉爽滑，人均24元吃出正宗广西味。', '小店虽不大，但桂林米粉的香味能飘到街对面。招牌卤菜粉用秘制卤水拌制，配上锅烧、叉烧、花生和酸豆角，拌匀后每一根米粉都裹满酱汁，入口顺滑。汤粉也值得一试，汤底用猪骨熬制，清淡鲜美。老板是广西人，用料实在。适合赶课时快速解决一餐，或想换换口味时。', 1, '卤菜粉');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_09', '津满楼天津菜', 'restaurant', 'restaurant', 'place_001', 39.9553469, 116.3521822, '文慧园西路与学院南路交叉口南140米', 445, '¥¥', 71.0, '15645986807', 'https://store.is.autonavi.com/showpic/2617c2c7d289f5a80000002340124972?type=pic', '["https://store.is.autonavi.com/showpic/2617c2c7d289f5a80000002340124972?type=pic", "https://store.is.autonavi.com/showpic/d88eb7d43332c3b40000002096654491?type=pic", "https://store.is.autonavi.com/showpic/71e7937b26a6bc9e0000002340138739?type=pic"]', '["适合聚会", "天津风味", "经典老店", "分量十足", "环境雅致"]', 4.6, 0, 0, '学院南路老牌天津菜馆，锅塌里脊、八珍豆腐等经典菜色，人均71元体验津门风味。', '津满楼环境古朴大气，红木桌椅和宫灯营造出老天津氛围。菜品地道，推荐锅塌里脊——鸡蛋裹着嫩滑里脊，口感层次丰富；八珍豆腐用料十足，海参、虾仁、鱿鱼样样有。分量大，适合多人聚餐。服务热情，会主动介绍菜品。适合带外地同学体验北方菜，或家庭聚餐。', 0, '锅塌里脊');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_10', '麦当劳(北京邮电大学餐厅内部专用)', 'restaurant', '', 'place_001', 39.962292, 116.3513399, '北太平庄街道西土城路10号41幢1层100室', 394, '¥¥', 34.0, '4009200205', 'https://aos-comment.amap.com/B0JB1AFNJE/comment/content_media_external_file_100000457_1773629860293_20944161.jpg', '["https://aos-comment.amap.com/B0JB1AFNJE/comment/content_media_external_file_100000457_1773629860293_20944161.jpg", "https://aos-comment.amap.com/B0JB1AFNJE/comment/20260323-3903f4c479ef36a41328c4a0-7fSanFMfYfQ9YCVOX4tNeQ.jpg", "https://aos-comment.amap.com/B0JB1AFNJE/comment/2a0a033e59a2076394af98a8b7f0c9b1_2048_2048_80.jpg"]', '["学生友好", "快餐圣地", "校园内", "深夜营业", "效率高"]', 4.5, 0, 0, '北邮校园内的麦当劳，专属学生党的快餐圣地，人均34元快速解决三餐。', '这家麦当劳位于北邮校园内部，是学生们最方便的用餐选择之一。店内宽敞明亮，设有充电插座和免费WiFi，适合自习或休息。经典巨无霸、麦辣鸡腿堡和薯条是永远的神，还有学生优惠套餐和甜品站。出餐快，服务高效。适合课间快速填饱肚子，或深夜复习时来份麦乐送。', 1, '巨无霸套餐');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_11', '一佰烤场BBQ生态烧烤烤鱼香锅', 'restaurant', '', 'place_001', 39.9568577, 116.3536014, '北京城区学院南路5号101号', 260, '¥¥', 79.0, '010-62266628', 'https://store.is.autonavi.com/showpic/732529e3b318ab8e0000002655518979?type=pic', '["https://store.is.autonavi.com/showpic/732529e3b318ab8e0000002655518979?type=pic", "https://aos-comment.amap.com/B0FFL5EPZK/comment/e5cddc5045f0bf98e704818a05693ebb_2048_2048_80.jpg", "https://aos-comment.amap.com/B0FFL5EPZK/comment/86f65c2b670d748bcfd65f5e81d7e560_2048_2048_80.jpg"]', '["聚会首选", "烟火气", "性价比高", "适合夜宵", "学生友好"]', 4.4, 0, 0, '烧烤、烤鱼、香锅一网打尽，北邮旁260米的烟火气聚集地！人均79元吃到撑，社团聚会、宿舍夜宵的绝佳选择。', '走进一佰烤场，炭火香气扑面而来，室内外座位宽敞，热闹的烟火气瞬间拉满氛围感。主打生态烧烤和麻辣香锅，烤鱼外焦里嫩，香锅配料丰富，适合三五好友围坐撸串聊天。服务热情，上菜速度快，还有免费小菜和饮品续杯，性价比超高。无论是庆祝考试结束还是周末小聚，这里都能让你吃到尽兴。', 0, '推荐招牌烤鱼');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_12', '蜜雪冰城(学院南路店)', 'restaurant', 'cold_drink', 'place_001', 39.9568778, 116.3541663, '西土城路10号5幢平房2号门', 263, '¥', 7.0, '18801237251', 'http://store.is.autonavi.com/query_pic?id=st2c745913-adf3-4bec-a8ae-2ecccab199fe&user=search&operate=original', '["http://store.is.autonavi.com/query_pic?id=st2c745913-adf3-4bec-a8ae-2ecccab199fe&user=search&operate=original", "https://store.is.autonavi.com/showpic/4a965401dd7fc9480000000963504503?type=pic", "https://aos-comment.amap.com/B0I2CP7NGQ/comment/703784D9_5F44_4695_8CE6_B1457E522525_L0_001_1439_1740_1728515806953_69185758.jpg"]', '["学生友好", "性价比高", "网红打卡", "甜食控", "平价饮品"]', 4.4, 0, 0, '蜜雪冰城，学生党的快乐源泉！人均7元，冰淇淋、柠檬水、奶茶样样经典，距北邮仅263米，下课顺路就能来一杯。', '蜜雪冰城永远是人气爆棚的平价茶饮店，学院南路店靠近校园，下课高峰常排长队。招牌柠檬水清爽解渴，甜筒冰淇淋奶香浓郁，奶茶系列甜而不腻，价格亲民到闭眼点单。店内装修简约明亮，适合打包带走或站着快速喝一杯。学生证还能享受隐藏优惠，是夏天解暑、冬天暖手的日常必备。', 1, '推荐柠檬水');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_13', '北京稻香村(瑞盛店)', 'restaurant', 'bakery', 'place_001', 39.9562856, 116.3474104, '学院南路38号智慧大厦底商', 619, '¥¥', 44.0, '010-62216190;13381217117', 'https://aos-comment.amap.com/B000A85LD3/comment/file_media_Photo_10158_IMG_1758777531_9793_IMG_20250925_131711_jpg_ss_2.jpg', '["https://aos-comment.amap.com/B000A85LD3/comment/file_media_Photo_10158_IMG_1758777531_9793_IMG_20250925_131711_jpg_ss_2.jpg", "http://store.is.autonavi.com/showpic/f4cd5efdf8a9facb50662b3a77b42c5a", "https://aos-comment.amap.com/B000A85LD3/comment/file_media_Photo_10156_IMG_1758773079_9792_IMG_20250925_120259_jpg_ss_2.jpg"]', '["老字号", "传统美食", "送礼佳品", "零食天堂", "学生友好"]', 4.6, 0, 0, '北京稻香村，老字号糕点铺，瑞盛店距校园619米。传统点心、熟食、零食一应俱全，送礼自用两相宜。', '稻香村是北京人从小吃到大的老字号，瑞盛店位于智慧大厦底商，环境整洁有序，糕点柜台琳琅满目。牛舌饼、枣泥酥、山楂锅盔是经典必买，熟食区的酱牛肉、猪头肉也备受好评。适合买来当早餐或宿舍零食，过节时礼盒装更是走亲访友的体面之选。店员热情周到，可以散称按需购买，对学生党很友好。', 0, '推荐牛舌饼');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_14', '木屋烧烤(海淀明光桥店)', 'restaurant', '', 'place_001', 39.9548289, 116.3485173, '西直门北大街1号一层05号', 651, '¥¥', 82.0, '19910709624', 'https://store.is.autonavi.com/showpic/ed1a61d953bdec3e0000001835750628?type=pic', '["https://store.is.autonavi.com/showpic/ed1a61d953bdec3e0000001835750628?type=pic", "https://store.is.autonavi.com/showpic/998a09f19b0c1a890000002383942051?type=pic", "http://store.is.autonavi.com/showpic/09e847cdc437a35018723555e77f2857"]', '["深夜营业", "聚会首选", "网红打卡", "烟火气", "适合夜宵"]', 4.6, 0, 0, '木屋烧烤海淀明光桥店，离校651米的撸串圣地！人均82元，环境时尚，烤串、烤海鲜、凉菜样样出彩，夜宵首选。', '木屋烧烤以工业风装修和明档厨房为特色，店内灯光暖黄，木桌木椅营造温馨氛围。招牌羊肉串肥瘦相间，烤鸡翅外皮焦脆，烤生蚝蒜香浓郁，搭配冰镇啤酒或酸梅汤，解馋又过瘾。服务生随叫随到，上菜速度快，适合社团聚餐或深夜解馋。距校园步行十分钟，是北邮人公认的夜宵根据地。', 0, '推荐羊肉串');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_15', '郭郭的小院(文慧园店)', 'restaurant', '', 'place_001', 39.9545814, 116.3525266, '文慧园西路11号', 522, '¥¥¥', 0.0, '010-62224220;13146224314', 'https://store.is.autonavi.com/showpic/71226c6846886ef20000002264180985?type=pic', '["https://store.is.autonavi.com/showpic/71226c6846886ef20000002264180985?type=pic", "https://aos-comment.amap.com/B0IG9DAUA5/comment/c62c981b6350d72b401c02b472349728_2048_2048_80.jpg", "https://aos-comment.amap.com/B0IG9DAUA5/comment/20260212-9dd698c1aebd789c4fd8e714-5cdhRQPX6p65cONF4I5yTZ.jpg"]', '["网红打卡", "环境优美", "适合约会", "文艺范", "精致美食"]', 4.5, 0, 0, '郭郭的小院，文慧园里的隐秘小馆，评分4.5。环境温馨如家，菜品精致，适合约会或闺蜜小聚。', '郭郭的小院藏在文慧园西路小巷里，推门而入是满院绿植和暖色灯光，像走进朋友家的客厅。菜品以创意家常菜为主，分量适中，摆盘精致，口味清淡健康。老板亲自下厨，服务亲切，会推荐当日隐藏菜单。适合情侣约会或三五好友聊天聚餐，人均虽未标价但中等偏上，环境绝对值得打卡。', 0, NULL);
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_16', '重庆小菜馆', 'restaurant', '', 'place_001', 39.9546351, 116.3520805, '学院南路32号院西院东2门旁', 524, '¥¥', 47.0, '13521320973', 'https://aos-comment.amap.com/B0LKYS3RVD/comment/file_media_Photo_25305_IMG_1769397903_24688_screenshot_20260126_112322_pn_1769397931500_81623275.jpg', '["https://aos-comment.amap.com/B0LKYS3RVD/comment/file_media_Photo_25305_IMG_1769397903_24688_screenshot_20260126_112322_pn_1769397931500_81623275.jpg", "https://aos-comment.amap.com/B0LKYS3RVD/comment/176750175765_1767501759299_53340303.jpg", "https://store.is.autonavi.com/showpic/0a0202d91a5980a84e9adf698a45766d"]', '["学生友好", "性价比高", "麻辣控", "适合聚餐", "下饭神器"]', 4.5, 0, 0, '重庆小菜馆，学院南路老店，人均47元吃正宗川菜！评分4.5，辣味十足，下饭神器，学生党的食堂级美味。', '重庆小菜馆是北邮周边的平价川菜馆，店面不大但干净整洁，墙上挂着川剧脸谱装饰。招牌水煮鱼、辣子鸡、毛血旺分量十足，麻辣鲜香，每道菜都超下饭。老板是重庆人，调料地道，米饭免费续，适合宿舍聚餐或下课解馋。服务热情，上菜快，价格实惠，人均47元就能吃到扶墙出。', 0, '推荐水煮鱼');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_17', '库迪咖啡(北京邮电大学校外店)', 'restaurant', 'snack', 'place_001', 39.9570552, 116.3538918, '学院南路9号1幢104号北京学院南路平房3号', 240, '¥', 9.0, '15801406951', 'https://store.is.autonavi.com/showpic/7b0db620ddccbe9ff42ce59100617216?operate=original?operate=original?operate=original?operate=original', '["https://store.is.autonavi.com/showpic/7b0db620ddccbe9ff42ce59100617216?operate=original?operate=original?operate=original?operate=original", "https://store.is.autonavi.com/showpic/2c008b0e1e3675b00000002769898442?type=pic", "https://aos-comment.amap.com/B0J3ACGXEZ/comment/20260323-9f97a82d8672cd767fbe1caa-6Fw2UztyCYo6xoGe6GbvDH.jpg"]', '["学生友好", "性价比高", "适合自习", "咖啡控", "网红打卡"]', 4.3, 0, 0, '库迪咖啡北邮校外店，距校240米，人均9元喝到现磨咖啡！学生党提神续命必备，性价比碾压星巴克。', '库迪咖啡以极简白色装修和快速出餐为特色，店内设有充电插座和WiFi，适合自习或小憩。经典美式、生椰拿铁、桃桃冰茶都是爆款，口感不输大牌，价格却低至个位数。学生证可享额外折扣，经常有买一送一活动。早晨一杯提神，下午一杯解乏，是北邮人学习备考的加油站。', 1, '推荐生椰拿铁');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_18', '豫石记羊汤(北邮店)', 'restaurant', 'restaurant', 'place_001', 39.9568785, 116.3537102, '学院南路西土城路10号', 258, '¥', 22.0, '18600973909', 'https://store.is.autonavi.com/showpic/f405040ca296181890ba60a8cd032aaa', '["https://store.is.autonavi.com/showpic/f405040ca296181890ba60a8cd032aaa", "https://aos-comment.amap.com/B0J2APOUK6/comment/content_media_external_file_1000044903_ss__1762388699842_58719422.jpg", "https://aos-comment.amap.com/B0J2APOUK6/comment/content_media_external_file_1000044900_ss__1762388699831_19638662.jpg"]', '["学生友好", "性价比高", "暖胃首选", "养生美食", "适合一人食"]', 4.3, 0, 0, '豫石记羊汤北邮店，距校258米，人均22元喝暖心暖胃羊肉汤！冬天暖身、夏天滋补，学生党的养生食堂。', '豫石记羊汤主打河南风味羊肉汤，店内热气腾腾，汤白肉嫩，搭配烧饼或粉丝，一碗下肚浑身暖和。羊肉鲜而不膻，汤底浓郁，可以免费续汤。小菜如凉拌羊杂、卤羊蹄也颇受欢迎。环境朴实，服务利落，适合一个人快速解决一餐或朋友简单小聚。价格实惠，是北邮人冬天必打卡的暖胃小店。', 1, '推荐羊肉汤');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_19', '茶百道(邮电大学店)', 'restaurant', 'cold_drink', 'place_001', 39.9568115, 116.3531013, '学院南路9号2幢101号', 269, '¥', 19.0, '18610199097', 'http://store.is.autonavi.com/query_pic?id=st403cff68-6a66-4b89-8244-2c48242140a2&user=search&operate=original', '["http://store.is.autonavi.com/query_pic?id=st403cff68-6a66-4b89-8244-2c48242140a2&user=search&operate=original", "https://aos-comment.amap.com/B0GK1HWS27/comment/C278C7F0_B530_4AE1_82FA_1355EF45B284_L0_001_1290_160_1755825675793_84178135.jpg", "http://store.is.autonavi.com/showpic/c2c56460a37744c2b0291de7b155c8bc"]', '["学生友好", "网红打卡", "甜食控", "性价比高", "适合拍照"]', 4.3, 0, 0, '茶百道邮电大学店，距校269米，人均19元喝到网红果茶！杨枝甘露、豆乳玉麒麟是爆款，学生党都在排。', '茶百道以新鲜水果茶和创意奶茶闻名，邮电大学店靠近校园，下课高峰常排长队。招牌杨枝甘露芒果味浓郁，豆乳玉麒麟奶盖绵密，果茶系列清爽解腻。店内装修粉嫩可爱，适合拍照打卡。支持小程序点单，学生证可享折扣，经常有买二送一活动。是午后小憩、逛街解渴的必备饮品。', 1, '推荐杨枝甘露');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_20', '布拉格餐厅(北邮店)', 'restaurant', '', 'place_001', 39.9631707, 116.3490442, '西土城路10号锦江商务酒店1层', 588, '¥¥¥', 141.0, '13269808099;18722331991', 'https://store.is.autonavi.com/showpic/35e802931f2aace50000001803808861?type=pic', '["https://store.is.autonavi.com/showpic/35e802931f2aace50000001803808861?type=pic", "https://aos-comment.amap.com/B0JDDLTRPI/comment/56f9b4a460bbbd164a5f8d62e210754d_2048_2048_80.jpg", "https://aos-comment.amap.com/B0JDDLTRPI/comment/content_media_external_images_media_30885_1736134272777_89218073.jpg"]', '["适合约会", "环境优美", "精致美食", "浪漫氛围", "适合纪念日"]', 4.5, 0, 0, '布拉格餐厅北邮店，人均141元，锦江商务酒店一层。环境优雅，菜品精致，适合约会或生日聚餐。', '布拉格餐厅以欧式复古装修和浪漫灯光为特色，环境安静私密，适合情侣约会或重要纪念日。主打西式简餐和捷克风味，如烤猪肘、牛排、意面等，摆盘精致，口味正宗。服务专业周到，提供免费餐前面包和沙拉。虽然价格偏高，但偶尔犒劳自己或庆祝特殊日子时，这里绝对是北邮周边的品质之选。', 0, '推荐烤猪肘');
