INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_40', '紫燕百味鸡(北京学院路店)', 'restaurant', '', 'place_001', 39.9568588, 116.3535025, '学院南路5号101号', 260, '¥', 35.0, '15712998769', 'http://store.is.autonavi.com/query_pic?id=sta0a759f3-d884-4bab-8452-52f0d8e37257&user=search&operate=original', '["http://store.is.autonavi.com/query_pic?id=sta0a759f3-d884-4bab-8452-52f0d8e37257&user=search&operate=original", "https://store.is.autonavi.com/showpic/f5cb15ded68fd53e0000002657228463?type=pic", "https://store.is.autonavi.com/showpic/58698bf22a1f96490db708ba0742311a"]', '[]', 4.1, 0, 0, '紫燕百味鸡(北京学院路店)', '', 0, NULL);
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_41', '好开心烧饼里脊(邮电大学店)', 'restaurant', '', 'place_001', 39.9568616, 116.3536513, '学院南路5号', 260, '¥', 10.0, '18222197917', 'http://store.is.autonavi.com/showpic/f0c23fa491f5c25d44069df316952b86', '["http://store.is.autonavi.com/showpic/f0c23fa491f5c25d44069df316952b86", "https://store.is.autonavi.com/showpic/9c75a6852cc8208d1bf72f77dd7f1347", "http://store.is.autonavi.com/showpic/f594d8893dd9a231f75d580977a7e854"]', '["学生友好", "早餐推荐", "平价美食", "出餐快"]', 4.1, 0, 0, '邮电大学门口的平价早餐之光！刚出锅的烧饼夹着嫩滑里脊，刷上秘制酱料，一口下去满满的幸福感。', '这家开在邮电大学门口的小店，是无数北邮学子晨起上课前的能量补给站。店面虽小，但干净整洁，老板动作麻利，出餐速度飞快。烧饼现烤现卖，外酥里软，里脊肉嫩滑多汁，搭配生菜和特调甜辣酱，口感层次丰富。人均10元就能吃得饱饱的，是赶早课、抢图书馆座位的绝佳选择。', 0, '经典烧饼里脊');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_42', '张亮麻辣烫(海淀校区北京邮电大学店)', 'restaurant', 'restaurant', 'place_001', 39.9568634, 116.353811, '西土城路10号7号平房', 260, '¥¥', 30.0, '13261771949', 'https://img.alicdn.com/imgextra/i2/O1CN013Da1GK1Ex2GzcHFBd_!!6000000000417-49-tps-750-750.webp', '["https://img.alicdn.com/imgextra/i2/O1CN013Da1GK1Ex2GzcHFBd_!!6000000000417-49-tps-750-750.webp", "https://store.is.autonavi.com/showpic/cc974503f00c932a0000002517034869?type=pic", "https://aos-comment.amap.com/B0FFLO0P6E/comment/6a6195d73b44c0bbc883b03e392e3868_2048_2048_80.jpg"]', '["学生友好", "深夜营业", "自助选菜", "暖身美食"]', 4.1, 0, 0, '北邮人最熟悉的麻辣烫味道！自选食材按斤称重，汤底浓郁，麻酱醇厚，是冬日暖身、深夜解馋的必备。', '张亮麻辣烫在北邮校区内，是学生们下课后的首选食堂之一。店内宽敞明亮，冰柜里摆满了新鲜蔬菜、豆制品、丸子和各种面食，自由搭配随心选。汤底有骨汤和麻辣两种，推荐加一勺浓稠的芝麻酱，再撒上花生碎和香菜，香气扑鼻。价格实惠，吃得饱又暖和，适合一个人快速解决一餐，也适合和室友一起边吃边聊。', 1, '麻酱麻辣烫');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_43', '长安面莊·洛阳牛肉汤', 'restaurant', 'restaurant', 'place_001', 39.9580893, 116.3400525, '四道口路2号院京果商厦B座', 1161, '¥', 27.0, '16637909728', 'https://aos-comment.amap.com/B0L22SZQMI/comment/content_media_external_file_355317_ss__1758770777664_49433868.jpg', '["https://aos-comment.amap.com/B0L22SZQMI/comment/content_media_external_file_355317_ss__1758770777664_49433868.jpg", "https://store.is.autonavi.com/showpic/2b693bb6a743a9030000002647848413?type=pic", "https://store.is.autonavi.com/showpic/49f804017595d9cc0000002647912146?type=pic"]', '["评分高", "早餐推荐", "汤鲜味美", "宝藏小店"]', 4.7, 0, 0, '评分4.7的洛阳牛肉汤，汤鲜肉嫩，饼丝一绝！清晨来一碗，暖胃又暖心，是附近学生的宝藏早餐地。', '这家藏在京果商厦里的洛阳牛肉汤店，是周边学生口口相传的宝藏美食。汤底用牛骨慢熬数小时，清澈见底却鲜味十足，牛肉片薄而嫩，搭配现烙的饼丝或烧饼，泡在汤里吸饱汤汁，一口下去满足感爆棚。店内装修简约干净，老板热情周到，还会贴心问你是否需要加汤。人均不到30元，就能享受一碗地道的洛阳风味，适合在没课的早晨慢慢品尝。', 0, '洛阳牛肉汤+饼丝');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_44', '拢隆炸货铺', 'restaurant', 'cafe', 'place_001', 39.9568317, 116.3529426, '北京城区学院南路9号', 269, '¥¥', 31.0, '13611010262', 'https://store.is.autonavi.com/showpic/725b87b0a5dd4f64b04ec0490846e728', '["https://store.is.autonavi.com/showpic/725b87b0a5dd4f64b04ec0490846e728", "https://aos-comment.amap.com/B0IK3CQI1Z/comment/458d6352c20f3430667f77752861760a_2048_2048_80.jpg", "https://aos-comment.amap.com/B0IK3CQI1Z/comment/e88bbc39a57a6d92ffe59a8ff0781f95_2048_2048_80.jpg"]', '["学生友好", "平价小吃", "现炸现卖", "适合分享"]', 4.1, 0, 0, '学院南路上的炸货小铺，现炸现卖，酥脆喷香！鸡排、薯条、炸串样样有，是课间解馋的快乐源泉。', '拢隆炸货铺就在学院南路，离北邮不过几步路，是学生们放学后扎堆的小吃据点。店里主打各种炸物，鸡排炸得金黄酥脆，咬开汁水四溢；薯条外焦里嫩，撒上椒盐粉特别香；还有炸串、炸蘑菇等，种类丰富。价格亲民，几块钱就能买一大份，边走边吃，解馋又过瘾。适合和同学一起买来分享，或者作为深夜追剧的零食。', 1, '招牌炸鸡排');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_45', '米村拌饭(枫蓝国际购物中心店)', 'restaurant', 'restaurant', 'place_001', 39.9519028, 116.3498661, '北京城区西直门北大街32号+B1楼B123号商铺', 872, '¥¥', 40.0, '13238256282', 'http://store.is.autonavi.com/query_pic?id=st596b1fbb-f39e-4563-a573-71db96d80dc8&user=search&operate=original', '["http://store.is.autonavi.com/query_pic?id=st596b1fbb-f39e-4563-a573-71db96d80dc8&user=search&operate=original", "https://aos-comment.amap.com/B0JUYZDA01/comment/content_media_external_images_media_3362_1743399820341_77454335.jpg", "https://aos-comment.amap.com/B0JUYZDA01/comment/e35baf777f41d3182833c04ea29bd4dc_2048_2048_80.jpg"]', '["学生友好", "韩式美食", "石锅拌饭", "商场店"]', 4.5, 0, 0, '枫蓝国际里的韩式拌饭专门店，石锅滋滋作响，锅巴焦香，酱料甜辣开胃，是学生党的干饭天堂。', '米村拌饭位于枫蓝国际购物中心地下一层，环境整洁明亮，座位舒适。招牌石锅拌饭上桌时还在滋滋作响，底部形成一层金黄锅巴，配上溏心蛋、菠菜、豆芽等丰富配菜，淋上韩式辣酱搅拌均匀，每一口都超满足。还有金枪鱼拌饭、辣炒年糕等选择，分量足，价格对学生友好。适合午餐或晚餐，一个人也能吃得丰盛又开心。', 0, '石锅拌饭');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_46', '好嫂子酱猪手·农家菜(学院南路店)', 'restaurant', '', 'place_001', 39.9564464, 116.3428907, '学院南路50号二层F218', 963, '¥¥¥', 69.0, '010-53979798', 'https://aos-comment.amap.com/B0FFJOTAB8/comment/2025-12-11-16-12-33%2B1428CAA3-4338-424A-AD99-0632885238D_1765440774762_52910951.jpg', '["https://aos-comment.amap.com/B0FFJOTAB8/comment/2025-12-11-16-12-33%2B1428CAA3-4338-424A-AD99-0632885238D_1765440774762_52910951.jpg", "https://aos-comment.amap.com/B0FFJOTAB8/comment/36ad6034-3bf9-4b91-b7ca-59717d15d0bb.png", "http://store.is.autonavi.com/showpic/20bcaf3cc704a9a1910a1f5abb03b707"]', '["适合聚餐", "农家菜", "酱猪手", "家常味道"]', 4.5, 0, 0, '学院南路上的农家菜馆，酱猪手软烂入味，农家菜实惠下饭，适合宿舍聚餐或改善伙食。', '好嫂子酱猪手·农家菜是学院南路上的一家温馨小馆，主打家常味道。招牌酱猪手炖得软糯脱骨，酱香浓郁，胶原蛋白满满；还有地三鲜、锅包肉等经典东北菜，分量实在，味道地道。店内环境朴实，服务员热情，适合几个同学一起聚餐，点几个菜配米饭，人均六七十元就能吃得相当丰盛。是考试结束后犒劳自己的好去处。', 0, '招牌酱猪手');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_47', '喜茶(北京枫蓝国际购物中心店)', 'restaurant', 'cold_drink', 'place_001', 39.9520526, 116.3505896, '西直门北大街32号院枫蓝国际购物中心F1层', 835, '¥¥', 19.0, '18710222383', 'http://store.is.autonavi.com/showpic/a017c8433499cac735939990d4a701e6', '["http://store.is.autonavi.com/showpic/a017c8433499cac735939990d4a701e6", "https://img.alicdn.com/imgextra/i1/O1CN01klC5Pb1EWTFUXx6tY_!!6000000000359-2-tps-72-72.png", "https://aos-comment.amap.com/B0H6PZMPN9/comment/456dddb8b250831338ab018d2024e419_2048_2048_80.jpg"]', '["学生友好", "网红饮品", "新品频出", "适合拍照"]', 4.4, 0, 0, '枫蓝国际一楼的喜茶，环境舒适，新品频出。课后来一杯多肉葡萄，清爽解渴，是北邮人的快乐水。', '喜茶在枫蓝国际购物中心一楼，位置显眼，装修简约时尚。店里常年人气爆棚，但出杯速度很快。招牌多肉葡萄果肉饱满，搭配芝士奶盖，酸甜清爽；还有芝芝莓莓、满杯红柚等经典款，以及季节限定的新品，总有一款合你心意。店内设有座位，适合自习间隙来放松一下，或者和同学逛街时买一杯边喝边逛。', 1, '多肉葡萄');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_48', '胖姐社区老火锅(哇沃生活广场店)', 'restaurant', '', 'place_001', 39.956495, 116.3425434, '哇沃生活广场底商1楼', 989, '¥¥¥', 102.0, '010-51053212', 'http://store.is.autonavi.com/showpic/9e2a394f3f8df960f16252744f87c7cc', '["http://store.is.autonavi.com/showpic/9e2a394f3f8df960f16252744f87c7cc", "https://aos-comment.amap.com/B0JAOAY34F/comment/content_media_external_images_media_6230_ss__1726047352398_88021094.jpg", "https://aos-comment.amap.com/B0JAOAY34F/comment/66a8b19bc2c849a06727c543e227db83_2048_2048_80.jpg"]', '["适合聚会", "重庆火锅", "麻辣鲜香", "怀旧风格"]', 4.5, 0, 0, '哇沃广场的社区老火锅，牛油锅底麻辣鲜香，菜品新鲜实惠，是宿舍聚会的热闹之选。', '胖姐社区老火锅开在哇沃生活广场底商，一进门就能闻到浓郁的牛油香。店内装修怀旧复古，墙上的老照片和搪瓷杯营造出社区火锅的氛围。锅底麻辣醇厚，越煮越香；推荐嫩牛肉、毛肚、鸭血等经典菜品，新鲜量足。价格在火锅店里算亲民，人均百元出头就能吃得尽兴。适合一群同学围坐涮肉，边吃边聊，气氛热烈。', 0, '嫩牛肉');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_49', '马记永·兰州牛肉面(枫蓝国际购物中心店)', 'restaurant', '', 'place_001', 39.9521598, 116.3498341, '西直门大街32号院1号楼枫蓝国际地下一楼104', 846, '¥¥', 45.0, '15790888521;17763546833', 'http://store.is.autonavi.com/query_pic?id=stc0444e99-56e7-42fb-bccc-89bf671bff76&user=search&operate=original', '["http://store.is.autonavi.com/query_pic?id=stc0444e99-56e7-42fb-bccc-89bf671bff76&user=search&operate=original", "https://aos-comment.amap.com/B0I2LD0UHR/comment/716af4b9a766de115b3bc5f1b48b43d1_2048_2048_80.jpg", "https://aos-comment.amap.com/B0I2LD0UHR/comment/04f8b542c9458f3052aec24286eb2003_2048_2048_80.jpg"]', '["学生友好", "手工拉面", "汤鲜面筋", "商场店"]', 4.4, 0, 0, '枫蓝国际里的兰州牛肉面，汤清面筋道，牛肉大片，加个卤蛋和辣子，就是一顿完美的午餐。', '马记永兰州牛肉面在枫蓝国际地下一层，开放式厨房能看到师傅现场拉面，场面治愈。面条分毛细、二细、韭叶等多种粗细，口感筋道爽滑。汤底清澈鲜美，牛肉片大片且软烂，撒上香菜和蒜苗，再浇一勺油泼辣子，香气直冲脑门。价格适中，人均四十多元就能吃得饱饱的。适合一个人快速解决午餐，或者在逛街累了来一碗暖胃。', 0, '兰州牛肉面');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_50', '爷爷不泡茶NOYEYENOTEA(北京枫蓝国际店)', 'restaurant', 'cold_drink', 'place_001', 39.951965, 116.3503262, '西直门北大街32号院枫蓝国际购物中心B1层', 852, '¥', 13.0, '13269226885', 'https://aos-comment.amap.com/B0K25ZQE1E/comment/377335722b21a00822170409259d6f4a_2048_2048_80.jpg', '["https://aos-comment.amap.com/B0K25ZQE1E/comment/377335722b21a00822170409259d6f4a_2048_2048_80.jpg", "http://store.is.autonavi.com/showpic/865e1dac430f63c3c22b2e0350e05e2a", "https://aos-comment.amap.com/B0K25ZQE1E/comment/7CBABCDF_4526_47F4_A4FD_1EB98E41227F_L0_001_1500_2000_1728716227362_11939263.jpg"]', '["学生友好", "平价奶茶", "茶香浓郁", "性价比高"]', 4.4, 0, 0, '枫蓝国际B1层的宝藏茶饮店，价格亲民，茶香浓郁，是学生党实现奶茶自由的快乐老家。', '爷爷不泡茶位于枫蓝国际购物中心B1层，店面虽不大，但装修古色古香，很有格调。主打各类茶饮，从经典的珍珠奶茶到清新的果茶，价格都在十几元，对学生党非常友好。推荐招牌的爷爷奶茶，茶味浓郁，奶香顺滑，珍珠Q弹有嚼劲。还可以选择甜度和冰量，满足不同口味。适合在逛街或自习前来一杯，性价比超高。', 1, '爷爷奶茶');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_51', '袁记云饺(北京市海淀区学院南路店)', 'restaurant', '', 'place_001', 39.9568092, 116.353261, '北京城区西土城路10号17号平房', 267, '¥', 23.0, '18513162326', 'https://store.is.autonavi.com/showpic/24d8c4f250f7147f3ac600fc4842f0ff?operate=original?operate=original?operate=original?operate=original', '["https://store.is.autonavi.com/showpic/24d8c4f250f7147f3ac600fc4842f0ff?operate=original?operate=original?operate=original?operate=original", "http://store.is.autonavi.com/showpic/c1b71f3af85d2cb6be4c12c494e83579", "https://aos-comment.amap.com/B0J1CCGCVF/comment/e9f21e3e458944ad93e32225835015d1_2048_2048_80.jpg"]', '["学生友好", "性价比高", "现包现煮", "快捷午餐"]', 4.0, 0, 0, '校门口267米的袁记云饺，是北邮学子们最暖心的食堂后花园。手工现包的云饺皮薄馅大，一口下去汤汁四溢，23元的人均价格让学生党毫无负担。', '走进店里，热气腾腾的蒸汽和面香扑面而来，阿姨们熟练地包着云饺，现包现煮的烟火气让人瞬间放松。云饺种类丰富，鲜虾、韭菜、玉米等经典馅料任选，搭配秘制辣椒油和醋，每一口都鲜香过瘾。店内环境干净整洁，座位紧凑但翻台快，适合课间快速解决一餐或和朋友小聚。推荐干拌云吞面，云吞与面条的碳水组合，性价比超高，是北邮学子的隐藏菜单。', 0, '干拌云吞面');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_52', '野人先生现做冰淇淋(北京枫蓝国际购物中心店)', 'restaurant', 'cold_drink', 'place_001', 39.95181, 116.3503232, '西直门北大街32号院3号楼B1层-101', 868, '¥', 27.0, '15836650535', 'https://store.is.autonavi.com/showpic/a71a7127e9bb4131e070759b56db5f80', '["https://store.is.autonavi.com/showpic/a71a7127e9bb4131e070759b56db5f80", "https://store.is.autonavi.com/showpic/0df251c0abc1c6bc748ed2071d26dfab", "https://store.is.autonavi.com/showpic/ca28984a304bffc00000002413580776?type=pic"]', '["学生友好", "网红打卡", "现做冰淇淋", "甜品控"]', 4.4, 0, 0, '枫蓝国际B1层的野人先生，用现做冰淇淋治愈你的夏天。27元就能get一杯高颜值鲜果冰淇淋，口感丝滑浓郁，是课后解馋的甜蜜炸弹。', '野人先生主打现做冰淇淋，水果与奶油的搭配在低温下瞬间凝固，每一口都充满新鲜感。店内装修以原木色为主，搭配绿植，清新自然。冰淇淋口味随季节变化，草莓、芒果、抹茶等经典款从不踩雷，还有限定款等你解锁。适合自习后、逛街时来一杯，拍照打卡也很出片。店员会贴心提醒“现做需要等一分钟”，但绝对值得等待。', 1, '鲜果冰淇淋');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_53', '何大川菜·金牌水煮鱼(四道口店)', 'restaurant', '', 'place_001', 39.9584135, 116.3399367, '北下关街道四道口路2号京果商厦B座', 1168, '¥¥¥', 100.0, '18515688925', 'https://aos-comment.amap.com/B0LKGC2T2P/comment/content_media_external_file_1000014096_ss__1769171315885_35354645.jpg', '["https://aos-comment.amap.com/B0LKGC2T2P/comment/content_media_external_file_1000014096_ss__1769171315885_35354645.jpg", "https://aos-comment.amap.com/B0LKGC2T2P/comment/3250211C_F3EE_48B1_B913_88CB8F4E7CE8_L0_001_1500_200_1770949590451_73777569.jpg", "https://aos-comment.amap.com/B0LKGC2T2P/comment/0CF8BA81_AFFE_4E6E_9EBC_2FB0641F7210_L0_001_1179_154_1772690644799_30486963.jpg"]', '["适合聚会", "川菜经典", "水煮鱼", "聚餐首选"]', 4.6, 0, 0, '何大川菜的金牌水煮鱼，是四道口川菜界的扛把子。4.6的高分和100元的人均，适合班级聚餐或庆祝活动，一盆红油翻滚的水煮鱼端上来，瞬间点燃味蕾。', '店内装修走中式风格，红灯笼、木桌椅，氛围热闹。水煮鱼是招牌，鱼肉嫩滑，辣椒和花椒的香气扑鼻，量大实在。除了水煮鱼，辣子鸡、毛血旺等经典川菜也做得地道。服务热情，上菜快，适合三五好友聚餐。虽然人均稍高，但分量足，性价比在同类川菜里算不错。', 0, '金牌水煮鱼');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_54', '成都你六姐·牛肉冒菜(枫蓝国际购物中心店)', 'restaurant', 'restaurant', 'place_001', 39.9518395, 116.3500487, '西直门北大街32号院枫蓝国际购物中心B1层', 873, '¥¥', 38.0, '17341648186', 'http://store.is.autonavi.com/query_pic?id=st984355c0-78bf-4544-b9f8-b8922b55d69b&user=search&operate=original', '["http://store.is.autonavi.com/query_pic?id=st984355c0-78bf-4544-b9f8-b8922b55d69b&user=search&operate=original", "https://aos-comment.amap.com/B0KK0656P4/comment/20260320-3f43f8f8cbe3d5e317c164fe-7r96Y8rzrn27xOUqL54GVe.jpg", "https://aos-comment.amap.com/B0KK0656P4/comment/20260320-3f43f8f8cbe3d5e317c164fe-11TXPB4tFY96Iv64vHNdWG.jpg"]', '["学生友好", "一人食", "麻辣鲜香", "性价比高"]', 4.4, 0, 0, '成都你六姐的牛肉冒菜，是枫蓝国际B1层的人气王。38元的人均，让你在寒风里也能感受到成都街头的热辣与温暖，一人食或两人搭都刚刚好。', '这家店主打一人食冒菜，牛肉是招牌，肉质鲜嫩，搭配秘制汤底，麻辣鲜香。菜品自选，蔬菜、丸子、豆制品等种类丰富，按重量计价。店内装修有成都老茶馆的感觉，竹椅、木桌，氛围轻松。适合中午下课后独自来吃，或者和同学AA，人均友好。店员会推荐加一份方便面，吸饱汤汁后简直绝了。', 1, '牛肉冒菜加方便面');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_55', '琥珀川糟粕醋火锅(四道口店)', 'restaurant', '', 'place_001', 39.9586182, 116.3395755, '北京城区京果大厦b座一楼底商', 1197, '¥¥¥', 147.0, '15601192927', 'https://aos-comment.amap.com/B0L3N5D0M7/comment/content_media_external_images_media_100000025_1762669995354_12384204.jpg', '["https://aos-comment.amap.com/B0L3N5D0M7/comment/content_media_external_images_media_100000025_1762669995354_12384204.jpg", "https://aos-comment.amap.com/B0L3N5D0M7/comment/%5B2025-11-10-16-50-58%5DA429F666-C8C8-40C1-84A2-9578A82038E_1762764659333_19827379.jpg", "https://aos-comment.amap.com/B0L3N5D0M7/comment/content_media_external_images_media_100000025_1762669995350_50311702.jpg"]', '["网红火锅", "酸辣开胃", "海鲜火锅", "约会推荐"]', 4.6, 0, 0, '琥珀川的糟粕醋火锅，是四道口新晋的网红火锅店。147元的人均虽然不便宜，但酸辣开胃的汤底和新鲜海鲜，绝对值得期末考完来犒劳自己。', '糟粕醋火锅源自海南，汤底用酒糟发酵，酸辣中带一丝甜，涮海鲜和肉类都绝配。店内装修偏工业风，灯光柔和，适合情侣约会或小范围聚餐。推荐点一份海鲜拼盘，虾、贝类、鱼片在汤里涮几下，鲜味加倍。服务贴心，会主动帮忙调蘸料。虽然价格偏高，但偶尔来一次，体验感满满。', 0, '糟粕醋海鲜拼盘');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_56', '北京邮电大学海淀校区综合食堂', 'restaurant', 'restaurant', 'place_001', 39.9626004, 116.3504566, '西土城路10号北京邮电大学海淀校区', 463, '¥', 14.0, '13661163230', 'https://aos-comment.amap.com/B0I2OSSZ2G/comment/a70a39ef80c183a03cbbc18d2c8f5680_2048_2048_80.jpg', '["https://aos-comment.amap.com/B0I2OSSZ2G/comment/a70a39ef80c183a03cbbc18d2c8f5680_2048_2048_80.jpg", "https://aos-comment.amap.com/B0I2OSSZ2G/comment/3afa9e6b69892b4a532fbc8dc06d1252_2048_2048_80.jpg", "https://aos-comment.amap.com/B0I2OSSZ2G/comment/6949fb3990e7a25140c1fd0e04583230_2048_2048_80.jpg"]', '["校内食堂", "学生友好", "性价比高", "日常用餐"]', 4.1, 0, 0, '北邮综合食堂，是校内最实惠的吃饭选择。14元的人均，从早到晚供应家常菜，是赶早课、熬夜复习后的温暖港湾。', '食堂窗口众多，从包子油条到炒菜米饭，种类齐全。早餐的豆浆油条是经典，午餐的番茄炒蛋、红烧肉是下饭神器。环境宽敞明亮，座位多，但饭点时依然需要排队。价格对学生极其友好，几块钱就能吃饱吃好。适合不想出校门、预算有限的日常用餐。', 1, '早餐豆浆油条');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_57', '北京邮电大学海淀校区学生食堂', 'restaurant', 'restaurant', 'place_001', 39.9619865, 116.3529649, '西土城路10号北京邮电大学', 315, '¥', 19.0, '010-62281771;18210246088', 'https://aos-comment.amap.com/B0FFG3YKPH/comment/d50c2d22617b5abbe2d849b2c41ec051_2048_2048_80.jpg', '["https://aos-comment.amap.com/B0FFG3YKPH/comment/d50c2d22617b5abbe2d849b2c41ec051_2048_2048_80.jpg", "https://aos-comment.amap.com/B0FFG3YKPH/comment/8fc6c579f544be051ee715e101acddac_2048_2048_80.jpg", "https://aos-comment.amap.com/B0FFG3YKPH/comment/content_media_external_file_1000066050_ss__1765090499162_92265823.jpg"]', '["校内食堂", "快速用餐", "学生友好", "麻辣香锅"]', 4.0, 0, 0, '北邮学生食堂，比综合食堂更近，315米距离让你下课就能冲进去。19元的人均，菜品偏学生口味，是课间快速解决饥饿的宝藏地。', '学生食堂更注重速度和口味，窗口常推出盖浇饭、拉面、麻辣烫等学生爱吃的品类。环境比综合食堂稍小，但更接地气。推荐麻辣香锅，自选食材现炒，辣度可选，人均20元出头就能吃到撑。适合中午放学后快速解决，或者和室友一起拼单。', 1, '麻辣香锅');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_58', '锦渝川菜·水煮鱼·烤鸭(四道口店)', 'restaurant', '', 'place_001', 39.9571392, 116.3396056, '学院南路与交大东路交叉口西北40米', 1215, '¥¥¥', 99.0, '010-85715358', 'https://store.is.autonavi.com/showpic/59be31fff1f60351d02c2385baa1c7d0', '["https://store.is.autonavi.com/showpic/59be31fff1f60351d02c2385baa1c7d0", "https://store.is.autonavi.com/showpic/fc1940e7438fbdf00000000704514717?type=pic", "https://store.is.autonavi.com/showpic/e788e6fee8b8f65c0000000704542270?type=pic"]', '["适合聚会", "川菜烤鸭", "水煮鱼", "班级聚餐"]', 4.6, 0, 0, '锦渝川菜的水煮鱼和烤鸭双绝，是四道口聚餐的热门地。4.6高分，99元人均，适合班级团建或朋友聚会，一鱼一鸭，满足南北口味。', '店内装修大气，有包间，适合多人聚餐。水煮鱼是招牌，鱼肉鲜嫩，辣椒香而不燥；烤鸭皮脆肉嫩，配饼和酱料，地道北京味。服务热情，上菜速度快。推荐点一份水煮鱼加一份烤鸭，再配几个凉菜，人均100左右，性价比在同类川菜馆里很高。', 0, '水煮鱼+烤鸭');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_59', '卷卷春饼小馆(四道口店)', 'restaurant', 'restaurant', 'place_001', 39.9574063, 116.3395058, '学院南路与四道口交口(京果商厦斜对面,超市发旁)', 1218, '¥¥', 47.0, '16603679925', 'https://store.is.autonavi.com/showpic/cd4c691c8bc4f5d10000002544086951?type=pic', '["https://store.is.autonavi.com/showpic/cd4c691c8bc4f5d10000002544086951?type=pic", "https://aos-comment.amap.com/B0FFIL8929/comment/4fcfe3f55e4ccd8359c834f7d7cda031_2048_2048_80.jpg", "https://aos-comment.amap.com/B0FFIL8929/comment/435C1427_D4EB_4735_ADC4_48B51B7A3494_L0_001_2000_1126_1731485305548_20792177.jpg"]', '["学生友好", "性价比高", "春饼", "轻食体验"]', 4.6, 0, 0, '卷卷春饼小馆，用薄如蝉翼的春饼卷起各种家常菜。47元的人均，是四道口性价比超高的轻食体验，适合想换换口味的学生。', '春饼是现烙的，薄而有韧性，搭配京酱肉丝、酸辣土豆丝、炒合菜等经典配菜，自己动手卷着吃，乐趣十足。店内装修温馨，有家的感觉。价格亲民，两人点两套春饼加几个菜就能吃饱。适合宿舍聚餐或者想尝试北方传统美食的同学。', 0, '京酱肉丝春饼');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_60', '好这口重庆小面(明光桥店)', 'restaurant', '', 'place_001', 39.9534308, 116.3485884, '明光村16楼南侧一层', 771, '¥', 27.0, '010-62232389', 'https://aos-comment.amap.com/B0FFFS55GR/comment/db9e2dde420a76a12c4e566fe726fdb2_2048_2048_80.jpg', '["https://aos-comment.amap.com/B0FFFS55GR/comment/db9e2dde420a76a12c4e566fe726fdb2_2048_2048_80.jpg", "https://aos-comment.amap.com/B0FFFS55GR/comment/5114391fdf0731281e26dc77eac156ae_2048_2048_80.jpg", "https://aos-comment.amap.com/B0FFFS55GR/comment/204a158b4d640dfb6062cbeae8350cc3_2048_2048_80.jpg"]', '["学生友好", "重庆小面", "麻辣鲜香", "一人食"]', 4.3, 0, 0, '好这口重庆小面，明光桥边的地道山城味道。27元的人均，一碗红油小面就能让你在北方感受重庆的麻辣江湖，是课后解馋的绝佳选择。', '店面不大，但收拾得干净。小面是招牌，面条劲道，汤底用牛骨熬制，麻辣鲜香。推荐豌杂面，豌豆软糯，杂酱咸香，拌匀后每根面条都裹满酱料。还有酸辣粉、抄手等选择。服务阿姨很热情，会问“要加辣不”。适合中午一个人来吃，或者和同学拼单。', 1, '豌杂面');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_61', '麦当劳(四道口餐厅)', 'restaurant', '', 'place_001', 39.9564061, 116.3396765, '大柳树路2号家属区北区11', 1227, '¥', 31.0, '010-62242313;4000517117', 'https://aos-comment.amap.com/B000A85OC0/comment/fc942b80228c4edcbbfede3d0f40b5aa_2048_2048_80.jpg', '["https://aos-comment.amap.com/B000A85OC0/comment/fc942b80228c4edcbbfede3d0f40b5aa_2048_2048_80.jpg", "https://aos-comment.amap.com/B000A85OC0/comment/B562ADEB_E780_4715_B2F2_3DA6BD612BFA_L0_001_IMG_4830_1694758054887_3247a748.JPG", "https://aos-comment.amap.com/B000A85OC0/comment/80118492_4879_4EE3_8687_53DE216F68DE_L0_001_1440_1080_1764386067032_26558505.jpg"]', '[]', 4.6, 0, 0, '麦当劳(四道口餐厅)', '', 0, NULL);
