INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_70', '磁器铜锅涮肉(学院南路店)', 'restaurant', '', 'place_001', 39.9584165, 116.3399347, '北京城区四道口2号院2号楼1层102', 1168, '¥', 90.0, '010-62268389;13021987191', 'https://store.is.autonavi.com/showpic/1e0186efcdb7ba130000002535750678?type=pic', '["https://store.is.autonavi.com/showpic/1e0186efcdb7ba130000002535750678?type=pic", "https://store.is.autonavi.com/showpic/c5c00478bf5b0ef60000002301544259?type=pic", "https://aos-comment.amap.com/comment/content_service__1771341664428_96586573_1771341818886_22270147.jpg"]', '[]', 4.5, 0, 0, '磁器铜锅涮肉(学院南路店)', '', 0, NULL);
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_71', '啊臻味道米粉(四道口直营店)', 'restaurant', 'cafe', 'place_001', 39.9584389, 116.3397412, '四道口路2号京果商厦B座F1层', 1184, '¥', 23.0, '13120108831;15210082063', 'https://aos-comment.amap.com/B0FFKXLVPA/comment/E4ED8C6D_12D7_482C_A6F2_F5F8B0E6C97A_L0_001_1080_1920_1735666591349_17992044.jpg', '["https://aos-comment.amap.com/B0FFKXLVPA/comment/E4ED8C6D_12D7_482C_A6F2_F5F8B0E6C97A_L0_001_1080_1920_1735666591349_17992044.jpg", "http://store.is.autonavi.com/showpic/7e0fc43d9fd34fbda52e1404e0e7511a", "https://aos-comment.amap.com/B0FFKXLVPA/comment/content_media_external_file_1000101306_ss__1767631153488_54677512.jpg"]', '["学生友好", "辣味过瘾", "性价比高", "网红打卡", "适合打包"]', 4.5, 0, 0, '新疆味道的米粉霸主，酱香浓郁辣得过瘾，人均23元就能吃到撑，是央财学子解馋必去的宝藏小店！', '一进门就被浓郁的酱香包围，招牌的鸡肉炒米粉是必点，粗米粉裹满秘制酱料，辣度可选微辣到爆辣，每一口都超满足。店面不大但干净整洁，饭点经常排队，建议错峰或打包。适合和室友一起来个辣味挑战，或是考试后犒劳自己。对学生党来说，性价比无敌，还能加馕或年糕，吃法多样。', 0, '招牌鸡肉炒米粉');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_72', '山西刀削面(文慧园店)', 'restaurant', 'restaurant', 'place_001', 39.955408, 116.3521732, '西直门北大街首钢国际大厦对面', 439, '¥', 22.0, '18510174455', 'https://store.is.autonavi.com/showpic/dc418639a3e9c36adb61a9b340e7c8be', '["https://store.is.autonavi.com/showpic/dc418639a3e9c36adb61a9b340e7c8be", "https://store.is.autonavi.com/showpic/30b422e4bda904d594d41fe0597ffdbb", "https://store.is.autonavi.com/showpic/1d68345c267df44f13db3dfd21ca2a5a"]', '["学生友好", "深夜营业", "手工现做", "快速便捷", "性价比高"]', 4.0, 0, 0, '校门口439米的刀削面老店，手工削面筋道爽滑，22元管饱，是赶课和深夜自习后的暖心选择。', '这家店离学校走路就能到，是很多学生的第二食堂。师傅现场削面，面条厚薄均匀，入口弹牙。汤底用骨头熬制，鲜香浓郁，配上几片牛肉和青菜，简单却治愈。环境朴实，服务效率高，适合一个人快速解决一餐，或和同学边吃边聊。推荐加个卤蛋和豆腐，不到30元就能吃得超满足。', 0, '牛肉刀削面');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_73', '京果商厦', 'restaurant', '', 'place_001', 39.9589931, 116.3396233, '四道口路2号(中央财经大学对面)', 1191, '¥', 0.0, '', 'https://aos-comment.amap.com/B0FFFW5CL5/comment/content_media_external_file_8492_1768549174177_94666819.jpg', '["https://aos-comment.amap.com/B0FFFW5CL5/comment/content_media_external_file_8492_1768549174177_94666819.jpg", "http://store.is.autonavi.com/showpic/324eb82858a60c16b3e98ca3c436ee88", "https://aos-comment.amap.com/B0FFFW5CL5/comment/%5B2025-08-22-10-44-53%5D311BF995-0AF8-4223-9088-726A6646C97_1755830697920_65906177.jpg"]', '["学生友好", "美食聚集地", "接地气", "适合聚会", "丰俭由人"]', 4.5, 0, 0, '央财对面的美食聚集地，4.5分好评，汇集各类小吃快餐，是学生下课觅食的万能选择。', '京果商厦就在学校对面，里面藏着十几家档口，从麻辣烫到煎饼果子，从奶茶到炸鸡，应有尽有。环境热闹接地气，每到饭点人声鼎沸，充满校园生活的烟火气。适合和同学结伴来，每人选不同档口，拼一桌吃遍各种风味。人均丰俭由人，几块钱也能吃饱，是零花钱紧张时的救星。', 0, NULL);
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_74', '紫光园清真北京小吃(四道口店)', 'restaurant', '', 'place_001', 39.9570459, 116.3397503, '中央财经大学南1门东140米', 1204, '¥¥', 32.0, '18710057285', 'http://store.is.autonavi.com/query_pic?id=stc56029d4-8f36-4428-b61d-aded6ac2fe6d&user=search&operate=original', '["http://store.is.autonavi.com/query_pic?id=stc56029d4-8f36-4428-b61d-aded6ac2fe6d&user=search&operate=original", "https://aos-comment.amap.com/B0KBO5D7PS/comment/78B955BB_08FE_48BF_9455_CBDB40A3B5B2_L0_001_1500_200_1744425417375_85818667.jpg", "https://store.is.autonavi.com/showpic/306ee43509dda0e8d998ce4cd12c2231"]', '["学生友好", "老字号", "清真认证", "早餐推荐", "性价比高"]', 4.5, 0, 0, '正宗清真北京小吃，人均32元吃遍老北京味道，离学校南门仅140米，早餐和下午茶首选。', '紫光园是北京老字号，这家店紧邻央财，环境干净明亮。必点的糖火烧层层酥脆，豆汁儿配焦圈地道够味，还有牛肉饼、炸松肉等经典小吃。服务热情，出餐快，适合早起上课前买份包子豆浆，或下午没课时来碗面茶。价格亲民，学生党也能轻松体验老北京饮食文化。', 0, '糖火烧');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_75', '华腾央厨', 'restaurant', 'restaurant', 'place_001', 39.955106, 116.352818, '三环以内学院南路32号院首钢发展研究院内', 460, '¥¥', 71.0, '13581588417', 'http://store.is.autonavi.com/showpic/8bf184e508125e46d2ffacf573255fa3', '["http://store.is.autonavi.com/showpic/8bf184e508125e46d2ffacf573255fa3", "https://aos-comment.amap.com/B0IR2H31XE/headerImg/content_media_external_images_media_249037_1658818927978_981491f6.jpg"]', '["环境雅致", "现炒现做", "适合聚会", "品质中餐", "学生友好"]', 4.0, 0, 0, '学院南路内的精致食堂，人均71元享受现炒小锅菜，环境雅致，适合改善伙食或小聚。', '华腾央厨藏在首钢研究院里，环境比普通食堂更讲究，暖色灯光和木质桌椅让人放松。主打现炒菜品，锅气十足，推荐宫保鸡丁和酸菜鱼，分量实在。服务贴心，适合和室友来改善伙食，或是社团小聚。价格虽比路边摊高，但品质对得起价位，是校园周边难得的中档选择。', 0, '宫保鸡丁');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_76', '利哥兄弟菜馆', 'restaurant', 'restaurant', 'place_001', 39.9590207, 116.3392911, '四道口2号院1号楼1层101', 1220, '¥¥', 54.0, '18518668841', 'http://store.is.autonavi.com/showpic/81a74e76c7aae93f684f8939eff13db6', '["http://store.is.autonavi.com/showpic/81a74e76c7aae93f684f8939eff13db6", "https://store.is.autonavi.com/showpic/d136724f091bddea0000002334526167?type=pic", "https://aos-comment.amap.com/B0K6TBOGSS/comment/content_media_external_file_1000021792_ss__1751701553292_93209827.jpg"]', '["学生友好", "家常味道", "适合聚会", "量大实惠", "人气火爆"]', 4.5, 0, 0, '四道口性价比之王，人均54元吃地道家常菜，4.5分好评，适合组团解馋。', '利哥兄弟菜馆是附近学生的聚餐圣地，店面不大但烟火气十足。菜单以家常菜为主，锅包肉外酥里嫩，地三鲜咸香下饭，每道菜都量大实惠。老板热情，经常和熟客唠嗑。适合期末考后组团来搓一顿，人均50出头就能点满一桌，比食堂更有仪式感。', 0, '锅包肉');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_77', '疯狂烤翅(四道口店)', 'restaurant', '', 'place_001', 39.9578977, 116.3392712, '北京市海淀区四道口路甲2号', 1230, '¥¥', 71.0, '13269850388;18511278444', 'https://aos-comment.amap.com/B000A7Z070/comment/EA57715D_D118_4874_96E9_BBC750F45148_L0_001_2000_150_1744425315237_15414136.jpg', '["https://aos-comment.amap.com/B000A7Z070/comment/EA57715D_D118_4874_96E9_BBC750F45148_L0_001_2000_150_1744425315237_15414136.jpg", "https://aos-comment.amap.com/B000A7Z070/comment/161FF02A_64CE_4312_B6A0_D72A48487708_L0_001_2000_150_1744425315237_58712685.jpg", "https://aos-comment.amap.com/B000A7Z070/comment/72411fc588652a2cfcae3d2e7310a2f3_2048_2048_80.jpg"]', '["深夜营业", "学生友好", "烧烤夜宵", "适合聚会", "网红打卡"]', 4.5, 0, 0, '四道口夜宵扛把子，人均71元吃疯狂烤翅，10种口味任选，是熬夜党的救赎。', '这家烤翅店是央财学子的深夜食堂，营业到凌晨，适合自习后或周末来撸串。招牌烤翅有原味、蜜汁、麻辣等十几种口味，外皮焦香，肉质嫩滑。环境热闹，适合和哥们儿边吃边侃大山。除了烤翅，还有烤串和凉菜，搭配冰镇饮料，人均70元吃撑。', 0, '蜜汁烤翅');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_78', '永和大王(学院南路)', 'restaurant', 'cafe', 'place_001', 39.9570215, 116.3394091, '中央财经大学南1门东130米', 1234, '¥', 20.0, '010-62152539', 'https://aos-comment.amap.com/B000A87JP4/comment/5B14DEFB_CB5C_4046_BA35_04533E0403EA_L0_001_2000_1500_1743600789600_36421931.jpg', '["https://aos-comment.amap.com/B000A87JP4/comment/5B14DEFB_CB5C_4046_BA35_04533E0403EA_L0_001_2000_1500_1743600789600_36421931.jpg", "https://aos-comment.amap.com/comment/content_service__1772942101716_45619695_1772942167645_59271598.jpg", "https://aos-comment.amap.com/B000A87JP4/comment/b729393d-78c9-4f13-8c41-08f5ec774891.png"]', '["学生友好", "24小时营业", "快餐首选", "早餐推荐", "性价比高"]', 4.5, 0, 0, '校门口130米的快餐老牌，人均20元吃热乎豆浆油条和卤肉饭，早中晚都管饱。', '永和大王就在学校南门旁边，是学生解决三餐的快捷选择。24小时营业，早上有现磨豆浆和油条，中午的卤肉饭和排骨面都是经典。环境整洁，出餐飞快，适合赶课时打包带走，或深夜饿了来碗热汤面。价格实惠，学生党毫无压力。', 0, '卤肉饭');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_79', '魏家凉皮(四道口店)', 'restaurant', 'cafe', 'place_001', 39.958234, 116.3391016, '学院南路与交大东路交叉口西北160米', 1240, '¥', 27.0, '010-68865589', 'http://store.is.autonavi.com/query_pic?id=st829c2f75-2800-452b-93a5-8e8c20183114&user=search&operate=original', '["http://store.is.autonavi.com/query_pic?id=st829c2f75-2800-452b-93a5-8e8c20183114&user=search&operate=original", "https://img.alicdn.com/imgextra/i2/O1CN01XXTiB51Wwj5aAchDB_!!6000000002853-0-tps-1080-1064.jpg", "https://aos-comment.amap.com/B0L6BUL5NZ/comment/content_media_external_file_1000014406_ss__1772959825480_57080651.jpg"]', '["学生友好", "夏季必吃", "酸辣开胃", "快速便捷", "网红打卡"]', 4.5, 0, 0, '四道口凉皮界天花板，人均27元吃酸辣爽口的秘制凉皮，夏天解暑必备。', '魏家凉皮是连锁中的佼佼者，这家店离学校不远，夏天生意火爆。凉皮薄滑筋道，配上面筋和黄瓜丝，浇上秘制辣椒油，酸辣开胃。除了凉皮，还有肉夹馍和粥品，搭配起来就是完美一餐。环境干净，适合夏天没胃口时来一碗，或打包回宿舍当宵夜。', 0, '秘制凉皮');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_80', '小湘界·一锅鲜', 'restaurant', 'restaurant', 'place_001', 39.9564934, 116.3428897, '北京城区北太平庄街道学院南路50号一层F102', 961, '¥¥', 46.0, '13521810767', 'https://aos-comment.amap.com/B0HGX5XY24/comment/content_media_external_file_100000975_1771342451519_26997272.jpg', '["https://aos-comment.amap.com/B0HGX5XY24/comment/content_media_external_file_100000975_1771342451519_26997272.jpg", "https://store.is.autonavi.com/showpic/b739a5825bf6671bc19cc160bee28f95", "http://store.is.autonavi.com/showpic/e1b7bf3c0795700c2a03e6b4e68d65f6"]', '["学生友好", "湘菜风味", "适合聚会", "下饭神器", "性价比高"]', 4.3, 0, 0, '学院南路湘菜小馆，人均46元吃一锅鲜，辣味下饭，适合和同学来过把瘾。', '小湘界主打湘式一锅鲜，热气腾腾的锅仔端上桌，香味四溢。招牌的一锅鲜里有鱼、虾、豆腐等，汤汁浓郁，辣度适中。环境温馨，有卡座适合小聚。价格实惠，人均不到50元就能吃得很丰盛，适合想换口味时来解馋，或和湖南室友一起找家乡味。', 0, '一锅鲜');
