INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_101', '必胜宅急送(明光桥店)', 'restaurant', '', 'place_001', 39.9546677, 116.3486062, '北三环内西直门北大街1号1层底商', 660, '¥¥', 57.0, '4008123123', 'http://store.is.autonavi.com/showpic/5689d28ea310f9ed880c21be', '["http://store.is.autonavi.com/showpic/5689d28ea310f9ed880c21be", "https://store.is.autonavi.com/showpic/056ece44c1162830db0ed28af16128e7", "http://store.is.autonavi.com/showpic/594afe133da62d4dec40aa09fd65c48a"]', '["外卖方便", "深夜营业", "学生友好", "性价比高"]', 3.9, 0, 0, '明光桥下的披萨外卖专家，主打经典意式披萨、焗饭和小食，价格亲民且出餐快，是宿舍追剧或赶作业时的能量补给站。', '必胜宅急送明光桥店位于北三环内，距离校园步行仅需几分钟，主打外卖配送服务。店内环境简洁，以高效出餐和稳定品质著称。无论是经典的超级至尊披萨、芝心卷边，还是焗饭、鸡翅等小食，都适合学生快速解决一餐。深夜赶作业或周末宿舍聚会时，点一份外卖就能满足味蕾。服务上支持线上点单、自取和配送，对学生群体非常友好。适合作为日常简餐或宵夜选择，性价比高，是校园生活中不可或缺的便捷美食据点。', 0, '推荐超级至尊披萨');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_102', '华莱士·全鸡汉堡(四道口店)', 'restaurant', 'cafe', 'place_001', 39.9564894, 116.3406185, '北京城区交大东路2号院学院live商业街B1层', 1147, '¥', 18.0, '18696149945', 'https://store.is.autonavi.com/showpic/c406ecbf863a7c93518b1bad6a34294e?operate=original', '["https://store.is.autonavi.com/showpic/c406ecbf863a7c93518b1bad6a34294e?operate=original", "https://aos-comment.amap.com/B0FFICFYL4/comment/AEE51933_062D_463B_8F23_6AE59E130A6A_L0_001_1179_83_1766040216764_55156152.jpg", "https://aos-comment.amap.com/B0FFICFYL4/comment/content_media_external_file_1000507939_ss__1764732796375_32890295.jpg"]', '["学生友好", "性价比高", "适合小聚", "快餐"]', 4.2, 0, 0, '四道口学生党的平价炸鸡天堂，香酥全鸡和汉堡是必点，18元的人均让你实现炸鸡自由，适合解馋或小聚。', '华莱士全鸡汉堡四道口店位于学院live商业街B1层，交通便利，是周边学生常去的平价快餐店。店内装修简约明亮，主打西式快餐，如脆皮全鸡、香辣鸡腿堡、薯条和可乐套餐。人均仅18元，性价比极高，尤其适合学生党解馋或三五好友简单小聚。出餐速度快，服务热情，常有优惠活动。无论是午餐、晚餐还是夜宵，这里都是快速填饱肚子的好去处。氛围轻松随意，适合课间或课后快速解决一餐，是校园周边不可错过的美食地标。', 1, '推荐脆皮全鸡');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_103', '甲乙饼·手工牛肉饼(枫蓝国际店)', 'restaurant', '', 'place_001', 39.9518443, 116.3501605, '北京城区西直门北大街32号院枫蓝国际购物中心B1层', 869, '¥¥', 32.0, '15116990304', 'http://store.is.autonavi.com/showpic/f7f759f89b434be4bbca502d8d5f1505', '["http://store.is.autonavi.com/showpic/f7f759f89b434be4bbca502d8d5f1505", "https://store.is.autonavi.com/showpic/99f3b70d20c34ab29eb79b36f7731200", "https://store.is.autonavi.com/showpic/57e317dfc82825d64564926896e8f64d"]', '["手工制作", "学生友好", "适合简餐", "性价比高"]', 4.0, 0, 0, '枫蓝国际里的手工牛肉饼专家，外皮酥脆、肉馅饱满，搭配粥品小菜，是暖胃又实惠的校园简餐首选。', '甲乙饼·手工牛肉饼枫蓝国际店位于枫蓝国际购物中心B1层，环境整洁舒适，主打手工现做的牛肉饼和各类中式简餐。牛肉饼外皮金黄酥脆，内馅鲜嫩多汁，搭配小米粥或酸辣汤，暖胃又满足。人均32元，价格适中，适合学生午餐或晚餐。服务上，店员热情周到，出餐速度较快。这里适合一个人安静用餐，也适合和朋友小聚聊天。推荐理由：手工制作、食材新鲜、性价比高，是校园周边难得的家常味道。', 0, '推荐手工牛肉饼');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_104', '兰熊鲜奶', 'restaurant', 'cold_drink', 'place_001', 39.9516927, 116.349899, '西直门北大街32号院枫蓝国际购物中心B1层', 892, '¥', 16.0, '18310098681', 'https://aos-comment.amap.com/B0LK61LIGD/comment/6D1B49B8_1FAB_4A19_BC67_852DBC035596_L0_001_1500_200_1773053679663_21665057.jpg', '["https://aos-comment.amap.com/B0LK61LIGD/comment/6D1B49B8_1FAB_4A19_BC67_852DBC035596_L0_001_1500_200_1773053679663_21665057.jpg", "https://aos-comment.amap.com/B0LK61LIGD/comment/BAB5D037_E319_420C_8670_B769916681D8_L0_001_1500_200_1773053679665_44047629.jpg", "https://store.is.autonavi.com/showpic/96ed39058a8a23f70000002305554140?type=pic"]', '["学生友好", "性价比高", "健康饮品", "适合自习"]', 4.0, 0, 0, '枫蓝国际里的鲜奶饮品小站，主打新鲜牛乳和水果搭配，口感丝滑清甜，是课后解渴或自习提神的健康之选。', '兰熊鲜奶位于枫蓝国际购物中心B1层，店面小巧精致，以新鲜牛乳为基底，搭配当季水果和茶饮，打造出多款健康饮品。招牌如芋泥鲜奶、芒果鲜奶等，口感浓郁而不腻，甜度可调，适合学生口味。人均仅16元，价格非常亲民，是课后解渴或自习时提神的好伴侣。店内环境清新，适合短暂歇脚。服务上，店员制作快速，支持自取和外送。推荐理由：用料实在、健康无添加、性价比超高，是校园周边饮品店中的一股清流。', 1, '推荐芋泥鲜奶');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_105', 'LINLEE·手打柠檬茶(海淀四道口店)', 'restaurant', 'bar', 'place_001', 39.9563523, 116.3406524, '北京城区交大东路2号3号楼学院里live商业街B1层09', 1148, '¥', 18.0, '16619763025', 'https://img.alicdn.com/imgextra/i4/O1CN01IjGJnC1D2s5gyHvU6_!!6000000000159-2-tps-1061-1061.png', '["https://img.alicdn.com/imgextra/i4/O1CN01IjGJnC1D2s5gyHvU6_!!6000000000159-2-tps-1061-1061.png", "https://store.is.autonavi.com/showpic/9e6b0c3e5ab860e40000002462614986?type=pic"]', '["学生友好", "网红打卡", "性价比高", "夏日解暑"]', 4.1, 0, 0, '四道口的手打柠檬茶专门店，现捶现做，酸爽回甘，是夏天解暑或饭后消食的清爽选择，学生优惠多多。', 'LINLEE手打柠檬茶海淀四道口店位于学院里live商业街B1层，是柠檬茶爱好者的天堂。店内采用新鲜柠檬现捶现做，茶底清爽，酸度适中，回甘悠长。招牌如招牌柠檬茶、鸭屎香柠檬茶等，口感层次丰富，适合解暑或搭配重口味餐食。人均18元，价格亲民，且常有学生优惠活动。店内环境时尚，适合打卡拍照或短暂休息。服务热情，出餐速度快。推荐理由：真材实料、口感独特、性价比高，是校园周边夏日里的清凉之选。', 1, '推荐招牌柠檬茶');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_106', '塔斯汀中国汉堡(北京市海淀四道口京果店)', 'restaurant', 'cafe', 'place_001', 39.9582445, 116.3399807, '北京城区北京城区四道口2号院2号楼1层101', 1166, '¥', 20.0, '15710095936', 'https://store.is.autonavi.com/showpic/9b006630064cd611916165319378ce7d', '["https://store.is.autonavi.com/showpic/9b006630064cd611916165319378ce7d", "https://store.is.autonavi.com/showpic/95e4fa04eb9d542fca3b917dc7634f7f", "https://aos-comment.amap.com/comment/20260319-96879df0c2d477cbbc3bf125-5xuChDKPKQt9xKkFRxMV4t.jpg"]', '["国潮", "学生友好", "性价比高", "手工制作"]', 4.1, 0, 0, '四道口的手工汉堡新秀，中式面饼夹西式馅料，外酥里嫩，20元的人均让你体验国潮快餐的魅力。', '塔斯汀中国汉堡海淀四道口店位于四道口2号院，主打手工现做的中国汉堡，用中式面饼替代传统面包，口感更酥脆。内馅包括香辣鸡腿、牛肉等，搭配生菜和酱料，味道独特。人均20元，价格实惠，适合学生午餐或晚餐。店内环境现代简约，出餐速度快，服务高效。推荐理由：国潮风格、手工制作、性价比高，是传统汉堡的创新演绎，适合尝鲜或解决日常一餐。', 1, '推荐香辣鸡腿中国汉堡');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_107', '姜小豆滕州菜煎饼(枫蓝国际购物中心店)', 'restaurant', '', 'place_001', 39.9517703, 116.3501645, '西直门北大街32号院枫蓝国际购物中心B1层', 877, '¥', 20.0, '', 'https://aos-comment.amap.com/B0K1OHXQQ0/comment/202603_14-11163_1773458209811_90794983.jpg', '["https://aos-comment.amap.com/B0K1OHXQQ0/comment/202603_14-11163_1773458209811_90794983.jpg", "https://aos-comment.amap.com/B0K1OHXQQ0/comment/A4379E62_65C0_404D_83D8_935168D41753_L0_001_1126_200_1768748671575_36923852.jpg", "https://aos-comment.amap.com/B0K1OHXQQ0/comment/E26BDE92_FF1D_4F72_BF83_1F9A19C5533D_L0_001_2000_112_1768748671577_33640615.jpg"]', '["健康轻食", "学生友好", "性价比高", "特色小吃"]', 3.9, 0, 0, '枫蓝国际里的山东特色小吃，薄脆煎饼包裹丰富蔬菜，低脂健康，20元管饱，是减肥学生的福音。', '姜小豆滕州菜煎饼枫蓝国际店位于购物中心B1层，主打正宗的滕州菜煎饼。煎饼采用杂粮面糊摊制，薄脆可口，内馅选用多种新鲜蔬菜如豆芽、白菜、粉丝等，可根据个人喜好搭配。人均20元，价格实惠，且低脂健康，适合减肥或注重饮食的学生。店内环境干净整洁，出餐速度快。服务上，店员会耐心推荐搭配。推荐理由：特色地方美食、营养均衡、性价比高，是校园周边健康简餐的优质选择。', 1, '推荐经典菜煎饼');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_108', '小番街海淀食堂', 'restaurant', '', 'place_001', 39.9553968, 116.3528889, '学院南路与文慧园西路交叉口东南160米', 427, '¥', 21.0, '13021985958;18626582999', 'uploads/images/surrounding/小番街海淀食堂.jpg', '[]', '["学生友好", "性价比高", "快餐", "距离近"]', 3.6, 0, 0, '学院南路附近的平价食堂，主打家常菜和快餐，21元管饱，是距离校园最近的饱腹之选，适合赶课族。', '小番街海淀食堂位于学院南路与文慧园西路交叉口附近，距离校园仅400多米，是学生解决日常餐食的便捷选择。店内提供各类家常菜、盖饭、面条和快餐，价格亲民，人均21元，分量足。环境虽简单但干净，适合快速用餐。服务上，采用自助取餐模式，效率高。推荐理由：距离近、价格低、选择多，是课间或课后快速填饱肚子的理想去处。', 1, NULL);
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_109', '虎头军煎饼(四道口店)', 'restaurant', 'restaurant', 'place_001', 39.9569632, 116.3390279, '中央财经大学南1门东80米', 1267, '¥', 14.0, '13641363669;17315636816', 'http://store.is.autonavi.com/showpic/90810ced21b29a304dd30292cc29a67c', '["http://store.is.autonavi.com/showpic/90810ced21b29a304dd30292cc29a67c", "https://aos-comment.amap.com/B0KBGDUIUX/comment/b5664184abf4f2d2533cd41b14b64a62_2048_2048_80.jpg", "https://aos-comment.amap.com/B0KBGDUIUX/comment/20260317-742a0056b16a4668c4d0e317-50C0cUuyFWzAm7fc7L7lXn.jpg"]', '["学生友好", "性价比高", "早餐", "夜宵"]', 4.1, 0, 0, '四道口的人气煎饼摊，薄脆酱香，14元一个管饱，是早八课或夜宵时的经典校园味道。', '虎头军煎饼四道口店位于中央财经大学南门附近，是周边学生熟知的煎饼小店。主打传统煎饼果子，面糊摊得薄而均匀，夹上薄脆、鸡蛋、生菜和秘制酱料，口感酥脆香浓。人均仅14元，价格超低，适合早餐或夜宵。店内环境简单，但出餐速度快，服务热情。推荐理由：经典口味、价格实惠、方便快捷，是校园生活中不可或缺的街头美食。', 1, '推荐经典煎饼');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_110', 'HOT ROCK韩国料理', 'restaurant', '', 'place_001', 39.9562511, 116.3407642, '北京城区交大东路2号院学院LIVE地下一层', 1142, '¥¥', 44.0, '13321173441', 'http://store.is.autonavi.com/showpic/5ebc04f074e1814536ae7783c15c3960', '["http://store.is.autonavi.com/showpic/5ebc04f074e1814536ae7783c15c3960", "https://store.is.autonavi.com/showpic/e21ea3af9a03dd937396b4286a2506a9", "https://store.is.autonavi.com/showpic/f0e30357e6f21f2c96454b148b2641a6"]', '["适合聚会", "韩式料理", "学生友好", "氛围好"]', 4.0, 0, 0, '学院LIVE地下的韩式烤肉店，石锅拌饭和部队火锅是招牌，氛围热闹，适合宿舍聚餐或朋友小聚。', 'HOT ROCK韩国料理位于交大东路学院LIVE地下一层，环境充满韩式风情，灯光柔和，适合聚餐。主打韩式烤肉、石锅拌饭、部队火锅和炸鸡等，人均44元，价格适中。烤肉可以自己动手烤制，互动性强，适合宿舍或朋友小聚。服务上，店员会协助烤肉，态度热情。推荐理由：氛围好、菜品正宗、适合聚会，是校园周边体验韩式美食的好去处。', 0, '推荐石锅拌饭');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_111', '朱小小螺蛳粉(四道口店)', 'restaurant', '', 'place_001', 39.9563323, 116.3406934, '北京城区交大东路2号院8幢B1层B101', 1145, '¥', 11.0, '15624900756', 'https://aos-comment.amap.com/B0KDLLRXOH/comment/88321C8C_D24C_4CC9_AEEE_4A2C45788524_L0_001_1500_2000_1743517498109_39912541.jpg', '["https://aos-comment.amap.com/B0KDLLRXOH/comment/88321C8C_D24C_4CC9_AEEE_4A2C45788524_L0_001_1500_2000_1743517498109_39912541.jpg", "https://aos-comment.amap.com/B0KDLLRXOH/comment/BB1A4509_A760_474B_BBA9_C10194565816_L0_001_1220_1626_1743517498109_98594589.jpg", "https://aos-comment.amap.com/B0KDLLRXOH/comment/37fe297a71bc06d49ebe1de3210c051c_2048_2048_80.jpg"]', '["学生友好", "性价比高", "深夜营业", "酸辣鲜香"]', 4.0, 0, 0, '藏在交大东路的负一层，却是螺蛳粉爱好者的宝藏地。人均11元就能嗦到一碗酸辣鲜香的柳州风味，汤底浓郁，配料超足，是学生党解馋的绝佳选择。', '朱小小螺蛳粉(四道口店)位于交大东路2号院B1层，位置虽隐蔽但人气不减。店内装修简约，主打地道的柳州螺蛳粉，汤底用螺蛳熬制，酸笋、腐竹、花生等配料丰富，辣度可选。嗦上一口，酸辣鲜香直冲味蕾，让人欲罢不能。人均仅11元，性价比超高，适合下课或周末来此大快朵颐。无论是独享还是和室友拼单，都能吃得满足。', 1, '招牌螺蛳粉');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_112', '原始泥炉炭火烤肉(四道口店)', 'restaurant', 'restaurant', 'place_001', 39.9568098, 116.3528518, '学院南路9号', 273, '¥¥', 0.0, '13811695066', 'https://store.is.autonavi.com/showpic/427ccc801496b81fdcc5e72df0c01171', '["https://store.is.autonavi.com/showpic/427ccc801496b81fdcc5e72df0c01171"]', '["适合聚会", "烟火气", "炭火烤肉", "学生友好"]', 3.4, 0, 0, '学院南路旁的炭火烤肉店，用原始泥炉烤出烟火气。虽然评分一般，但炭火直烤的肉香和热闹氛围，适合三五好友来此聚餐，感受校园旁的夜生活。', '原始泥炉炭火烤肉(四道口店)紧邻学院南路，距离校园仅273米，是学生聚会的热门选择。店内采用传统泥炉炭火烤制，肉品在炭火中滋滋作响，香气四溢。环境偏市井风格，热闹嘈杂，适合和同学边烤肉边聊天。不过评分3.4，服务可能偶有疏漏，但若追求烟火气和实惠，仍值得一试。人均参考价未标注，推断在¥¥区间，适合周末或考试后的放松聚餐。', 0, NULL);
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_113', '乐食水饺', 'restaurant', 'restaurant', 'place_001', 39.9583778, 116.339794, '大钟寺四道口路2号京果商厦B座商场1层', 1180, '¥', 21.0, '18612778888', 'https://store.is.autonavi.com/showpic/5e52192efcbb9fc4f689176c4f53127e', '["https://store.is.autonavi.com/showpic/5e52192efcbb9fc4f689176c4f53127e", "https://aos-comment.amap.com/B000A8X9DF/comment/9ea4482ccc0f6ccd9d7089ab332491a5_2048_2048_80.jpg", "https://aos-comment.amap.com/B000A8X9DF/comment/74a66ec6874580e78cb045b52b5b1148_2048_2048_80.jpg"]', '["学生友好", "性价比高", "手工现包", "适合一人食"]', 4.0, 0, 0, '大钟寺京果商厦里的水饺小店，人均21元就能吃到手工现包的水饺，皮薄馅大，是校园周边的暖心食堂。适合赶课或自习后快速解决一顿。', '乐食水饺位于京果商厦B座1层，距离校园1180米，是学生早午餐或晚餐的便捷之选。店内主打手工水饺，馅料丰富，如猪肉白菜、韭菜鸡蛋等经典口味，现包现煮，皮薄馅足，咬下去汁水丰盈。环境干净整洁，服务效率高，适合一人食或和同学简单聚餐。参考人均21元，性价比不错，尤其适合冬天来一碗热腾腾的水饺，暖胃又暖心。', 1, '猪肉白菜水饺');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_114', '好开心烧饼里脊(四道口店)', 'restaurant', '', 'place_001', 39.9571782, 116.3396116, '北京城区学院南路与交大东路交叉口西北40米', 1213, '¥', 14.0, '', 'https://store.is.autonavi.com/showpic/74506f46d9c7585a1ee03edfc8112876', '["https://store.is.autonavi.com/showpic/74506f46d9c7585a1ee03edfc8112876", "https://aos-comment.amap.com/B0LD0AGQ4D/comment/content_media_external_images_media_1000052583_ss__1750241098408_56631507.jpg", "http://store.is.autonavi.com/showpic/1bfdb9c7d35e29517729520062e66395"]', '["学生友好", "性价比高", "早餐首选", "现做现卖"]', 4.0, 0, 0, '学院南路与交大东路交叉口的烧饼里脊小店，人均14元就能吃到外酥里嫩的现做烧饼，是学生早八或课后小吃的经典之选。', '好开心烧饼里脊(四道口店)位于学院南路与交大东路交叉口西北角，距离校园1213米，是周边学生的早餐和课间零食圣地。烧饼现烤，外皮酥脆，夹上嫩滑的里脊肉和酱料，一口下去层次丰富。店内主打简餐，服务快捷，适合赶时间的学生。参考人均14元，价格亲民，无论是清晨赶课还是下午饿肚子，都能快速满足。', 1, '烧饼里脊');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_115', '卤太宗大鸡腿饭(财大店)', 'restaurant', 'restaurant', 'place_001', 39.9572932, 116.3395697, '学院南路33号卷卷春饼小馆旁边', 1214, '¥', 24.0, '010-62139388;13311494250', 'https://aos-comment.amap.com/B0IGV539HD/comment/content_media_external_file_1000078419_ss__1759841500694_60241144.jpg', '["https://aos-comment.amap.com/B0IGV539HD/comment/content_media_external_file_1000078419_ss__1759841500694_60241144.jpg", "https://aos-comment.amap.com/B0IGV539HD/comment/content_media_external_file_1000078424_ss__1759841500694_68438526.jpg", "https://aos-comment.amap.com/B0IGV539HD/comment/064e938635d796e9081be2012dcd236f_2048_2048_80.jpg"]', '["学生友好", "性价比高", "分量足", "卤味经典"]', 4.0, 0, 0, '学院南路33号的小馆，卤太宗大鸡腿饭是招牌，人均24元就能吃到卤香四溢的大鸡腿配米饭，分量十足，是学生午餐的硬核选择。', '卤太宗大鸡腿饭(财大店)位于学院南路33号，紧邻卷卷春饼小馆，距离校园1214米。店内主打卤味饭，招牌大鸡腿饭选用卤制入味的鸡腿，肉质软烂，搭配米饭和蔬菜，分量扎实，性价比高。环境偏快餐风格，简洁明亮，适合学生午餐或晚餐。参考人均24元，用一顿饭的时间就能补充能量，尤其适合食欲旺盛的同学。', 1, '卤太宗大鸡腿饭');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_116', '八珍王(北京四道口路京果商厦店)', 'restaurant', 'cafe', 'place_001', 39.9594198, 116.3392132, '中关村街道,四道口路2号京果商厦负一楼物美市集内', 1226, '¥¥', 36.0, '4000051921', 'http://store.is.autonavi.com/showpic/5f3ccf13178876069c4df656db824d09', '["http://store.is.autonavi.com/showpic/5f3ccf13178876069c4df656db824d09", "https://store.is.autonavi.com/showpic/d93b78412d21789281eed7e82da3eea4", "http://store.is.autonavi.com/showpic/95d7b0c05cbe4a7c5273667c30a6777f"]', '["学生友好", "适合外带", "卤味零食", "夜宵推荐"]', 4.0, 0, 0, '京果商厦负一楼的熟食店，八珍王以卤味和酱货闻名，人均36元能买到各种卤鸭脖、鸡爪等，是追剧或宿舍夜聊的零食担当。', '八珍王(北京四道口路京果商厦店)位于京果商厦负一楼物美市集内，距离校园1226米。店内主打卤味熟食，如卤鸭脖、酱鸡爪、卤豆干等，味道浓郁，适合外带。环境是市集档口风格，服务直接，学生可自选搭配。参考人均36元，价格适中，尤其适合宿舍聚会或自习后打包带回，边刷剧边啃。', 0, '卤鸭脖');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_117', '虎头军煎饼北京邮电大学校内店', 'restaurant', 'cafe', 'place_001', 39.9601862, 116.3518981, '北京城区-北太平庄街道北京邮电大学', 182, '¥', 15.0, '15120017583', 'https://store.is.autonavi.com/showpic/df55c44430d972b21edda712c832b525', '["https://store.is.autonavi.com/showpic/df55c44430d972b21edda712c832b525", "https://store.is.autonavi.com/showpic/c26b76fa4720d0fe6927f04006bc18ad"]', '["校园内", "早餐首选", "学生友好", "现做现卖"]', 3.3, 0, 0, '北邮校园内的煎饼小店，虎头军煎饼是经典早餐，人均15元就能吃到现摊的薄脆煎饼，是校内学生的便捷之选。', '虎头军煎饼北京邮电大学校内店位于北邮校园内，距离校园仅182米，是校内学生的早餐和课间小吃首选。煎饼现摊，薄脆酥脆，搭配鸡蛋、酱料和葱花，口感丰富。环境是简易档口，服务高效，适合赶课学生。参考人均15元，价格亲民，评分3.3虽一般，但胜在位置便利，是校内食堂外的快捷选择。', 1, '招牌煎饼');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_118', '正新鸡排(北京财经大学店)', 'restaurant', '', 'place_001', 39.9586274, 116.3399936, '北京城区四道口路四道口村2号平房1.2幢', 1161, '¥', 13.0, '13663246708', 'http://store.is.autonavi.com/query_pic?id=st80923c27-cd0e-4450-83a2-239a22584288&user=search&operate=original', '["http://store.is.autonavi.com/query_pic?id=st80923c27-cd0e-4450-83a2-239a22584288&user=search&operate=original", "https://aos-comment.amap.com/B0LUDM8OX7/comment/content_media_external_file_1000014408_ss__1772959762755_42878054.jpg", "http://store.is.autonavi.com/showpic/0b1a9175dd83545bc0f22751a3805ef7"]', '["学生友好", "性价比高", "炸鸡小吃", "快捷美味"]', 3.9, 0, 0, '财经大学旁的正新鸡排，人均13元就能吃到招牌炸鸡排，外酥里嫩，是学生课后解馋的经典小吃。', '正新鸡排(北京财经大学店)位于四道口路，距离校园1161米，是周边学生的小吃据点。主打炸鸡排，现炸现卖，外皮酥脆，肉质鲜嫩，撒上孜然或辣椒粉，香气诱人。环境是街边档口，服务快捷，适合边走边吃或打包带回。参考人均13元，性价比高，尤其适合下午下课或晚自习后犒劳自己。', 1, '招牌鸡排');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_119', '元宝甑糕(枫蓝国际购物中心店)', 'restaurant', '', 'place_001', 39.9518326, 116.3499509, '西直门北大街32号院枫蓝国际购物中心B1层', 876, '¥', 22.0, '13126717322', 'https://aos-comment.amap.com/B0JA9RKDCT/comment/1231b139c9aed7c8dd57fa79be7261e2_2048_2048_80.jpg', '["https://aos-comment.amap.com/B0JA9RKDCT/comment/1231b139c9aed7c8dd57fa79be7261e2_2048_2048_80.jpg", "https://aos-comment.amap.com/B0JA9RKDCT/comment/f84bd95de5a83007ea71f85655d2b977_2048_2048_80.jpg", "https://aos-comment.amap.com/B0JA9RKDCT/comment/cb6f0cf84a223b6880ff4b03b9ca8de5_2048_2048_80.jpg"]', '["学生友好", "甜品推荐", "传统小吃", "适合外带"]', 3.7, 0, 0, '枫蓝国际B1层的元宝甑糕，人均22元能吃到软糯香甜的陕西传统甑糕，是甜品控的校园新宠。', '元宝甑糕(枫蓝国际购物中心店)位于西直门北大街枫蓝国际B1层，距离校园876米。店内主打陕西传统甑糕，用糯米、红枣蒸制而成，口感软糯，甜而不腻。环境是商场档口，干净整洁，适合逛街间隙或课后顺路品尝。参考人均22元，价格适中，尤其适合喜欢甜食的同学，可以买一份边走边吃。', 0, '传统甑糕');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_120', '蜀湘曹氏鸭脖', 'restaurant', '', 'place_001', 39.958964, 116.3396323, '四道口2号院2号楼1层101-19', 1191, '¥¥', 36.0, '', 'https://store.is.autonavi.com/showpic/835d28ad40904ef5882a4d8b686001b4', '["https://store.is.autonavi.com/showpic/835d28ad40904ef5882a4d8b686001b4", "https://store.is.autonavi.com/showpic/b6c7865f1e8aca99cb86314eb9967389", "https://store.is.autonavi.com/showpic/cf1a9369486eb0647000056d4d8b382e"]', '["学生友好", "辣卤经典", "夜宵推荐", "适合外带"]', 3.9, 0, 0, '四道口2号院的蜀湘曹氏鸭脖，人均36元能尝到辣卤鸭脖和鸭翅，是重口味爱好者的解馋圣地，适合宿舍夜宵。', '蜀湘曹氏鸭脖位于四道口2号院，距离校园1191米，主打辣卤鸭货，如鸭脖、鸭翅、鸭锁骨等，卤香浓郁，辣味十足。环境是街边小店，服务直接，学生可自选称重。参考人均36元，价格适中，尤其适合喜欢辣味的同学，买回宿舍边追剧边啃，或者作为聚会零食。', 0, '辣卤鸭脖');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_121', '麦多和馅饼(四道口路店)', 'restaurant', 'restaurant', 'place_001', 39.9582311, 116.3390766, '北京城区北京城区四道口2号11幢平房3号', 1243, '¥', 13.0, '19133300388', 'http://store.is.autonavi.com/showpic/0dce530b5ae343d6ee85e25d0c6baf07', '["http://store.is.autonavi.com/showpic/0dce530b5ae343d6ee85e25d0c6baf07", "https://aos-comment.amap.com/B0K1OX3BAV/comment/content_media_external_file_1000001397_ss__1761184690611_55740083.jpg", "https://aos-comment.amap.com/B0K1OX3BAV/comment/202509_10-20293_1757507385180_57000916.jpg"]', '["学生友好", "性价比高", "早餐首选", "出餐快", "平价美食"]', 3.9, 0, 0, '麦多和馅饼，校园旁的平价早餐王！现烤馅饼外皮酥脆，内馅饱满多汁，一口咬下超满足。赶课、夜宵首选，人均13元吃到撑，学生党的暖心食堂。', '这家店藏在四道口路边，店面虽小但烟火气十足。主打现烤馅饼，从经典猪肉大葱到创意照烧鸡腿，每一款都皮薄馅大、热乎出炉。老板动作麻利，出餐快，特别适合赶课的学生党。店内环境简单整洁，可打包带走，边走边吃也很方便。人均不到15元就能解决一餐，性价比超高，是校园周边不可错过的平价美食据点。', 0, '招牌猪肉大葱馅饼');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_122', '春莱·老挝冰咖啡·泰式奶茶(学院Live店)', 'restaurant', '', 'place_001', 39.9564265, 116.3405427, '北京城区北京城区交大东路2号院8栋学院Live商业B1', 1155, '¥', 16.0, '13401053410;18618158160', 'https://aos-comment.amap.com/B0L2ZR4K8P/comment/content_media_external_file_1000016752_ss__1772160147009_17651614.jpg', '["https://aos-comment.amap.com/B0L2ZR4K8P/comment/content_media_external_file_1000016752_ss__1772160147009_17651614.jpg", "https://store.is.autonavi.com/showpic/db8cacdcec59de09b87690e6af0b413b", "https://store.is.autonavi.com/showpic/35e8856e28a6715ba48599649f747c64"]', '["学生友好", "网红打卡", "异国风情", "下午茶", "适合自习"]', 3.8, 0, 0, '春莱·老挝冰咖啡，校园旁的东南亚风味驿站！袋装冰咖啡浓郁醇厚，泰式奶茶甜而不腻，人均16元就能体验异国风情，是下午茶和自习提神的好去处。', '走进春莱，仿佛穿越到东南亚街头，店内装饰充满热带风情，彩灯、藤椅、绿植营造出轻松惬意的氛围。招牌老挝冰咖啡用塑料袋装着，冰爽浓郁，是夏日解暑神器；泰式奶茶香甜顺滑，适合搭配甜品。店家还提供免费WiFi，不少学生喜欢来这里自习或小聚。价格亲民，人均十几元就能享受异国风味，是校园周边独特的休闲角落。', 1, '老挝冰咖啡');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_123', '一手店(枫蓝国际购物中心店)', 'restaurant', 'cafe', 'place_001', 39.9517585, 116.3500378, '西直门北大街32号(枫蓝国际购物中心B1层)', 881, '¥¥', 36.0, '13930768887;19568726532', 'http://store.is.autonavi.com/showpic/2d1a275cd9e5266f59b26cc8eb71dfd4', '["http://store.is.autonavi.com/showpic/2d1a275cd9e5266f59b26cc8eb71dfd4", "https://aos-comment.amap.com/B0FFHD44M8/comment/2ACDA194_7A67_41F7_BC35_3BDDBA976630_L0_001_1500_2000_1740125712970_36458578.jpg", "https://aos-comment.amap.com/B0FFHD44M8/comment/174122469021_1741224698172_80403072.jpg"]', '["学生友好", "性价比高", "熟食卤味", "适合聚餐", "追剧零食"]', 3.6, 0, 0, '一手店，枫蓝国际里的熟食宝藏店！卤味、凉菜、熟食种类丰富，价格实惠，适合宿舍聚餐或追剧加餐。人均36元，学生党的解馋好选择。', '一手店位于枫蓝国际购物中心B1层，店面整洁明亮，各种熟食、卤味、凉菜整齐陈列。从酱猪蹄到卤牛肉，从凉拌海带丝到泡椒凤爪，应有尽有。店员热情，可以按需称重购买，非常适合宿舍聚餐、追剧时当零食或下酒菜。价格亲民，人均30多元就能买一堆，性价比很高。位置离校园不远，逛商场时顺便带点回去，方便又美味。', 0, '酱猪蹄');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_124', '咏巷炸鸡(枫蓝国际店)', 'restaurant', '', 'place_001', 39.9517345, 116.3500168, '北京城区西直门北大街32号院枫蓝国际购物中心B1层', 885, '¥¥', 33.0, '15003308469', 'https://store.is.autonavi.com/showpic/dcb404c11a24c3ab0000002634662035?type=pic', '["https://store.is.autonavi.com/showpic/dcb404c11a24c3ab0000002634662035?type=pic", "https://aos-comment.amap.com/B0KK5LBGYK/comment/content_media_external_images_media_348759_ss__1735817094041_46117982.jpg", "https://aos-comment.amap.com/B0KK5LBGYK/comment/content_media_external_images_media_348772_ss__1735817094042_11294603.jpg"]', '["学生友好", "深夜营业", "炸鸡控", "性价比高", "适合解馋"]', 3.6, 0, 0, '咏巷炸鸡，枫蓝国际里的炸鸡王者！外酥里嫩，现炸现卖，撒上秘制调料香气扑鼻。人均33元，是学生党解馋、聚会、夜宵的热门选择。', '咏巷炸鸡的店面不大，但炸鸡的香味总能飘出老远。招牌炸鸡块、鸡翅、鸡腿都是现点现炸，外皮金黄酥脆，内里肉质鲜嫩多汁。撒上孜然、辣椒或甘梅粉，每一口都超满足。店内提供堂食和打包，环境简洁干净。不少学生下课后会来买一份，边走边吃或带回宿舍。价格适中，人均30多元，是校园周边炸鸡界的性价比之王。', 1, '招牌炸鸡块');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_125', '沙县小吃', 'restaurant', 'restaurant', 'place_001', 39.9553789, 116.3522012, '学院南路32号', 441, '¥', 24.0, '13681347223', 'https://store.is.autonavi.com/showpic/08bd5d41a34bc86a0ad1bca16db726ee', '["https://store.is.autonavi.com/showpic/08bd5d41a34bc86a0ad1bca16db726ee", "https://store.is.autonavi.com/showpic/2466acd95d052f3f0000002594956149?type=pic", "https://store.is.autonavi.com/showpic/5a99c03298af0a510000002594956150?type=pic"]', '["学生友好", "平价食堂", "深夜营业", "经典小吃", "出餐快"]', 3.3, 0, 0, '沙县小吃，校园旁的老牌平价食堂！蒸饺、拌面、炖罐，经典家常味，人均24元吃饱吃好。赶课、夜宵、省钱时的不二之选。', '这家沙县小吃就在学院南路，离校园仅400多米，是学生们的日常食堂。店面不大但干净卫生，老板热情好客。招牌蒸饺皮薄馅鲜，蘸上醋和辣椒油，一口一个；花生酱拌面浓香顺滑，是很多人的最爱；炖罐汤清味美，暖胃又暖心。价格实惠，人均20多元就能吃得饱饱的。无论是赶课时的快速午餐，还是深夜的暖心夜宵，这里都能满足你。', 1, '蒸饺+花生酱拌面');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_126', '小时代美食城(京果商厦A座店)', 'restaurant', 'restaurant', 'place_001', 39.9589497, 116.3392961, '四道口路2号院号物美超市京果商厦', 1219, '¥', 25.0, '010-62121226', 'http://store.is.autonavi.com/showpic/29d7ac89025b2548aa37f61f50da29ee', '["http://store.is.autonavi.com/showpic/29d7ac89025b2548aa37f61f50da29ee", "http://store.is.autonavi.com/showpic/961ac13ad35eb03e4c52f1598aec9cae", "http://store.is.autonavi.com/showpic/c50504a0c5de4489f29125488fff4644"]', '["学生友好", "性价比高", "美食集合", "适合聚餐", "选择多样"]', 3.8, 0, 0, '小时代美食城，校园旁的平价美食集合地！各种小吃档口，从麻辣烫到炒饭，人均25元吃遍南北风味。适合学生聚餐、午餐选择困难症。', '小时代美食城位于京果商厦内，是一个热闹的美食集合空间。里面分布着多个档口，提供麻辣烫、烤串、炒饭、米线、盖饭等多样选择，价格都在十几到二十元之间。环境虽然简单，但烟火气十足，饭点时人声鼎沸，很有生活气息。适合和同学一起来，各点各的，然后拼桌吃。人均25元左右就能吃得丰富多样，是解决午餐或晚餐的好去处。', 1, NULL);
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_127', '窑鸡王', 'restaurant', '', 'place_001', 39.954876, 116.3521793, '学院南路32号院东区西2门旁', 496, '¥¥', 41.0, '', 'https://store.is.autonavi.com/showpic/ef3bcd006c08b0d6b9599097e7446528?operate=original', '["https://store.is.autonavi.com/showpic/ef3bcd006c08b0d6b9599097e7446528?operate=original"]', '["学生友好", "深夜营业", "肉食爱好者", "适合拼单", "外卖友好"]', 3.3, 0, 0, '窑鸡王，校园旁的夜宵王者！整只窑鸡香气扑鼻，皮脆肉嫩，撕开汁水直流。人均41元，适合宿舍拼单或深夜解馋。', '窑鸡王位于学院南路，离校园步行几分钟。主打整只窑鸡，用秘制酱料腌制后烤制，外皮焦香，内里鸡肉鲜嫩多汁。店面不大，主要做外卖和打包，但香味总能飘到街上。不少学生会提前预订，晚上回宿舍时带一只，大家一起撕着吃，超有满足感。价格稍高但分量足，人均40多元，适合三五人拼单。深夜想吃肉时，这里绝对是首选。', 1, '招牌窑鸡');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_128', '拌将麻辣拌·麻辣烫(四道口店)', 'restaurant', '', 'place_001', 39.9562755, 116.3411414, '北京城区北京城区朝阳区交大东路2号院学院里', 1111, '¥', 26.0, '18721319622', 'https://store.is.autonavi.com/showpic/86cc412a8b597a810000002462642826?type=pic', '["https://store.is.autonavi.com/showpic/86cc412a8b597a810000002462642826?type=pic", "https://aos-comment.amap.com/B0LB7UOFEI/comment/content_media_external_file_1000016742_ss__1772159833204_47493447.jpg", "https://store.is.autonavi.com/showpic/6734c9d8c6db3eb20000002462634926?type=pic"]', '["学生友好", "麻辣控", "性价比高", "自选食材", "出餐快"]', 3.7, 0, 0, '拌将麻辣拌·麻辣烫，校园旁的麻辣拌新宠！自选食材，现拌现吃，酱料浓郁超入味。人均26元，学生党的麻辣瘾解药。', '拌将位于交大东路学院里，主打麻辣拌和麻辣烫。店内食材新鲜多样，从蔬菜到丸子、肉类，可以自选搭配。选好后，店员会现场煮熟，再用秘制酱料拌匀，麻辣鲜香，超级入味。与普通麻辣烫不同，这里更注重酱料的口感，每一口都裹满酱汁。环境干净明亮，适合一人食或朋友小聚。人均20多元，性价比高，是校园周边麻辣爱好者的宝藏小店。', 1, '招牌麻辣拌');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_129', '东北菜铁锅炖', 'restaurant', 'restaurant', 'place_001', 39.9545806, 116.3524478, '学院南路32号院东区西2门旁', 523, '¥¥¥', 80.0, '', 'uploads/images/surrounding/东北菜铁锅炖.jpg', '[]', '["适合聚会", "东北风味", "分量十足", "氛围感强", "聚餐首选"]', 3.3, 0, 0, '东北菜铁锅炖，校园旁的聚会天堂！大铁锅炖菜热气腾腾，分量十足，人均80元适合宿舍聚餐。体验东北豪爽风情，暖胃又暖心。', '这家东北菜铁锅炖就在学院南路，离校园很近。店内装修充满东北农家风格，大炕、花布、红灯笼，氛围感十足。主打铁锅炖，有排骨、鸡、鱼等多种选择，配菜丰富，一锅能装下五六个人的量。炖煮过程中香气四溢，掀开锅盖时热气腾腾，超有仪式感。服务员热情，还会帮忙贴玉米饼子。人均80元左右，虽然稍贵，但分量足，适合宿舍或社团聚餐。', 0, '铁锅炖排骨');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_130', '胤韩紫菜包饭·炸鸡·拌饭(四道口店)', 'restaurant', '', 'place_001', 39.9563602, 116.3407083, '交大东路2号院学院LIVE商业街B1层', 1143, '¥', 29.0, '15810592023', 'https://store.is.autonavi.com/showpic/224b55ac6f241199be9649b7b9497132', '["https://store.is.autonavi.com/showpic/224b55ac6f241199be9649b7b9497132", "https://aos-comment.amap.com/B0JK0LTT8C/comment/0A938BD1_4E0D_4E98_9FF7_BC610C4A0F92_L0_001_1500_2000_1731569512858_30990235.jpg", "https://aos-comment.amap.com/B0JK0LTT8C/comment/2bbdd16dfd3ccc5cd62b2805d6e1ffaa_2048_2048_80.jpg"]', '["学生友好", "韩式简餐", "性价比高", "适合一人食", "出餐快"]', 3.7, 0, 0, '胤韩紫菜包饭·炸鸡·拌饭，校园旁的韩式简餐店！紫菜包饭料足味美，炸鸡酥脆，拌饭香浓。人均29元，学生党的韩餐首选。', '胤韩位于学院LIVE商业街B1层，店面清新简约，充满韩式风格。主打紫菜包饭、炸鸡和拌饭，食材新鲜，味道正宗。紫菜包饭种类丰富，有金枪鱼、牛肉、泡菜等口味，每一卷都料足饱满；炸鸡外酥里嫩，搭配甜辣酱超好吃；拌饭酱香浓郁，锅巴脆脆的。价格亲民，人均不到30元就能吃得满足。适合一人食或和朋友一起，是校园周边韩餐爱好者的宝藏店。', 1, '金枪鱼紫菜包饭');
