INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_141', '紫燕百味鸡(北京四道口外卖专营店)', 'restaurant', '', 'place_001', 39.9591287, 116.339295, '北京城区四道口2号院1号楼2层202号', 1219, '¥¥', 35.0, '18205180721', 'http://store.is.autonavi.com/query_pic?id=sta0a759f3-d884-4bab-8452-52f0d8e37257&user=search&operate=original', '["http://store.is.autonavi.com/query_pic?id=sta0a759f3-d884-4bab-8452-52f0d8e37257&user=search&operate=original"]', '["外卖专营", "卤味下饭", "学生友好", "性价比高"]', 3.6, 0, 0, '专营外卖的紫燕百味鸡，招牌夫妻肺片和百味鸡是下饭神器。秘制卤味香浓入味，价格亲民，是宿舍加餐或追剧零食的绝佳选择。', '这家紫燕百味鸡主打外卖，店面虽小但出餐效率高。招牌夫妻肺片红油透亮，牛肉、牛肚等食材拌得入味，麻辣鲜香；百味鸡皮脆肉嫩，卤汁醇厚。还有藤椒鸡、酸辣海带丝等小菜，搭配米饭就是完美一餐。适合不想出门的懒人党，或考试周囤货。虽然评分一般，但胜在经典口味稳定，性价比高，人均35元就能吃得满足。', 0, '夫妻肺片');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_142', '山西刀削面(明光东路店)', 'restaurant', 'restaurant', 'place_001', 39.9584452, 116.3389868, '四道口路乐天玛特1层', 1248, '¥', 23.0, '010-82106905;15201117037', 'http://store.is.autonavi.com/showpic/68e2395d14195540de460aea39357af4', '["http://store.is.autonavi.com/showpic/68e2395d14195540de460aea39357af4", "https://aos-comment.amap.com/B000A809Q0/comment/2025-11-09-21-39-16%2B5272F9E7-5E15-45F9-B503-B0BA49D71EC_1762695561922_80229345.jpg", "https://aos-comment.amap.com/B000A809Q0/comment/2025-11-09-21-39-14%2B32BE3A04-85F1-4CCC-BB75-B0E98473497_1762695561921_15333051.jpg"]', '["平价食堂", "面条筋道", "学生友好", "快速简餐"]', 3.6, 0, 0, '正宗山西刀削面，面条筋道爽滑，臊子香浓实惠。23元人均就能吃撑，是附近学生解决午餐晚餐的宝藏小馆。', '小店开在乐天玛特一层，环境简朴但烟火气十足。师傅现场削面，面条厚薄均匀、入口弹牙。招牌刀削面可选牛肉、猪肉或素臊子，汤底用骨头熬制，浓郁鲜香。加上一勺辣椒油和醋，酸辣开胃。还有凉皮、肉夹馍等小吃，适合赶课间隙快速填饱肚子。虽然评分不高，但胜在便宜大碗，是校园周边的平价食堂。', 0, '牛肉刀削面');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_143', '麦田归来·四季轻食(四道口店)', 'restaurant', '', 'place_001', 39.9559261, 116.3407922, '北京城区交大东路2号院学院里', 1151, '¥', 24.0, '13552900336', 'https://store.is.autonavi.com/showpic/acd345a5ce8992a53534c1e46f35740a', '["https://store.is.autonavi.com/showpic/acd345a5ce8992a53534c1e46f35740a", "https://store.is.autonavi.com/showpic/5705680e28d1093c33e8d16b478b40d1"]', '["健康轻食", "减脂友好", "学生友好", "清新环境"]', 3.5, 0, 0, '主打四季轻食的健康餐厅，低卡沙拉和暖沙拉是减脂党福音。人均24元，食材新鲜，配料丰富，适合追求轻食主义的你。', '店面位于交大东路学院里，环境清新简约，适合一人食或闺蜜小聚。菜单以沙拉、波奇饭、三明治为主，招牌“四季轻食碗”可选鸡胸肉、虾仁或豆腐，搭配时令蔬菜和杂粮饭，淋上自选酱汁，清爽饱腹。还有暖沙拉适合冬天。服务贴心，可定制口味。适合健身党、减肥期或想换个清淡口味的学生，价格对学生党友好。', 0, '四季轻食碗');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_144', '老北京炸酱面(师范大学店)', 'restaurant', 'restaurant', 'place_001', 39.9568584, 116.3537611, '北京交通大学附属中学分校东南门旁', 261, '¥¥', 51.0, '13699100403', 'http://store.is.autonavi.com/showpic/76f6f3346a2a9b5863ba7b841fd0997a', '["http://store.is.autonavi.com/showpic/76f6f3346a2a9b5863ba7b841fd0997a", "https://aos-comment.amap.com/B0JRNLSY19/comment/content_media_external_images_media_100008329_1740988124761_32326167.jpg", "https://aos-comment.amap.com/B0JRNLSY19/comment/content_media_external_images_media_100008329_1740988124760_67240153.jpg"]', '["老北京风味", "炸酱面", "位置便利", "评分较低"]', 2.9, 0, 0, '主打老北京炸酱面的小店，靠近师范大学，炸酱面码子丰富。人均51元，味道传统但评分偏低，适合想尝尝地道北京味的学生。', '店在交大附中分校东南门旁，位置便利，但评分仅2.9，需谨慎选择。炸酱面是招牌，手擀面条筋道，炸酱咸香，配菜有黄瓜丝、豆芽等，拌匀后酱香浓郁。还有京酱肉丝、芥末墩等老北京菜。环境一般，服务中规中矩。适合想体验北京风味的外地学生，或朋友聚餐尝鲜。但价格略高，人均51元，性价比一般。', 0, '老北京炸酱面');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_145', '极速披萨', 'restaurant', 'cafe', 'place_001', 39.958518, 116.3396863, '北京城区四道口路2号京果商厦B座F1层', 1188, '¥', 30.0, '13520425299', 'https://store.is.autonavi.com/showpic/2f5be7918b6895252dd0f26562f58222', '["https://store.is.autonavi.com/showpic/2f5be7918b6895252dd0f26562f58222"]', '["快速出餐", "披萨", "学生友好", "外卖方便"]', 3.5, 0, 0, '极速披萨主打快速出餐的经典披萨，口味多样，价格亲民。人均30元就能吃到热乎的披萨，适合学生小聚或外卖解馋。', '店在京果商厦B座一层，主打外卖和快速堂食。披萨有经典意式、美式厚底等选择，如玛格丽特、超级至尊等，料足芝士多。还有意面、焗饭等简餐。出餐快，适合课间或自习后快速解决。虽然评分3.5，但胜在便宜方便，30元就能吃饱。环境简单，适合一人食或和朋友拼单。', 0, '超级至尊披萨');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_146', '万家早安·品致早餐(北下关店)', 'restaurant', 'cafe', 'place_001', 39.9593285, 116.3393948, '北京城区四道口2号20号楼3层', 1211, '¥', 19.0, '15910625889', 'http://store.is.autonavi.com/showpic/89a932a9a2710780af062f4e6169017d', '["http://store.is.autonavi.com/showpic/89a932a9a2710780af062f4e6169017d", "http://store.is.autonavi.com/showpic/ad51a98056dada9d9323bfb39a51fdf0", "http://store.is.autonavi.com/showpic/e968b01a641a45996fb82fe118e6b4d2"]', '["早餐", "精致轻食", "学生友好", "性价比高"]', 3.5, 0, 0, '品致早餐店，主打精致早餐和轻食，人均19元。环境干净，包子、粥、三明治等选择丰富，适合早起上课前来一份元气早餐。', '店在北下关，环境明亮整洁，适合早餐时段。菜单有传统中式早餐如小笼包、豆浆油条，也有西式三明治、咖啡。招牌“品致早餐套餐”包含主食、饮品和小菜，营养均衡。出餐快，适合赶早课的学生。虽然评分3.5，但价格实惠，19元就能吃好。适合想好好吃早餐、追求健康生活的学生。', 0, '品致早餐套餐');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_147', '牛约堡·手作牛肉汉堡(四道口店)', 'restaurant', 'cafe', 'place_001', 39.9591906, 116.339327, '京果商厦A座3层橘猫美食城', 1217, '¥', 30.0, '17600309659;18201243624', 'https://img.alicdn.com/imgextra/i2/O1CN01wqgQAn1bDS05Su1Wo_!!6000000003431-2-tps-543-536.png', '["https://img.alicdn.com/imgextra/i2/O1CN01wqgQAn1bDS05Su1Wo_!!6000000003431-2-tps-543-536.png", "http://store.is.autonavi.com/showpic/a79eb2cefd1702effb9b844f77ec5f1f", "http://store.is.autonavi.com/showpic/1c41c59534475d88f96495a08b67496a"]', '["手作汉堡", "肉食爱好者", "学生友好", "外卖方便"]', 3.5, 0, 0, '手作牛肉汉堡店，主打现做厚实牛肉饼，搭配新鲜蔬菜。人均30元，性价比高，适合肉食爱好者解馋。', '藏在京果商厦橘猫美食城内，小店主打外卖和堂食。牛肉饼手打现煎，汁水丰富，搭配培根、芝士、生菜等，层次感强。还有薯条、鸡翅等小食。环境简单，适合快速填饱肚子。评分3.5，但学生评价不错。适合想吃汉堡又不想花大钱的学生，30元就能吃到满足。', 0, '手作牛肉汉堡');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_148', '好运鸭徽州鸭头', 'restaurant', '', 'place_001', 39.9577655, 116.339407, '北京城区四道口2号', 1220, '¥', 27.0, '13688633291;15127054068', 'https://store.is.autonavi.com/showpic/9b0c16507c9b836ad1d1db7d512fad4e', '["https://store.is.autonavi.com/showpic/9b0c16507c9b836ad1d1db7d512fad4e", "https://aos-comment.amap.com/B0L1XHQWSH/comment/content_media_external_file_100003461_1757420634480_52971953.jpg", "https://aos-comment.amap.com/B0L1XHQWSH/comment/content_media_external_file_100003461_1757420634469_28614475.jpg"]', '["卤味", "麻辣", "学生友好", "零食", "外卖方便"]', 3.5, 0, 0, '徽州风味鸭头店，鸭头卤得入味，麻辣鲜香。人均27元，适合当零食或下酒菜，是宿舍追剧的绝配。', '小店主打外卖和即买即走，鸭头是招牌，先卤后炸，外酥里嫩，麻辣味十足。还有鸭脖、鸭翅、藕片等卤味，辣度可选。适合晚上饿了下单，或聚会时当零食。虽然评分3.5，但价格实惠，27元就能买不少。适合喜欢重口味卤味的学生。', 0, '徽州鸭头');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_149', '爱麻辣香锅烤鱼美蛙(京果商厦A座店)', 'restaurant', 'restaurant', 'place_001', 39.9591397, 116.3392471, '学院南路京果商厦A座橘猫精选餐厅2楼C5档口', 1223, '¥¥¥', 104.0, '15910605799;15911164136', 'http://store.is.autonavi.com/showpic/08161c5d117f8dde3d226efffbfa8104', '["http://store.is.autonavi.com/showpic/08161c5d117f8dde3d226efffbfa8104"]', '["聚餐", "麻辣", "烤鱼", "美蛙", "热闹环境"]', 3.5, 0, 0, '主打麻辣香锅、烤鱼和美蛙的餐厅，人均104元，适合聚餐。口味重辣鲜香，环境热闹，是朋友聚会的好去处。', '店在京果商厦橘猫精选餐厅2楼，环境热闹，适合多人聚餐。麻辣香锅可选多种食材，爆炒后麻辣鲜香；烤鱼外焦里嫩，汤汁入味；美蛙肉质细嫩。人均104元，价格偏高，但分量足，适合生日、团建等场合。评分3.5，学生评价两极，喜欢重口味的会爱。', 0, '麻辣香锅');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_150', '生鲜超市百家卤味', 'restaurant', 'cafe', 'place_001', 39.9580899, 116.3391674, '世纪景园商务中心B座正门西60米', 1236, '¥', 14.0, '18810578680', 'https://store.is.autonavi.com/showpic/87f91ea4cda74608e5d5887a0453d44b', '["https://store.is.autonavi.com/showpic/87f91ea4cda74608e5d5887a0453d44b", "https://store.is.autonavi.com/showpic/a4ca2b2d38c310d9a408cdd4db718333", "http://store.is.autonavi.com/showpic/0fa9e67f0ff8506d185598e8ec8c7722"]', '["卤味", "超市", "超低价", "学生友好", "即买即走"]', 3.5, 0, 0, '生鲜超市内的百家卤味，主打现做卤味熟食，价格超低，人均14元。鸡爪、猪蹄等卤味新鲜实惠，适合买回宿舍加餐。', '开在世纪景园商务中心附近的生鲜超市里，主打即买即走的卤味。有卤鸡爪、猪蹄、牛肉等，现卤现卖，味道家常。价格极低，人均14元就能买不少。环境就是超市档口，适合顺路买点回宿舍当零食或下饭菜。虽然评分3.5，但胜在便宜新鲜。', 0, '卤鸡爪');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_151', 'HotPotato薯条专门店(交大东路店)', 'restaurant', '', 'place_001', 39.956226, 116.3408421, '北京城区交大东路2号院8幢-1层B102', 1137, '¥', 13.0, '15010388028', 'https://store.is.autonavi.com/showpic/9613723c11eae0c511f7ab0eb8c94c33', '["https://store.is.autonavi.com/showpic/9613723c11eae0c511f7ab0eb8c94c33"]', '["学生友好", "性价比高", "现炸薯条", "平价小吃"]', 3.4, 0, 0, '交大东路旁的平价薯条天堂！HotPotato主打现炸薯条，外酥里嫩，13元就能吃到撑，是学生党解馋的宝藏小店。', '位于交大东路地下一层的HotPotato薯条专门店，环境简约温馨，主打各种口味的手工薯条。店内弥漫着现炸薯条的香气，每一根都金黄酥脆，外焦里嫩。老板热情，份量十足，13元的人均价格对学生党极其友好。适合下课后来一份当零食，或和室友一起分享。虽然评分不高，但性价比超高，是校园周边不可错过的平价美食。', 1, '招牌现炸薯条');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_152', '阿里·新疆烧烤拌面大盘鸡', 'restaurant', 'restaurant', 'place_001', 39.9581583, 116.3400665, '四道口路2号京果商厦B座', 1159, '¥¥', 46.0, '', 'https://store.is.autonavi.com/showpic/d32613e34da72a761faa256a0fc77b24', '["https://store.is.autonavi.com/showpic/d32613e34da72a761faa256a0fc77b24"]', '["适合聚会", "新疆风味", "大盘鸡", "烧烤夜宵"]', 3.4, 0, 0, '想吃正宗新疆味？阿里烧烤拌面大盘鸡，46元人均，大盘鸡拌面香浓过瘾，烧烤烟火气十足，是宿舍聚餐的热门选择。', '位于京果商厦B座的阿里新疆烧烤拌面大盘鸡，是校园周边新疆风味的人气据点。店内环境充满西域风情，烟火气十足。招牌大盘鸡份量惊人，鸡肉鲜嫩，土豆绵软，搭配宽面吸饱汤汁，每一口都满足。烧烤系列更是夜宵必备，羊肉串肥瘦相间，孜然香气扑鼻。适合社团聚餐、宿舍小聚，人均46元就能吃撑，性价比很高。', 0, '大盘鸡拌面');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_153', '好好吃.脆皮鸡烤肉拌饭(京果商厦A座店)', 'restaurant', 'cafe', 'place_001', 39.9584319, 116.3397541, '北京城区京果商厦B座', 1183, '¥¥¥', 71.0, '13641300399', 'https://store.is.autonavi.com/showpic/b9a0460b801ca370430d9de951569604', '["https://store.is.autonavi.com/showpic/b9a0460b801ca370430d9de951569604"]', '["肉食爱好者", "脆皮鸡", "烤肉拌饭", "快餐简餐"]', 3.4, 0, 0, '脆皮鸡烤肉拌饭的绝妙组合！好好吃主打脆皮鸡和烤肉双拼，71元人均，外皮焦脆，肉质多汁，是肉食爱好者的福音。', '京果商厦A座的‘好好吃’专做脆皮鸡烤肉拌饭，环境干净明亮，主打快餐式简餐。招牌脆皮鸡外皮炸得金黄酥脆，里面鸡肉嫩滑多汁，搭配特制酱料和米饭，一口下去层次丰富。还有烤肉拌饭、双拼等选择，份量足，适合午餐或晚餐快速解决。虽然人均71元稍高，但用料扎实，适合偶尔犒劳自己。', 0, '脆皮鸡拌饭');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_154', '永顺炸鸡(京果商厦B座店)', 'restaurant', '', 'place_001', 39.958208, 116.3391395, '', 1237, '¥¥', 31.0, '', 'https://store.is.autonavi.com/showpic/c71c854e836bdf8a0000000954076042?type=pic', '["https://store.is.autonavi.com/showpic/c71c854e836bdf8a0000000954076042?type=pic", "http://store.is.autonavi.com/showpic/bec35cbea2ef0cd5e04f52565dd4f7e9", "https://store.is.autonavi.com/showpic/e6b38bddabf249deb7899043890fb571"]', '["学生友好", "老店", "炸鸡", "性价比高"]', 3.4, 0, 0, '永顺炸鸡，京果商厦的老牌炸鸡店！31元人均，外皮酥脆，鸡肉鲜嫩多汁，是校园周边解馋的经典选择。', '京果商厦B座的永顺炸鸡，是附近学生从小吃到大的老店。店面不大，但炸鸡香气四溢，每次路过都忍不住买一份。招牌炸鸡腿外皮酥脆掉渣，咬开鸡肉嫩滑多汁，腌制入味。还有鸡翅、鸡块等选择，价格亲民，31元就能吃得很满足。适合课间加餐或晚上追剧时享用，是校园周边的经典小吃。', 1, '招牌炸鸡腿');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_155', '成都小吃(四道口店)', 'restaurant', '', 'place_001', 39.9583522, 116.3390307, '北京城区京果商厦西南2门旁', 1245, '¥¥', 33.0, '13661331077', 'https://store.is.autonavi.com/showpic/1ef31224f48705498a11245226f0e25e', '["https://store.is.autonavi.com/showpic/1ef31224f48705498a11245226f0e25e", "https://store.is.autonavi.com/showpic/e96340a96d0f26a883f62a5d0e60a1d6", "http://store.is.autonavi.com/showpic/18dc14f52f41cfd57a0f144c44ed942d"]', '["川味", "麻辣鲜香", "学生友好", "性价比高"]', 3.4, 0, 0, '四道口的成都小吃，33元人均，麻辣鲜香，地道川味。从担担面到水煮鱼，每一口都是成都街头的味道，适合无辣不欢的你。', '位于京果商厦西南门旁的成都小吃，是校园周边川味爱好者的秘密基地。环境朴实，充满市井烟火气。菜单丰富，从担担面、酸辣粉到水煮鱼、回锅肉，每道菜都麻辣鲜香，用料实在。人均33元就能吃到撑，性价比超高。适合和同学一起来，边吃边聊，感受地道的成都风味。', 1, '担担面');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_156', '西少爷(四道口店)', 'restaurant', 'cafe', 'place_001', 39.9584274, 116.3399936, '四道口路2号京果商厦B座', 1163, '¥', 23.0, '', 'https://store.is.autonavi.com/showpic/1207a5f2b668cdd00000000959896777?type=pic', '["https://store.is.autonavi.com/showpic/1207a5f2b668cdd00000000959896777?type=pic", "https://store.is.autonavi.com/showpic/9025925e093c6618f55397c8d0ea612e"]', '["学生友好", "快餐", "肉夹馍", "性价比高"]', 3.3, 0, 0, '西少爷四道口店，23元人均，肉夹馍和凉皮的经典搭配。现烤馍皮酥脆，肉香四溢，是校园周边快捷午餐的标杆。', '西少爷四道口店位于京果商厦B座，环境整洁明亮，主打中式快餐。招牌肉夹馍，馍皮现烤酥脆，夹着肥瘦相间的卤肉，一口咬下肉汁四溢。搭配一份酸辣爽口的凉皮，就是完美的午餐组合。人均23元的价格对学生党极其友好，出餐速度快，适合课间快速解决一餐。', 1, '经典肉夹馍');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_157', '厚府·牛油拌饭(四道口店)', 'restaurant', 'cafe', 'place_001', 39.9582445, 116.3399807, '北京城区四道口2号院2号楼1层111号', 1166, '¥', 19.0, '18612062138', 'https://aos-comment.amap.com/B0JBSANRI8/comment/83A45C9D_9D90_43A5_AFB0_F3C928DA2475_L0_001_1280_1446__1693461175033_4fbab2cd.jpg', '["https://aos-comment.amap.com/B0JBSANRI8/comment/83A45C9D_9D90_43A5_AFB0_F3C928DA2475_L0_001_1280_1446__1693461175033_4fbab2cd.jpg", "https://aos-comment.amap.com/B0JBSANRI8/comment/987DECCA_7E55_417F_BA4A_85C727539145_L0_001_1279_1192__1693461175033_8ab01a78.jpg", "https://aos-comment.amap.com/B0JBSANRI8/comment/F3855095_DADF_4D0A_8CB1_F4DECB846044_L0_001_1279_1070__1693461175033_65949345.jpg"]', '["学生友好", "性价比高", "牛油拌饭", "平价午餐"]', 3.3, 0, 0, '厚府·牛油拌饭，19元人均，牛油拌饭香浓不腻，每一粒米饭都裹满牛油香气，是学生党省钱的宝藏午餐。', '四道口附近的厚府·牛油拌饭，环境简约干净，主打牛油拌饭系列。招牌牛油拌饭，米饭粒粒分明，拌入特制牛油和酱料，香气扑鼻，口感丰富而不腻。还有多种配菜可选，如煎蛋、蔬菜等。人均19元的价格是附近最实惠的选择之一，适合预算紧张时来一碗，吃得饱又满足。', 1, '招牌牛油拌饭');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_158', '极度PizzAの全麦软底', 'restaurant', 'cafe', 'place_001', 39.958518, 116.3396863, '四道口路2号京果商厦B座F1层', 1188, '¥', 29.0, '13520425299;17630808303', 'http://store.is.autonavi.com/showpic/db827cc8497d71caeb74fe6020e545d1', '["http://store.is.autonavi.com/showpic/db827cc8497d71caeb74fe6020e545d1", "https://aos-comment.amap.com/B0HRO7LMBZ/comment/69f6d31aac676e434025d82b56d78960_2048_2048_80.jpg", "https://aos-comment.amap.com/B0HRO7LMBZ/comment/0bb697fe8eee8eb054916159b46dba9b_2048_2048_80.jpg"]', '["学生友好", "健康披萨", "全麦饼底", "性价比高"]', 3.3, 0, 0, '极度PizzA的全麦软底披萨，29元人均，主打健康全麦饼底，料足味美，是披萨爱好者的清新之选。', '京果商厦B座一层的极度PizzA，主打全麦软底披萨，环境轻松休闲。招牌全麦饼底比传统披萨更健康，口感软韧有嚼劲，搭配新鲜蔬菜和芝士，料足味美。还有多种口味可选，如经典玛格丽特、培根等。人均29元的价格很亲民，适合和同学一起分享，或一个人来份单人套餐。', 1, '全麦软底披萨');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_159', '喜赞·暖轻食·健康餐(西直门店)', 'restaurant', 'cafe', 'place_001', 39.9591197, 116.3392511, '北京城区四道口2号院1号楼2层226号', 1223, '¥', 21.0, '', 'https://store.is.autonavi.com/showpic/ffee7dc8158e81c7a60c75d83ce1a4f3', '["https://store.is.autonavi.com/showpic/ffee7dc8158e81c7a60c75d83ce1a4f3"]', '["健康餐", "学生友好", "低卡", "轻食"]', 3.2, 0, 0, '喜赞·暖轻食·健康餐，21元人均，沙拉和暖轻食的完美结合，低卡又美味，是健身和减脂同学的日常食堂。', '西直门店的喜赞·暖轻食，环境清新自然，主打健康轻食。菜单丰富，有各种沙拉、暖轻食碗、三明治等，食材新鲜，搭配合理。招牌暖轻食碗，蔬菜、谷物、蛋白质一应俱全，调味清爽不油腻。人均21元的价格在轻食界极具竞争力，适合健身前后或想清淡饮食时来一份，吃得健康又满足。', 1, '暖轻食碗');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_160', '大胡子冰可可(学院Live店)', 'restaurant', '', 'place_001', 39.9563762, 116.3407423, '交大东路2号院学院里', 1140, '¥', 24.0, '18618158160', 'uploads/images/surrounding/大胡子冰可可(学院Live店).jpg', '[]', '["学生友好", "现场音乐", "冰可可", "休闲放松"]', 3.1, 0, 0, '大胡子冰可可，学院Live店，24元人均，冰可可浓郁丝滑，搭配现场音乐，是交大东路旁的休闲放松好去处。', '交大东路学院里的‘大胡子冰可可’，环境充满文艺气息，常有现场音乐表演。招牌冰可可，用优质可可粉调制，口感浓郁丝滑，冰爽解暑。还有多种口味可选，如薄荷、焦糖等。人均24元，适合课后和朋友来坐坐，听听音乐，放松心情。虽然评分不高，但独特的氛围和亲民价格吸引了不少学生。', 1, '招牌冰可可');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_161', '冒菜西施·成都火锅冒菜·麻辣烫(海淀店)', 'restaurant', 'cafe', 'place_001', 39.9591197, 116.3392511, '北京城区四道口2号院1号楼二层202号', 1223, '¥', 15.0, '18611120525', 'https://store.is.autonavi.com/showpic/bfa3eeef5d9c0fabfa1c41178d71e971', '["https://store.is.autonavi.com/showpic/bfa3eeef5d9c0fabfa1c41178d71e971"]', '["学生友好", "性价比高", "麻辣鲜香", "快速就餐"]', 3.1, 0, 0, '冒菜西施带着成都火锅味来啦！海淀店离学校不远，人均15元就能吃上热辣冒菜，性价比超高，适合课后来一碗解馋。', '这家店主打成都火锅冒菜和麻辣烫，环境简洁明亮，适合学生党快速解决一餐。服务热情，上菜速度快，特别适合课后或自习后来饱餐一顿。冒菜汤底麻辣鲜香，食材新鲜丰富，推荐搭配米饭吃更过瘾。虽然评分不高，但价格亲民，是校园周边解馋的好去处。', 1, '冒菜套餐');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_162', '叁更眠·新中式茶饮·下午茶', 'restaurant', 'cold_drink', 'place_001', 39.9551574, 116.3518698, '文慧园西路与学院南路交叉口南160米', 473, '¥', 12.0, '', 'uploads/images/surrounding/叁更眠·新中式茶饮·下午茶.jpg', '[]', '["学生友好", "性价比高", "网红打卡", "适合小憩", "文艺风"]', 2.4, 0, 0, '叁更眠新中式茶饮，离校园仅473米，人均12元就能喝到精致下午茶，是课间小憩的绝佳选择。', '这家店主打新中式茶饮和下午茶，环境雅致，充满文艺气息，适合学生党来放松聊天或拍照打卡。茶饮种类丰富，口感清新不腻，价格实惠，特别适合课后或周末约朋友小聚。氛围安静，也适合一个人带本书来消磨时光。虽然评分不高，但性价比突出，是校园周边的隐藏宝藏。', 1, '新中式茶饮');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_163', '祁姥姥家现熬疙瘩汤(西直门店)', 'restaurant', 'cafe', 'place_001', 39.9591628, 116.3392242, '北京城区四道口2号院1号楼2层226号', 1225, '¥', 25.0, '15701084550', 'uploads/images/surrounding/祁姥姥家现熬疙瘩汤(西直门店).jpg', '[]', '["学生友好", "性价比高", "家常味道", "暖心暖胃"]', 2.9, 0, 0, '祁姥姥家现熬疙瘩汤，西直门店离校园1225米，人均25元喝上暖心暖胃的现熬疙瘩汤，适合冬天来一碗。', '这家店以现熬疙瘩汤为特色，环境温馨朴实，服务周到，适合学生党来吃个家常便饭。疙瘩汤口感浓稠，料足味鲜，搭配小菜更完美。价格亲民，人均25元就能吃饱吃好，特别适合课后或周末来暖胃。虽然评分一般，但性价比高，是校园周边寻找家常味道的好地方。', 0, '现熬疙瘩汤');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_164', '一家为你现炒的干锅排骨章么么', 'restaurant', '', 'place_001', 39.9582277, 116.339844, '北京城区四道口路2号京果商厦B座', 1177, '¥¥', 0.0, '13621161882', 'uploads/images/surrounding/一家为你现炒的干锅排骨章么么.jpg', '[]', '["适合聚会", "现炒现做", "麻辣鲜香", "学生友好"]', 2.8, 0, 0, '一家为你现炒的干锅排骨章么么，离校园1177米，现炒干锅香气扑鼻，适合约同学来聚餐。', '这家店主打现炒干锅排骨，环境热闹有烟火气，服务热情周到，适合学生党聚会或解馋。干锅排骨现炒现做，麻辣鲜香，锅底配菜丰富，分量十足。价格适中，适合三五好友一起分享。虽然评分不高，但现炒的锅气很足，是校园周边吃干锅的不错选择。', 0, '干锅排骨');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_165', '荟聚披萨', 'restaurant', 'cafe', 'place_001', 39.9582277, 116.339844, '北京城区四道口路2号京果商厦B座', 1177, '¥¥', 70.0, '13520425299', 'https://store.is.autonavi.com/showpic/8e1013f31e281f151c976ad4f30f0498', '["https://store.is.autonavi.com/showpic/8e1013f31e281f151c976ad4f30f0498"]', '["适合聚会", "西餐体验", "环境舒适", "学生友好"]', 2.7, 0, 0, '荟聚披萨离校园1177米，人均70元吃上正宗披萨，环境舒适，适合周末约朋友来享受西餐。', '这家店主打披萨，环境现代简约，氛围轻松，适合学生党约会或小聚。披萨种类多样，用料扎实，口感丰富，还有意面、沙拉等选择。价格适中，人均70元能吃得不错，是校园周边吃西餐的好去处。虽然评分一般，但适合偶尔改善伙食。', 0, '经典披萨');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_166', '东北卤水豆腐店', 'restaurant', 'restaurant', 'place_001', 39.958883, 116.3396792, '京果商厦A座', 1187, '¥', 0.0, '', 'https://store.is.autonavi.com/showpic/808d1f084d07e52508c627e88afb2c24', '["https://store.is.autonavi.com/showpic/808d1f084d07e52508c627e88afb2c24"]', '["学生友好", "性价比高", "东北风味", "外带方便"]', 2.6, 0, 0, '东北卤水豆腐店，京果商厦A座，离校园1187米，正宗东北卤水豆腐，适合买回去当加餐。', '这家店以东北卤水豆腐为特色，环境简单，主打外带或小吃。豆腐卤味浓郁，口感嫩滑，价格实惠，适合学生党买来当零食或配菜。虽然评分不高，但豆腐新鲜现做，是校园周边寻找地道东北味的好地方。', 0, '卤水豆腐');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_167', '鸡汤焖饭手枪腿饭', 'restaurant', '', 'place_001', 39.9585287, 116.3392951, '四道口路2号京果商厦B座', 1222, '¥', 0.0, '', 'https://store.is.autonavi.com/showpic/475ba0ee80eb707b350546747cc1043c', '["https://store.is.autonavi.com/showpic/475ba0ee80eb707b350546747cc1043c"]', '["学生友好", "性价比高", "快速就餐", "简餐首选"]', 2.6, 0, 0, '鸡汤焖饭手枪腿饭，四道口京果商厦B座，离校园1222米，鸡汤焖饭配手枪腿，人均实惠，适合课后来一份。', '这家店主打鸡汤焖饭和手枪腿饭，环境简洁，出餐快，适合学生党快速解决午饭或晚饭。鸡汤焖饭鲜美入味，手枪腿外酥里嫩，分量足，价格亲民。虽然评分不高，但性价比高，是校园周边吃简餐的好选择。', 1, '手枪腿饭');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_168', '蜜鸡王', 'restaurant', '', 'place_001', 39.9548529, 116.3522152, '文慧园西路与学院南路交叉口南200米', 498, '¥¥', 45.0, '', 'uploads/images/surrounding/蜜鸡王.jpg', '[]', '["学生友好", "适合小聚", "蜜汁口味", "近校园"]', 2.1, 0, 0, '蜜鸡王离校园仅498米，人均45元吃上蜜汁烤鸡，适合课后约同学来解馋。', '这家店主打蜜汁烤鸡，环境温馨，服务热情，适合学生党小聚或外带。烤鸡外皮焦香，肉质嫩滑，蜜汁口味甜而不腻，搭配薯条或沙拉更佳。价格适中，人均45元能吃得满足，是校园周边吃鸡的好去处。虽然评分不高，但离学校近，方便快捷。', 0, '蜜汁烤鸡');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_169', '漫曲餐厅', 'restaurant', 'restaurant', 'place_001', 39.9575275, 116.3405106, '学院南路与交大东路交叉口东北80米', 1131, '¥¥¥', 138.0, '', 'uploads/images/surrounding/漫曲餐厅.jpg', '[]', '["适合约会", "环境浪漫", "高端体验", "庆祝首选"]', 2.5, 0, 0, '漫曲餐厅离校园1131米，人均138元，环境浪漫，适合约会或庆祝，是校园周边的高端选择。', '这家餐厅环境优雅浪漫，氛围感十足，适合学生党来约会或庆祝特殊日子。菜品精致，以西餐和创意菜为主，口感丰富，摆盘讲究。虽然价格较高，但适合偶尔犒劳自己。服务周到，是校园周边提升生活品质的好去处。', 0, '招牌牛排');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_170', '玖酱三叔·脆皮烤鸡(第二档口·卓航美食城店)', 'restaurant', '', 'place_001', 39.9562758, 116.3409418, '交大东路2号院学院里', 1127, '¥¥', 34.0, '', 'https://store.is.autonavi.com/showpic/d3d5a744360115f1a012d9f639e3d59f', '["https://store.is.autonavi.com/showpic/d3d5a744360115f1a012d9f639e3d59f"]', '["学生友好", "性价比高", "脆皮烤鸡", "美食城"]', 2.4, 0, 0, '玖酱三叔·脆皮烤鸡，卓航美食城店，离校园1127米，人均34元吃上脆皮烤鸡，适合课后来一份。', '这家店主打脆皮烤鸡，环境热闹，位于美食城内，选择多样。烤鸡外皮酥脆，肉质鲜嫩多汁，价格实惠，适合学生党快速解决一餐。人均34元就能吃得满足，是校园周边吃烤鸡的好选择。虽然评分不高，但性价比高，值得一试。', 1, '脆皮烤鸡');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_171', '金辉北平食府(金辉国际商务大酒店)', 'restaurant', '', 'place_001', 39.9564517, 116.3438207, '明光桥西金辉商务酒店1楼', 888, '¥¥', 74.0, '010-62253331;010-62275588', 'http://store.is.autonavi.com/showpic/3c793da83071687437dc04684b1995a7', '["http://store.is.autonavi.com/showpic/3c793da83071687437dc04684b1995a7", "http://store.is.autonavi.com/showpic/53acdd41a3106c892e6e8ec8"]', '["适合聚会", "京味菜", "环境雅致", "步行可达"]', 2.2, 0, 0, '金辉北平食府藏身商务酒店一楼，主打地道京味菜，环境雅致。虽然评分不高，但人均74元的价格在校园周边算得上实惠，适合宿舍聚餐或家庭来访时体验老北京风味。', '位于金辉国际商务大酒店一层的北平食府，环境走的是传统中式风格，红木桌椅、宫灯装饰，颇有几分老北京的韵味。服务中规中矩，胜在空间宽敞，包间适合多人聚会。菜品以京鲁菜为主，烤鸭、炸酱面等经典款都有，味道虽不算惊艳但胜在稳定。距离校园不到900米，步行可达，适合不想跑太远又想换个正经餐厅氛围的同学。不过评分偏低，建议降低期待值，当作日常改善伙食的去处即可。', 0, '推荐烤鸭');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_172', '禾膳记(京果商厦店)', 'restaurant', 'restaurant', 'place_001', 39.9589511, 116.3396293, '大钟寺四道口路2号京果商厦乐食美食城', 1191, '¥¥', 0.0, '', 'uploads/images/surrounding/禾膳记(京果商厦店).jpg', '[]', '["学生友好", "美食城", "快速简餐", "性价比高"]', 2.4, 0, 0, '禾膳记藏在京果商厦美食城里，是解决快速午餐的好去处。人均未知但美食城价格通常亲民，适合课间或自习后溜达过来填饱肚子，选择自由度高。', '禾膳记位于京果商厦乐食美食城内，属于典型的美食城档口模式。环境就是热闹的美食城氛围，座位共享，高峰期需拼桌。主打简餐快餐，菜品种类丰富，从盖饭到面条都有，适合一个人快速解决一餐。距离校园1.2公里，步行约15分钟，骑车更便捷。美食城的好处是各取所需，如果同行朋友口味不同，可以各点各的。评分不高，但作为填饱肚子的选择，性价比可能不错。', 0, NULL);
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_173', '6块6家常菜·小份菜(大钟寺店)', 'restaurant', 'cafe', 'place_001', 39.9585275, 116.3399437, '四道口路2号京果商厦B座', 1166, '¥', 0.0, '', 'uploads/images/surrounding/6块6家常菜·小份菜(大钟寺店).jpg', '[]', '["学生友好", "小份菜", "性价比高", "适合一人食"]', 2.2, 0, 0, '6块6家常菜主打小份菜和极致低价，名字就透露出对学生党的友好。人均零元标注可能不准，但小份菜模式让你花少钱尝多样，适合想省钱又想吃好的日子。', '这家店的名字就是最大的招牌——6块6家常菜，主打小份菜模式，让你用实惠的价格尝到多种家常味道。位于京果商厦B座，环境是快餐店风格，干净简洁。小份菜的好处是可以多点几样，不浪费又能满足吃货心。距离校园1.2公里，骑车10分钟可达。评分2.2虽然不高，但考虑到价格和定位，作为日常食堂还是值得一试。适合独自用餐或两三个同学拼桌，人均可能比标注更低。', 1, '推荐小炒肉');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_174', '颠柠手作茶(四道口店)', 'restaurant', 'bar', 'place_001', 39.9584631, 116.3396324, '北京城区四道口2号1号楼一层76号房间', 1193, '¥¥', 0.0, '', 'https://store.is.autonavi.com/showpic/5aacffee8b10c1023a305a91f303e3b4', '["https://store.is.autonavi.com/showpic/5aacffee8b10c1023a305a91f303e3b4"]', '["学生友好", "手作茶饮", "网红打卡", "解暑必备"]', 2.1, 0, 0, '颠柠手作茶主打手作柠檬茶，名字就透着个性。位于四道口，距离校园1.2公里，适合下课路上顺带一杯。手作茶饮通常用料新鲜，是解暑或提神的好选择。', '颠柠手作茶是一家主打手作柠檬茶的饮品店，名字里的“颠”字透出几分不羁和个性。店面不大，但手作茶饮的制作过程看得见，新鲜柠檬现切现捣，茶底现泡，口感清爽。距离校园1.2公里，步行或骑车都能到，适合下午课后来一杯解乏。手作茶饮的价格通常比连锁店略高，但用料扎实，值得一试。评分2.1可能反映了刚开业或小众定位，但喜欢柠檬茶的同学不妨去探个店。', 1, '推荐招牌柠檬茶');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_175', 'CROWFFEE 一只乌鸦', 'restaurant', 'snack', 'place_001', 39.9575069, 116.355428, '新街口外大街19号北京师范大学兰蕙公寓二楼', 244, '¥¥', 0.0, '', 'http://store.is.autonavi.com/showpic/8655a3a3969ecee6c728928da9fe6535', '["http://store.is.autonavi.com/showpic/8655a3a3969ecee6c728928da9fe6535"]', '["文艺", "小众咖啡馆", "适合自习", "步行可达"]', 1.0, 0, 0, 'CROWFFEE一只乌鸦藏在北师大兰蕙公寓二楼，是一家小众咖啡馆。距离校园仅244米，是自习或小憩的绝佳去处。评分虽低，但咖啡爱好者可来探索独特氛围。', 'CROWFFEE一只乌鸦，名字就透着文艺和神秘感。它藏在北师大兰蕙公寓二楼，距离你的校园仅244米，步行3分钟即到，是校园周边的隐藏宝藏。环境走的是工业风加复古混搭，适合一个人带电脑来学习，或和朋友小声聊天。主打手冲咖啡和创意饮品，咖啡豆选品有讲究。评分1.0可能源于小众定位或服务争议，但如果你喜欢探索独立咖啡馆，这里值得一探。距离近是最大优势，课间溜达过来点杯拿铁，偷得浮生半日闲。', 0, '推荐手冲咖啡');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_176', '北京邮电大学学苑风味餐厅', 'restaurant', '', 'place_001', 39.9623415, 116.3523001, '西土城路10号', 366, '¥', 17.0, '13520432076', 'http://store.is.autonavi.com/showpic/700ee01100e8847142b08659ea3a0112', '["http://store.is.autonavi.com/showpic/700ee01100e8847142b08659ea3a0112", "http://store.is.autonavi.com/showpic/6d2750ed7235aed36054175e45d95a5a"]', '["食堂", "性价比高", "学生友好", "步行可达"]', 0.7, 0, 0, '北邮学苑风味餐厅是校园食堂级别的存在，人均仅17元，性价比无敌。距离366米，是解决早餐或夜宵的便捷之选，味道虽朴实但胜在实惠。', '北京邮电大学学苑风味餐厅，其实是北邮的校内食堂，但对外开放。距离你校园366米，步行5分钟即到，是蹭饭的好地方。环境就是标准大学食堂，干净整洁，高峰期人多需排队。菜品种类丰富，从打菜窗口到面食窗口都有，味道家常，胜在价格亲民——人均17元，在校园周边几乎找不到更便宜的选择。评分0.7可能来自偶尔的菜品不稳定，但作为日常填饱肚子的去处，性价比无敌。适合一个人快速解决一餐，或和同学来体验校园食堂氛围。', 1, '推荐红烧肉');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_177', '叫了个炸鸡(京果商厦店)', 'restaurant', '', 'place_001', 39.9584275, 116.3399437, '四道口路2号京果商厦B座', 1167, '¥', 0.0, '', 'uploads/images/surrounding/叫了个炸鸡(京果商厦店).jpg', '[]', '["学生友好", "外卖", "夜宵", "炸鸡", "性价比高"]', 0.7, 0, 0, '叫了个炸鸡是经典的外卖炸鸡品牌，京果商厦店离校园1.2公里。炸鸡外酥里嫩，价格亲民，是熬夜追剧或宿舍夜宵的快乐源泉，评分低但味道不差。', '叫了个炸鸡是连锁炸鸡品牌，主打外卖和外带，京果商厦店距离校园1.2公里，骑车10分钟可到。店面不大，但出餐快，适合手机下单后溜达过去取。炸鸡是经典韩式做法，外皮酥脆，内里多汁，有原味、甜辣等多种口味可选。价格亲民，一份炸鸡配饮料人均不到30元，是宿舍夜宵或聚会小食的好选择。评分0.7可能源于个别差评，但作为快餐炸鸡，味道和性价比在校园周边算是不错的。', 1, '推荐甜辣炸鸡');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_178', '优溢源冻酸奶', 'restaurant', 'cold_drink', 'place_001', 39.9565986, 116.3427669, '学院南路50号哇沃生活广场F1层', 968, '¥', 27.0, '', 'http://store.is.autonavi.com/showpic/944231cc889b0fa754a1fcf73e3f59f5', '["http://store.is.autonavi.com/showpic/944231cc889b0fa754a1fcf73e3f59f5", "http://store.is.autonavi.com/showpic/a89d6828802a68eda14a638b447f97e7", "http://store.is.autonavi.com/showpic/c93df2303e54fc6c0f6343433e4213a8"]', '["学生友好", "健康甜品", "夏日解暑", "低脂"]', 0.4, 0, 0, '优溢源冻酸奶主打健康低脂的冻酸奶，位于哇沃生活广场，距离校园968米。人均27元，是夏日解暑或健身后的清爽选择，口感像冰淇淋但更健康。', '优溢源冻酸奶是一家主打冻酸奶的小店，位于学院南路哇沃生活广场一楼，距离校园968米，步行约12分钟。环境清新简约，适合逛街累了歇脚。冻酸奶口感绵密，类似冰淇淋但更低脂健康，可以搭配新鲜水果、坚果等配料，DIY属于自己的口味。人均27元，在甜品里算适中。评分0.4可能因为刚开业或小众，但冻酸奶本身是夏日解暑的好选择，尤其适合健身后的同学，既满足口腹之欲又无负担。', 1, '推荐水果冻酸奶');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_179', '箐筳荷叶烤鸡(京果商厦A座店)', 'restaurant', 'restaurant', 'place_001', 39.9589021, 116.3396313, '京果商厦A座', 1191, '¥¥', 37.0, '17551053530;18310815031', 'uploads/images/surrounding/箐筳荷叶烤鸡(京果商厦A座店).jpg', '[]', '["学生友好", "特色烤鸡", "荷叶清香", "适合分享"]', 0.3, 0, 0, '箐筳荷叶烤鸡主打荷叶包裹烤制的鸡肉，清香四溢。位于京果商厦A座，距离校园1.2公里，人均37元，是换口味尝鲜的好去处，适合宿舍聚餐。', '箐筳荷叶烤鸡以荷叶包裹烤鸡为特色，鸡肉在烤制过程中吸收了荷叶的清香，外皮金黄，内里鲜嫩多汁。位于京果商厦A座，距离校园1.2公里，骑车10分钟可达。环境是快餐简餐风格，干净利落。除了招牌荷叶烤鸡，还有配菜和主食可选，人均37元，性价比不错。评分0.3可能源于个别体验不佳，但如果你喜欢尝试新口味，荷叶烤鸡值得一吃。适合两三个同学一起，点一只烤鸡分享，配上米饭就是满足的一餐。', 0, '推荐荷叶烤鸡');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_180', '手撕脆皮烤鸭', 'restaurant', 'restaurant', 'place_001', 39.9590784, 116.3394447, '交大东路与学院南路交叉口北240米', 1207, '¥', 24.0, '', 'uploads/images/surrounding/手撕脆皮烤鸭.jpg', '[]', '["学生友好", "烤鸭", "外带", "性价比高", "适合一人食"]', 0.3, 0, 0, '手撕脆皮烤鸭主打现烤现撕的脆皮烤鸭，位于交大东路附近，距离校园1.2公里。人均24元，价格实惠，是解馋或加餐的平民选择，适合打包带回宿舍。', '手撕脆皮烤鸭是一家主打烤鸭外带的小店，位于交大东路与学院南路交叉口北240米，距离校园1.2公里，骑车12分钟可达。店面不大，但烤鸭是现烤现撕，外皮酥脆，肉质鲜嫩，配上酱料和面饼，就是一份满足的简餐。人均24元，在烤鸭里算是非常实惠的价格，适合一个人解馋或两个人分享。评分0.3可能来自店面环境或服务，但如果你想吃烤鸭又不想去大餐厅，这里是不错的选择。打包带回宿舍，配剧吃更香。', 0, '推荐脆皮烤鸭');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_181', 'MG HAIR SALON(北师大店)', 'shopping', '', 'place_001', 39.9578536, 116.3549428, '匠心荟MG染烫师大店直营店', 188, '¥¥¥', 170.0, '13001289686', 'https://store.is.autonavi.com/showpic/dab7bf2260320c1784854a3ba2f6a88e', '["https://store.is.autonavi.com/showpic/dab7bf2260320c1784854a3ba2f6a88e", "https://store.is.autonavi.com/showpic/c845d95fc41e19697e80c89f419de83d", "http://store.is.autonavi.com/showpic/0c63c8d76ee03b99a68006882fdb5c91"]', '["专业染烫", "学生友好", "预约制", "环境干净", "技术好"]', 4.4, 0, 0, '北师大旁的专业美发沙龙，染烫技术口碑超赞，适合学生党换个新造型，价格小贵但值！', 'MG HAIR SALON就在北师大旁边，步行两分钟就到，主打染烫造型，匠心荟直营店品质有保障。店内环境干净明亮，理发师技术专业，尤其适合想要换个发色或者尝试新造型的同学。人均170元虽不便宜，但效果持久，性价比在学生圈里评价很高。建议提前预约，周末人多。', 0, '推荐染烫套餐');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_182', '枫蓝国际购物中心', 'shopping', '', 'place_001', 39.9515929, 116.3504031, '西直门北大街32号院', 889, '¥¥', 0.0, '010-62219999', 'http://store.is.autonavi.com/showpic/2d0482c1f2cc4c8acaf856e295f3c6fb', '["http://store.is.autonavi.com/showpic/2d0482c1f2cc4c8acaf856e295f3c6fb", "https://store.is.autonavi.com/showpic/47ad5a6a2a1d4da70000000785290920?type=pic", "https://aos-comment.amap.com/B000A84154/comment/file_media_Photo_4033_IMG_1768458633_4367_IMG_4367_jp_1768459132673_86322834.jpg"]', '["综合商场", "学生友好", "周末好去处", "吃喝玩乐", "交通便利"]', 4.8, 0, 0, '北师大周边最大购物中心，吃喝玩乐一站搞定，周末闲逛首选！', '枫蓝国际购物中心是北师大附近最热闹的综合商场，评分高达4.8，距离校园步行10分钟左右。这里集齐了潮流服饰、美食餐厅、电影院和娱乐设施，适合同学聚会、约会或者单纯逛街放松。负一层有超市和各类小吃，楼上还有电影院和KTV，周末经常有活动，是校园生活的绝佳去处。', 1, NULL);
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_183', '物美超市(明光桥西店)', 'shopping', 'electronics', 'place_001', 39.9572863, 116.3463913, '学院南路15号院9号楼学院派B1层', 650, '¥', 0.0, '010-56670601;18730878903', 'https://store.is.autonavi.com/showpic/4c8d95473c21132ddbc4c26a32add771', '["https://store.is.autonavi.com/showpic/4c8d95473c21132ddbc4c26a32add771", "https://store.is.autonavi.com/showpic/22d265e42d7a757934ee799b5065e3d7", "http://store.is.autonavi.com/showpic/ffad578adec0693e849ad4369796b377"]', '["生活超市", "学生友好", "性价比高", "囤货首选", "交通方便"]', 4.6, 0, 0, '明光桥旁的物美超市，生活用品和零食一应俱全，学生囤货首选！', '物美超市(明光桥西店)位于学院派B1层，距离北师大步行约8分钟，是同学们采购日用品和零食的宝藏地。超市面积大，商品种类丰富，从零食饮料到文具日化应有尽有，价格亲民，经常有学生折扣活动。适合周末来囤货，或者考试前买点提神零食。', 1, NULL);
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_184', '悦刻电子烟(哇沃生活广场店)', 'shopping', '', 'place_001', 39.9560864, 116.3428957, '学院南路50号哇沃生活广场F2层', 976, '¥¥', 0.0, '13167570909;18519133212', 'https://aos-comment.amap.com/B0FFLPE8PQ/comment/content_media_external_images_media_85779_1656303244271_35d8b158.jpg', '["https://aos-comment.amap.com/B0FFLPE8PQ/comment/content_media_external_images_media_85779_1656303244271_35d8b158.jpg", "https://aos-comment.amap.com/B0FFLPE8PQ/comment/content_media_external_images_media_85767_1656302820332_31abb5fd.jpg", "https://aos-comment.amap.com/B0FFLPE8PQ/comment/efc5cf014215d79d81efa35ca64ffaf3_2048_2048_80.jpg"]', '["电子烟集合", "品牌齐全", "服务专业", "学生友好", "位置便利"]', 4.8, 0, 0, '哇沃生活广场里的电子烟集合店，品牌齐全，适合老烟民尝鲜或囤货。', '悦刻电子烟(哇沃生活广场店)位于学院南路哇沃生活广场二层，评分高达4.8，是电子烟爱好者的聚集地。店内陈列了悦刻全系列产品及各种口味烟弹，店员专业热情，能帮你推荐最适合的款式。距离北师大步行约10分钟，适合课余时间来逛逛，但请同学们理性消费，注意健康。', 0, NULL);
