INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_221', '屈臣氏(枫蓝国际购物中心店)', 'shopping', '', 'place_001', 39.9514958, 116.3504699, '西直门外北大街32号枫蓝国际2层', 897, '¥¥', 0.0, '010-82211722', 'https://aos-comment.amap.com/B0FFJD0YT1/comment/2677A0BB_A8AE_4488_8441_E028FA701C0A_L0_001_1500_2000_1731402830859_95707323.jpg', '["https://aos-comment.amap.com/B0FFJD0YT1/comment/2677A0BB_A8AE_4488_8441_E028FA701C0A_L0_001_1500_2000_1731402830859_95707323.jpg", "https://aos-comment.amap.com/B0FFJD0YT1/comment/20260322-7bc45eb418f955cf0ccc6694-6jmH88RQv3P7E0OXqtHsWX.jpg", "https://store.is.autonavi.com/showpic/34ff836c234bb51a0000001350870346?type=pic"]', '["学生友好", "品类齐全", "购物便利", "适合囤货", "性价比高"]', 4.3, 0, 0, '枫蓝国际里的屈臣氏，是学生党日常囤货的宝地！从护肤美妆到生活用品一站式购齐，品类超齐全，还能淘到不少惊喜好物。', '这家屈臣氏位于枫蓝国际购物中心二层，店内宽敞明亮，货架排列整齐，逛起来非常舒适。作为校园周边的首选日化连锁，这里涵盖了从基础护肤、彩妆、个人护理到零食饮料、家居小物等各类商品，非常适合课余时间来补货。店内经常有会员特价和买赠活动，而且支持自助结账，快速又方便。无论是买一瓶急救面膜、换季护肤品，还是顺手带一包糖果，这里都能满足你的日常小需求。', 0, NULL);
