INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_251', '崇前造型(北邮总店)', 'service', '', 'place_001', 39.9582171, 116.3501537, '北京邮电大学西土城路10号院6号楼底商(南门校医院西20米)', 313, '¥¥', 89.0, '18611102949', 'https://store.is.autonavi.com/showpic/a2537575ef2277016c945214fdd0c92f', '["https://store.is.autonavi.com/showpic/a2537575ef2277016c945214fdd0c92f", "https://store.is.autonavi.com/showpic/c440dfa9e043666d673decf1514dc6ef"]', '["学生友好", "技术稳定", "价格亲民", "校园周边", "无需预约"]', 4.1, 0, 0, '北邮南门旁的宝藏理发店，学生党常去的老店，技术稳定且价格亲民，剪发染烫都能搞定，下课顺路就能换个新造型。', '崇前造型北邮总店紧邻学校南门，是许多北邮学子从大一剪到毕业的固定据点。店内环境简洁明亮，理发师经验丰富，尤其擅长根据学生脸型推荐发型。洗剪吹价格合理，还有学生专属优惠活动。适合考前清爽短发、毕业季形象改造或日常修剪，不用预约也能快速服务。', 1, '学生剪发套餐');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_252', '我爱我家(华北北楼店)', 'service', '', 'place_001', 39.9563906, 116.3549979, '学院南路32号院甲5号楼底商', 334, '¥¥', 0.0, '', 'https://store.is.autonavi.com/showpic/a4fd450c810e4ffaec44758d3d56ff97', '["https://store.is.autonavi.com/showpic/a4fd450c810e4ffaec44758d3d56ff97", "https://store.is.autonavi.com/showpic/4a70422f6a45cd2b4970b474175733c8", "https://store.is.autonavi.com/showpic/c1e9aff650f75cb50000002478620743?type=pic"]', '["租房服务", "专业咨询", "房源丰富", "学生友好", "交通便利"]', 4.1, 0, 0, '学院南路的中介门店，为北邮学子提供租房、买卖咨询，房源信息全，服务专业，是校外找房的第一站。', '我爱我家华北北楼店位于学院南路，是学生校外租房的重要帮手。店内经纪人对周边小区如明光村、蓟门里非常熟悉，能快速匹配预算和需求。服务流程透明，提供免费咨询和带看，适合考研党、实习族或合租小团体。虽然人均为0，但租房签约后有合理佣金。', 0, NULL);
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_253', '中国邮政北京邮电大学邮政所', 'service', '', 'place_001', 39.9585991, 116.3513384, '西土城路10号北京邮电大学', 204, '¥', 0.0, '', 'http://store.is.autonavi.com/showpic/5e591ef55261939284f29064b278ed67', '["http://store.is.autonavi.com/showpic/5e591ef55261939284f29064b278ed67", "http://store.is.autonavi.com/showpic/ec7750a3e83a3ff16ad313eed5cd3c70", "https://store.is.autonavi.com/showpic/84d12bb4c6c65d99409bcb56c5375039"]', '["校园内部", "邮政服务", "便捷高效", "寄取快递", "学生常用"]', 4.0, 0, 0, '北邮校园内的邮政所，寄收快递、寄信、办理邮政业务超方便，是学生和教职工的日常后勤站。', '中国邮政北京邮电大学邮政所就在校园里，下课就能来寄快递、取挂号信或办理邮政储蓄。窗口服务效率高，提供标准邮政服务，还支持EMS和包裹寄送。对于需要寄送文件、书籍或家乡特产的同学来说，这里是校内最可靠的邮政点。', 0, NULL);
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_254', '视觉造型明光桥物美店', 'service', '', 'place_001', 39.9573025, 116.3463045, '明光桥西物美超市二楼', 657, '¥¥¥', 213.0, '010-59431296', 'https://store.is.autonavi.com/showpic/f1cb1d7de4c504667df5d849d8cec527', '["https://store.is.autonavi.com/showpic/f1cb1d7de4c504667df5d849d8cec527", "https://store.is.autonavi.com/showpic/c48477b55f81fa2b83beb03625c57216", "https://store.is.autonavi.com/showpic/30b92281291aee5302da0402cc40f9a8"]', '["专业造型", "技术精湛", "环境时尚", "适合重要场合", "价格较高"]', 4.3, 0, 0, '明光桥物美超市二楼的综合美发店，技术精湛但价格较高，适合想换个精致发型或做特殊造型的师生。', '视觉造型位于物美超市二楼，环境时尚舒适，理发师团队经验丰富，擅长剪染烫和造型设计。虽然人均213元偏高，但服务细致，从洗头到造型都很专业，还能根据脸型和气质定制方案。适合毕业季、面试或重要活动前的形象升级。', 0, '定制染烫服务');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_255', '浩峰美容美发(北京一今典花园店)', 'service', '', 'place_001', 39.9533839, 116.3555163, '北太平庄街道文慧园北路8号庆亚大厦1楼', 667, '¥¥', 56.0, '010-82418859', 'https://store.is.autonavi.com/showpic/4c0b0e2b2f7ae6773e3051fc4f9fdcb5', '["https://store.is.autonavi.com/showpic/4c0b0e2b2f7ae6773e3051fc4f9fdcb5", "https://store.is.autonavi.com/showpic/e280a065015cfdd44fc8c9c0744f3fd5", "https://store.is.autonavi.com/showpic/e1dbdfaee8c752830000002442588149?type=pic"]', '["性价比高", "学生友好", "基础美发", "不推销", "平价实惠"]', 4.3, 0, 0, '文慧园北路的平价美发店，人均56元就能享受靠谱剪发和基础染烫，是学生党日常打理的好选择。', '浩峰美容美发今典花园店位于庆亚大厦一楼，价格亲民且服务周到。理发师手法利落，剪发、吹造型、基础染烫都能快速搞定。店内不推销办卡，适合学生课后简单修整或换个清爽发型。离北邮稍远但性价比极高，值得一跑。', 1, '基础剪发');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_256', '中瑞诚会计师事务所', 'service', '', 'place_001', 39.9523529, 116.3497582, '北太平庄街道西直门北大街32号枫蓝国际中心写字楼A座1楼', 829, '¥¥¥', 0.0, '010-66553366;13366553366', 'uploads/images/surrounding/中瑞诚会计师事务所.jpg', '[]', '["专业服务", "财务咨询", "企业服务", "实习机会", "创业支持"]', 4.4, 0, 0, '枫蓝国际中心的专业会计师事务所，为个人和企业提供财务、税务咨询，北邮学生实习或创业可求助。', '中瑞诚会计师事务所位于枫蓝国际中心写字楼，环境专业严谨。主要面向企业客户，但也提供个人税务咨询、审计等服务。对于北邮创业团队或需要财务规划的学生来说，这里能提供靠谱的财税建议。人均为0，具体服务按项目收费。', 0, NULL);
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_257', '北京邮电大学快递邮驿站', 'service', 'laundry', 'place_001', 39.9635663, 116.3511002, '西土城路10号北京邮电大学北门易邮柜', 530, '¥', 0.0, '', 'https://aos-comment.amap.com/B0FFIVNRNE/comment/a0fd5c2891a0ba46219d2c54f1ede393_2048_2048_80.jpg', '["https://aos-comment.amap.com/B0FFIVNRNE/comment/a0fd5c2891a0ba46219d2c54f1ede393_2048_2048_80.jpg", "https://store.is.autonavi.com/showpic/901653e84216afe7a5d577f98dca8bb7", "https://store.is.autonavi.com/showpic/7bd665f0fb031a752f0f985b8b17dac6"]', '["快递驿站", "24小时", "校园内部", "取件方便", "寄件服务"]', 4.2, 0, 0, '北邮北门的快递驿站，取件寄件一站式搞定，易邮柜24小时开放，下课顺路就能拿包裹。', '北京邮电大学快递邮驿站位于北门附近，是校园内最大的快递集散点。易邮柜全天候开放，快递到站后凭码取件，超方便。驿站还提供寄件服务，价格透明。适合网购频繁的同学们，尤其是双十一或毕业季寄行李时，这里能省不少事。', 0, NULL);
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_258', '金丽都影印中心(中商信大厦店)', 'service', '', 'place_001', 39.956407, 116.3508416, '学院南路34号金丽都', 390, '¥', 37.0, '010-62270397', 'https://store.is.autonavi.com/showpic/454479e99567fab50000002702638236?type=pic', '["https://store.is.autonavi.com/showpic/454479e99567fab50000002702638236?type=pic", "https://store.is.autonavi.com/showpic/4653cdd3174d16c1d0d7878fb8e8f022", "https://store.is.autonavi.com/showpic/aa21ce0fa84db17c4c39da38c1beebd1"]', '["打印复印", "学生必备", "期末季", "价格实惠", "快速服务"]', 4.1, 0, 0, '学院南路的影印中心，打印复印、文件装订、海报制作一条龙，期末季和活动前常爆满。', '金丽都影印中心位于学院南路，是北邮学生打印复习资料、论文和社团材料的老店。设备新、速度快，支持黑白彩色打印、扫描、装订和大幅面海报。价格实惠，37元人均就能搞定大量文件。期末周和毕业季尤其繁忙，建议错峰前往。', 1, '论文装订服务');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_259', '小象馆(枫蓝店)', 'service', '', 'place_001', 39.9521998, 116.3498411, '西直门北大街32号院枫蓝国际中心A座F1层', 842, '¥¥¥', 307.0, '', 'http://store.is.autonavi.com/showpic/ed3680a6e1805f8be4c81b69f77d35dd', '["http://store.is.autonavi.com/showpic/ed3680a6e1805f8be4c81b69f77d35dd", "http://store.is.autonavi.com/showpic/4d8aad4d437327211551aaf4f992d807", "http://store.is.autonavi.com/showpic/0c75224dd58340f80a9702c5ffdab3a8"]', '["证件照", "形象照", "专业摄影", "求职必备", "毕业纪念"]', 4.4, 0, 0, '枫蓝国际的证件照和形象照专业店，出片质量高，适合求职、签证或毕业照，人均虽高但效果惊艳。', '小象馆枫蓝店以精致证件照和形象照闻名，环境温馨，化妆和摄影团队专业。提供从服装搭配到精修成片的全套服务，适合拍简历照、签证照或毕业纪念照。人均307元虽贵，但成品自然高级，很多北邮学生为求职或重要场合专程来拍。', 0, '简历证件照');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_260', '藤野造型(四道口学院里店)', 'service', '', 'place_001', 39.9562011, 116.3407912, '交大东路2号院8幢-1层B103负一楼', 1142, '¥¥¥', 189.0, '', 'https://aos-comment.amap.com/B0KGPR5EBG/comment/6c37e7de245237aaf00216665c093051_2048_2048_80.jpg', '["https://aos-comment.amap.com/B0KGPR5EBG/comment/6c37e7de245237aaf00216665c093051_2048_2048_80.jpg", "https://aos-comment.amap.com/B0KGPR5EBG/comment/637896b2c10f8c5cbd21ad2c52a61b51_2048_2048_80.jpg", "https://aos-comment.amap.com/B0KGPR5EBG/comment/6CFC05AE_5B13_4954_AB94_A77D4C5E2CFB_L0_001_1079_131_1772514485453_51211775.jpg"]', '["网红美发", "评分高", "时尚造型", "技术好", "适合换风格"]', 4.6, 0, 0, '交大东路的网红美发店，评分高达4.6，技术好且服务贴心，适合追求时尚造型的北邮学子。', '藤野造型四道口学院里店位于负一层，环境潮酷，理发师团队年轻有创意，擅长日系和韩系发型。从剪发到烫染都技术在线，服务细致，还会提供造型建议。虽然人均189元偏高，但效果惊艳，适合换风格或重要场合前做造型。', 0, '日系剪发');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_261', '今爱美甲美睫(财经大学物美超市店)', 'service', '', 'place_001', 39.9584165, 116.3399347, '北京城区四道口路2号京果商厦B座物美超市1楼扶梯口今爱美甲', 1168, '¥¥¥', 162.0, '15010696393;18701090393', 'https://store.is.autonavi.com/showpic/be5e8ba9d1076754acaacd5223c23b7e', '["https://store.is.autonavi.com/showpic/be5e8ba9d1076754acaacd5223c23b7e", "http://store.is.autonavi.com/showpic/5c270f30cb471647700f7a8b38fbae61", "http://store.is.autonavi.com/showpic/4c98cbd5f3dc85a2c795e521f8f9b063"]', '["女生友好", "手艺精湛", "环境温馨", "适合约会", "品质消费"]', 4.6, 0, 0, '藏在物美超市里的美甲美睫宝藏店！评分4.6，价格小贵但手艺超赞，是附近女生们悄悄变美的秘密基地。', '这家店位于物美超市一楼的扶梯口，位置显眼，路过就能被吸引。店内环境整洁温馨，美甲师技术娴熟，无论是简约风还是复杂手绘都能轻松驾驭。虽然人均162元不算便宜，但做出来的效果持久且精致，特别适合面试、约会或重要场合前提升自信。服务贴心，会耐心沟通款式，性价比体现在品质上。', 0, '推荐简约法式美甲');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_262', '明光村邮政所', 'service', 'barber', 'place_001', 39.9539908, 116.3485474, '西直门北大街甲11号', 722, '¥', 0.0, '010-62011840;010-62259862;11185', 'http://store.is.autonavi.com/showpic/169b21044bb7d4631f7eee5440e4816a', '["http://store.is.autonavi.com/showpic/169b21044bb7d4631f7eee5440e4816a", "https://store.is.autonavi.com/showpic/7817c18e1e0c18f261989973754edfbe", "http://store.is.autonavi.com/showpic/724b763bbda32f6cd5fdff920c879cbc"]', '["便民服务", "实用主义", "办事快捷", "生活必备"]', 4.3, 0, 0, '校园旁的便民邮政所，寄包裹、取快递都超方便，虽然评分中规中矩，但胜在距离近、办事快。', '位于西直门北大街的明光村邮政所，是周边学生办理邮政业务的便捷之选。这里没有花哨的装饰，但功能齐全，可以寄信、寄包裹、领取挂号信和快递。工作人员态度务实，效率较高，对于需要邮寄资料或网购退换货的同学来说，是个省时省力的地方。虽然评分4.3不算惊艳，但日常使用完全足够。', 0, NULL);
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_263', '上海制衣′裁缝店服装修改', 'service', '', 'place_001', 39.9568646, 116.3523686, '北太平庄街道西土城路10号北京邮电大学海淀校区南家属区10号院11号楼2楼2号', 280, '¥', 0.0, '13718959597', 'https://aos-comment.amap.com/B0KGLZO06K/comment/IMG_20241006_114146_tem_1728186166005_79734388.jpg', '["https://aos-comment.amap.com/B0KGLZO06K/comment/IMG_20241006_114146_tem_1728186166005_79734388.jpg", "https://aos-comment.amap.com/B0KGLZO06K/comment/IMG_20241006_114220_tem_1728186166006_30748418.jpg", "https://store.is.autonavi.com/showpic/d32f575cfc96dba5e31dcb5fd10fc349"]', '["手工精细", "价格实惠", "学生友好", "生活便利"]', 4.0, 0, 0, '藏在北邮家属区里的裁缝店，改裤脚、修拉链、改尺寸样样在行，是解决衣物小烦恼的贴心小铺。', '这家裁缝店位于北邮家属区深处，虽然不太好找，但口碑很好。店主手艺娴熟，无论是改裤长、收腰身还是修补破洞，都能做得精细。店内还有少量布料和辅料可供选择。特别适合学生党，价格公道，改一条裤子十几二十元，性价比超高。如果你有不合身的衣物，不妨来这里试试。', 1, '推荐改裤脚服务');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_264', '北京邮电大学海淀校区体育馆', 'entertainment', '', 'place_001', 39.9606409, 116.3533623, '西土城路10号北京邮电大学东门(近北京师范大学)', 161, '¥¥', 34.0, '010-62281325;010-62282049', 'http://store.is.autonavi.com/showpic/96ae717576cad2b5d6fd5a1e15d7a7e2', '["http://store.is.autonavi.com/showpic/96ae717576cad2b5d6fd5a1e15d7a7e2", "http://store.is.autonavi.com/showpic/b7907ab3e1d551494c775844436af23d", "http://store.is.autonavi.com/showpic/aefdac8c2cfe91fb7c89574394d1dc85"]', '["校内设施", "运动健身", "性价比高", "适合团队", "学生友好"]', 4.5, 0, 0, '北邮校内的综合体育馆，设施齐全，羽毛球、篮球、游泳应有尽有，是同学们挥洒汗水的好去处。', '作为北邮校园内的核心运动场馆，这里集篮球馆、羽毛球馆、游泳馆和健身房于一体。场地宽敞明亮，地面防滑，通风良好。学生凭校园卡可享受优惠价格，性价比极高。无论是体育课、社团活动还是课余锻炼，这里都是首选。周末经常有校内比赛，氛围热烈。', 1, '推荐羽毛球场地');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_265', '飞狐24h健身(北师大店)', 'entertainment', '', 'place_001', 39.9578807, 116.3548949, '北京邮电大学海淀校区东门南450米', 184, '¥¥¥', 61.0, '15210833959', 'https://store.is.autonavi.com/showpic/135b72de0fada2f60000002655720330?type=pic', '["https://store.is.autonavi.com/showpic/135b72de0fada2f60000002655720330?type=pic", "https://store.is.autonavi.com/showpic/c8666e9f9ba836430000002655646703?type=pic", "https://store.is.autonavi.com/showpic/8ddf52deb774a8de0000002669794191?type=pic"]', '["24小时营业", "设备齐全", "适合健身", "夜猫友好", "学生友好"]', 4.5, 0, 0, '24小时营业的健身馆，设备新、空间大，适合无论白天黑夜都想动一动的你。', '飞狐健身离北邮东门很近，步行几分钟即到。最吸引人的是24小时营业，对于课业繁忙或喜欢夜间锻炼的同学非常友好。馆内器械齐全，有氧区、力量区、自由重量区划分清晰，还有团课教室。环境干净，通风不错。虽然人均61元不算特别便宜，但办卡后性价比尚可。', 1, '推荐力量训练区');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_266', '清鑫泉茶艺', 'entertainment', '', 'place_001', 39.9564243, 116.3545028, '北京城区学院南路32号院甲5号楼', 318, '¥¥¥', 65.0, '010-62276623;13041297159', 'https://store.is.autonavi.com/showpic/12c88446e6de8b892b1b577f5c56889f', '["https://store.is.autonavi.com/showpic/12c88446e6de8b892b1b577f5c56889f", "https://aos-comment.amap.com/B0FFH7BVAQ/comment/content_media_external_file_3359_1750157130557_58557283.jpg", "https://store.is.autonavi.com/showpic/94a984cf1ee9d1ab52783449aa0866e4"]', '["环境优雅", "适合自习", "文化体验", "朋友聚会", "安静舒适"]', 4.5, 0, 0, '学院南路的一家清雅茶艺馆，环境静谧，适合自习、聊天或小组讨论，是校园外的宁静一隅。', '清鑫泉茶艺藏在一片居民区中，闹中取静。店内布置古色古香，有包间和大厅座位，茶香袅袅。这里不仅提供各种茶叶（如龙井、铁观音、普洱），还有精致的茶点。适合一个人静心看书，或与三五好友品茶谈心。价格适中，人均65元，可以坐一下午，比咖啡馆更有文化氛围。', 0, '推荐铁观音茶');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_267', '北京邮电大学海淀校区体育场', 'entertainment', 'cinema', 'place_001', 39.9592809, 116.3540253, '西土城路10号北京邮电大学', 37, '¥', 30.0, '', 'https://aos-comment.amap.com/B0FFHQM58M/comment/20260307-27386ba591c96897a8b3f1ce-8a1EM3ncpml7IvUDY9xq5Q.jpg', '["https://aos-comment.amap.com/B0FFHQM58M/comment/20260307-27386ba591c96897a8b3f1ce-8a1EM3ncpml7IvUDY9xq5Q.jpg", "http://store.is.autonavi.com/showpic/9649f6c8f49ac9d563f0e77dea05f689", "http://store.is.autonavi.com/showpic/a0538d01b136803a8f37a8b22a1ebdca"]', '["免费开放", "校园设施", "适合跑步", "运动健康", "学生友好"]', 4.3, 0, 0, '北邮校园内的标准田径场，跑道、草坪、看台一应俱全，是晨跑和夜跑的最佳选择。', '这个体育场就在北邮校内，距离宿舍和教学楼都非常近，是学生们最常去的运动场所。标准的400米跑道，草坪维护良好，还有看台可以休息。无论是体育课测试、课后跑步还是晚上散步，都超级方便。晚上灯光充足，夜跑也很安全。最重要的是免费开放，对学生零门槛。', 1, NULL);
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_268', '北京师范大学邱季端体育馆', 'entertainment', '', 'place_001', 39.9581622, 116.3579455, '新街口外大街19号北京师范大学', 388, '¥¥', 26.0, '010-58808044', 'http://store.is.autonavi.com/showpic/fefc23a3dbb71c8a2290c12731d75e78', '["http://store.is.autonavi.com/showpic/fefc23a3dbb71c8a2290c12731d75e78", "http://store.is.autonavi.com/showpic/d0942b17ee8da0a219a73893acf2024e", "http://store.is.autonavi.com/showpic/12479f18252d3718a35adf5ca4ea1fb7"]', '["设施一流", "校内场馆", "运动健身", "性价比高", "适合比赛"]', 4.5, 0, 0, '北师大校内的现代化体育馆，设施一流，游泳馆和球类场地尤其受欢迎，是周边学生的运动乐园。', '邱季端体育馆是北师大最知名的运动地标，内部设施非常现代化。游泳馆水质清澈，有标准泳道；羽毛球和篮球场地弹性好，灯光专业。凭学生证可享受优惠，价格亲民。周末经常有校际比赛和活动，氛围热烈。虽然离北邮稍远，但值得专程前往。', 1, '推荐游泳馆');
