INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_270', '网鱼网咖(海淀枫蓝国际店)', 'entertainment', '', 'place_001', 39.9517824, 116.3507484, '西直门北大街32号院枫蓝国际购物中心B1层', 860, '¥¥', 41.0, '010-57517766', 'https://img.alicdn.com/imgextra/i2/O1CN01qMKzhk1xW9k4q8Wuj_!!6000000006450-0-tps-829-829.jpg', '["https://img.alicdn.com/imgextra/i2/O1CN01qMKzhk1xW9k4q8Wuj_!!6000000006450-0-tps-829-829.jpg", "https://aos-comment.amap.com/B0FFFG01O9/comment/67f6acbdbeb56ebeceebc7799f5cf5a6_2048_2048_80.jpg", "https://aos-comment.amap.com/B0FFFG01O9/comment/bd7c2f4d55991d5da360dded872bb549_2048_2048_80.jpg"]', '["电竞体验", "网速快", "环境舒适", "适合开黑", "学生友好"]', 4.7, 0, 0, '评分4.7的网咖，设备新、网速快，环境宽敞，是开黑和休闲的绝佳去处。', '网鱼网咖位于枫蓝国际购物中心地下一层，交通便利。店内装修时尚，电脑配置高，屏幕大，键盘鼠标手感好。分区合理，有普通区、电竞区和包间，适合不同需求。网速稳定，玩大型游戏毫无压力。还有饮料和小吃售卖。价格适中，人均41元，性价比高。', 1, '推荐电竞区体验');
