INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_281', '北体全生命周期运动健康管理中心(枫蓝店)', 'entertainment', '', 'place_001', 39.9515061, 116.3509311, '北太平庄街道西直门北大街32号院枫蓝国际B座811室', 885, '¥¥¥', 94.0, '17710785551', 'https://store.is.autonavi.com/showpic/44e4392b754344230168963b0499910a', '["https://store.is.autonavi.com/showpic/44e4392b754344230168963b0499910a", "https://aos-comment.amap.com/B0K06638CE/comment/content_media_external_file_26909_ss__1762557751228_09997686.jpg", "https://aos-comment.amap.com/B0K06638CE/comment/0feedback_sendimag_1748258174724_61489089.jpg"]', '["专业运动康复", "科学训练", "运动损伤", "体能提升", "环境舒适"]', 4.6, 0, 0, '北体大专业团队运营的健康管理中心，提供运动康复、体能训练等全方位服务。位于枫蓝国际，环境舒适，设备专业，是校园周边运动爱好者的宝藏去处。', '走进这里，仿佛进入了一个专业的运动康复殿堂。由北体大专业团队运营，从运动评估到个性化训练方案，每一步都科学严谨。店内环境明亮整洁，各种专业器械一应俱全。无论是运动损伤后的康复，还是想提升体能、塑形减脂，这里都能提供针对性指导。适合体育生、运动爱好者或久坐腰酸背痛的同学来体验。虽然人均不低，但专业度和效果绝对物超所值。', 0, '运动功能评估');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_282', '唱吧麦颂KTV(北京西直门枫蓝国际店)', 'entertainment', '', 'place_001', 39.9511349, 116.3510499, '北太平庄街道西直门北大街32号枫蓝国际购物中心2层', 923, '¥¥', 76.0, '010-62270612', 'http://store.is.autonavi.com/showpic/a952803ef7b31227a44651087144657c', '["http://store.is.autonavi.com/showpic/a952803ef7b31227a44651087144657c", "http://store.is.autonavi.com/query_pic?id=st77d091b5-b1e2-4e76-be7b-85696a809271&user=search&operate=original", "https://aos-comment.amap.com/B0FFG73BL3/comment/0feedback_sendimag_1749374600240_87640103.jpg"]', '["学生友好", "性价比高", "适合聚会", "氛围好", "交通便利"]', 4.6, 0, 0, '学生聚会必去的KTV！枫蓝国际二层，交通超方便。音效好、曲库全，包间氛围棒，还有学生优惠，性价比超高。', '唱吧麦颂是校园周边最受欢迎的KTV之一，位于枫蓝国际购物中心二楼，出校门步行几分钟就到。包间装修时尚，音响效果出色，曲库更新及时，流行、经典、老歌应有尽有。服务热情，还有各种套餐优惠，学生证还能打折！无论是生日趴、社团聚餐还是周末放松，这里都是绝佳选择。人均不到80元，唱到嗨玩到爽，性价比超高。', 1, '学生套餐');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_283', '北京师范大学教工之家', 'entertainment', 'billiard', 'place_001', 39.9614406, 116.3604848, '新街口外大街19号北京师范大学', 637, '¥', 18.0, '', 'http://store.is.autonavi.com/showpic/159a11fffe78996013fcf1342065659a', '["http://store.is.autonavi.com/showpic/159a11fffe78996013fcf1342065659a"]', '["校园情怀", "安静舒适", "价格亲民", "自习好去处", "放松心情"]', 4.4, 0, 0, '北师大校园内的宝藏休闲地！环境安静，价格亲民，是自习、聊天、放松的好去处。教工和学生都爱来，充满校园情怀。', '教工之家位于北师大校园内，是师生们课余放松的温馨角落。环境优雅，绿植环绕，书香与咖啡香交织。这里不仅有舒适的座椅，还有丰富的书籍和杂志，适合独自发呆、朋友小聚或安静自习。价格超级亲民，人均不到20元，就能享受一杯饮品和一段悠闲时光。作为校园内的休闲地标，它承载着无数北师大学子的青春记忆。', 1, NULL);
