INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_285', '云川台球(西直门店)', 'entertainment', '', 'place_001', 39.9479935, 116.3495262, '西直门北大街45-7号时代之光名苑底商地下1层', 1294, '¥¥', 38.0, '010-62228228', 'http://store.is.autonavi.com/showpic/7fa62c4f7b74a9240767dabaa88d6a5d', '["http://store.is.autonavi.com/showpic/7fa62c4f7b74a9240767dabaa88d6a5d", "http://store.is.autonavi.com/showpic/10492d7233851599725ef54173a0a176", "https://store.is.autonavi.com/showpic/9870edabe614fa0e6d0a2481ef142800"]', '["评分高", "环境好", "球台专业", "服务热情", "性价比高"]', 4.8, 0, 0, '评分高达4.8的台球圣地！环境高端，球台专业，服务到位。价格亲民，是同学切磋、休闲放松的绝佳去处。', '云川台球位于西直门时代之光名苑底商，虽然在地下1层，但环境非常棒。装修现代，灯光柔和，球台保养得很好，走球顺滑。还有独立包间，适合朋友小聚或比赛切磋。老板和服务员都很热情，会主动帮忙摆球。价格适中，人均不到40元，性价比超高。无论是台球高手还是新手，都能在这里找到乐趣。适合周末放松、社团活动或约会。', 0, '美式台球');
