INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_287', '鑫云端台球会所(四道口店)', 'entertainment', '', 'place_001', 39.9582698, 116.3397781, '京果商厦2号院2号楼B座2层101', 1183, '¥', 0.0, '13910535971;15501255999', 'https://store.is.autonavi.com/showpic/3d5bd670bb948cc4ee178d680720cf08', '["https://store.is.autonavi.com/showpic/3d5bd670bb948cc4ee178d680720cf08", "https://store.is.autonavi.com/showpic/5ae75c664ff38c225e3e0777cf084b63", "https://store.is.autonavi.com/showpic/0fd18b80a4ae0011c64e48a1feb49442"]', '["评分高", "空间宽敞", "价格实惠", "适合聚会", "氛围轻松"]', 4.7, 0, 0, '四道口附近的台球会所，评分4.7！环境宽敞，球桌多，价格实惠。适合学生组队来玩，享受台球乐趣。', '鑫云端台球会所位于京果商厦内，交通便利。店内空间很大，球桌数量多，不用担心排队等位。环境干净整洁，灯光柔和，球台保养得不错。价格亲民，人均几乎没有门槛，非常适合学生党。这里氛围轻松，适合朋友聚会、放松心情。无论是台球高手还是初学者，都能在这里享受击球的快乐。', 0, NULL);
