INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_289', '球爵台球俱乐部', 'entertainment', '', 'place_001', 39.9512071, 116.3547779, '文慧园路23号', 894, '¥', 0.0, '18510889513', 'https://aos-comment.amap.com/B0L2DH8VAL/comment/0feedback_sendimag_1773832401920_58878433.jpg', '["https://aos-comment.amap.com/B0L2DH8VAL/comment/0feedback_sendimag_1773832401920_58878433.jpg", "https://aos-comment.amap.com/B0L2DH8VAL/comment/4feedback_sendimag_1773832401922_43928046.jpg", "https://aos-comment.amap.com/B0L2DH8VAL/comment/content_media_external_file_100002717_1763861102709_54041632.jpg"]', '["环境整洁", "球台质量好", "价格实惠", "适合切磋", "氛围轻松"]', 4.5, 0, 0, '文慧园路附近的台球俱乐部，评分4.5！环境不错，球台质量好，价格实惠。是附近学生休闲娱乐的好选择。', '球爵台球俱乐部位于文慧园路，离学校不远。店内环境整洁，灯光舒适，球台保养得很好，走球顺畅。服务态度好，会主动帮忙摆球。价格非常实惠，人均几乎没有门槛，适合学生党。这里氛围轻松，适合朋友小聚、切磋球技。无论是台球新手还是老手，都能在这里找到乐趣。', 0, NULL);
