INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_291', '开心运动氧舱馆', 'entertainment', '', 'place_001', 39.9525648, 116.3598121, '志学路与文慧园路交叉口北160米', 908, '¥¥¥', 2275.0, '18511471852', 'https://aos-comment.amap.com/B0LGK1QHUQ/comment/content_media_external_file_498110_ss__1748312123736_75252429.jpg', '["https://aos-comment.amap.com/B0LGK1QHUQ/comment/content_media_external_file_498110_ss__1748312123736_75252429.jpg", "https://aos-comment.amap.com/B0LGK1QHUQ/comment/content_media_external_images_media_1000243597_ss__1765551121565_33525124.jpg", "https://aos-comment.amap.com/B0LGK1QHUQ/comment/content_media_external_file_498111_ss__1748312123734_21268891.jpg"]', '["高端体验", "科技感", "减压放松", "专业指导", "适合独处"]', 4.5, 0, 0, '高端运动氧舱馆，带你体验太空漫步般的运动新方式。高科技氧疗设备结合专业指导，缓解疲劳、提升状态，是学霸们课后充电的秘密基地。', '走进开心运动氧舱馆，仿佛踏入未来科技空间。馆内配备先进的低压氧舱设备，在模拟高原环境下运动，能有效提升心肺功能和燃脂效率。专业教练全程指导，根据你的体能定制训练计划。适合压力大、需要快速恢复的考研党或运动爱好者。虽然人均不低，但一场酣畅淋漓的氧舱运动，绝对是给身心的一次奢华投资。', 0, '高压氧舱体验');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_292', 'Kershoo元气岛·女性健身(西直门店)', 'entertainment', '', 'place_001', 39.9512085, 116.3512714, '西直门北大街32号院枫蓝国际中心B座F11层', 911, '¥¥', 81.0, '18931367984', 'https://aos-comment.amap.com/B0LRXL2Y8O/comment/file_media_Photo_116_IMG_1770119325_115_screenshot_20260203_194705_pn_1770119301552_05368644.jpg', '["https://aos-comment.amap.com/B0LRXL2Y8O/comment/file_media_Photo_116_IMG_1770119325_115_screenshot_20260203_194705_pn_1770119301552_05368644.jpg", "https://aos-comment.amap.com/B0LRXL2Y8O/comment/1422131B_3D9C_4FCD_87DC_E68616C7519D_L0_001_2000_150_1756188593089_57527307.jpg", "https://aos-comment.amap.com/B0LRXL2Y8O/comment/file_media_Photo_114_IMG_1770119308_113_screenshot_20260203_194648_pn_1770119301555_91647787.jpg"]', '["女性专属", "课程丰富", "私密性好", "环境温馨", "适合闺蜜"]', 4.5, 0, 0, '专为女性打造的元气健身空间，在西直门枫蓝国际B座11层等你。课程丰富、私密安全，用科学训练和温馨氛围助你遇见更美的自己。', 'Kershoo元气岛是一家专注于女性健身的精品馆，从入门到进阶课程一应俱全。店内装修粉嫩清新，配备专业女性健身器械，还有瑜伽、普拉提、搏击等多样课程。教练团队全是女性，沟通零障碍。适合闺蜜结伴或独自来撸铁，课后还能俯瞰西直门街景，心情超治愈。', 1, '元气燃脂课');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_293', '学院派健身游泳', 'entertainment', '', 'place_001', 39.9577868, 116.3466607, '北京城区学院派小区c座', 612, '¥¥¥', 2344.0, '13522973841', 'http://aos-cdn-image.amap.com/sns/ugccomment/ee8fa500-5112-4161-8e4e-8a801e71c240.jpg', '["http://aos-cdn-image.amap.com/sns/ugccomment/ee8fa500-5112-4161-8e4e-8a801e71c240.jpg", "http://store.is.autonavi.com/showpic/60519e89c513563b8aea6e10677ee9d7", "https://aos-comment.amap.com/B0FFHVDPHP/comment/22e6f78ebe087c50362baace805a1108_2048_2048_80.jpg"]', '["恒温泳池", "器械齐全", "环境高端", "专业教练", "适合健身达人"]', 4.3, 0, 0, '学院派小区里的高端健身游泳馆，室内恒温泳池和专业器械区一应俱全。环境高大上，适合追求品质的健身达人和游泳爱好者。', '学院派健身游泳馆藏在小区c座，是周边难得的高端运动空间。泳池常年恒温，水质清澈，适合课后畅游几圈解压。健身房器械齐全，从自由力量到有氧区应有尽有，还有私教一对一指导。环境宽敞明亮，更衣室干净舒适。适合想认真锻炼、不满足于基础运动的学生党。', 0, '恒温泳池畅游');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_294', '熙剧场(枫蓝国际购物中心店)', 'entertainment', '', 'place_001', 39.95151, 116.3497374, '西直门北大街32号院枫蓝国际购物中心4层', 916, '¥¥', 76.0, '010-82213287', 'http://store.is.autonavi.com/showpic/d8fbb32e2760b68a0f53ef9caf1f50c7', '["http://store.is.autonavi.com/showpic/d8fbb32e2760b68a0f53ef9caf1f50c7", "https://store.is.autonavi.com/showpic/db448123bee54fc50000002635362065?type=pic", "https://store.is.autonavi.com/showpic/c041a0dad2ed72170000002635282604?type=pic"]', '["文艺打卡", "沉浸式体验", "性价比高", "适合约会", "演出丰富"]', 4.5, 0, 0, '枫蓝国际里的沉浸式剧场，看一场话剧或脱口秀，让笑声冲散一天的疲惫。票价亲民，是校园周边的文艺社交新据点。', '熙剧场位于枫蓝国际购物中心四层，是集话剧、脱口秀、音乐会于一体的多元演艺空间。剧场虽不大，但声光效果极佳，观众席与舞台距离很近，沉浸感满分。经常有学生票和早鸟优惠，性价比超高。适合周末约上室友来看场喜剧，或者独自感受小众戏剧的魅力。', 1, '周末脱口秀');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_295', '谈小娱24h自助台球(杏坛路店)', 'entertainment', '', 'place_001', 39.9650131, 116.3544038, '北三环中路44号K座B1', 650, '¥¥', 131.0, '13263456623', 'https://aos-comment.amap.com/B0JGRS351B/headerImg/f958cbd9dbe9c6e4d6ff7b014e5dca5f_2048_2048_80.jpg', '["https://aos-comment.amap.com/B0JGRS351B/headerImg/f958cbd9dbe9c6e4d6ff7b014e5dca5f_2048_2048_80.jpg", "https://aos-comment.amap.com/B0JGRS351B/headerImg/5847c4c9751f96e1574e96786f814f4f_2048_2048_80.jpg", "https://aos-comment.amap.com/B0JGRS351B/headerImg/2a97de562230b32ee8e96cab5e8f3a54_2048_2048_80.jpg"]', '["24小时营业", "自助服务", "环境安静", "适合聚会", "夜猫子友好"]', 4.3, 0, 0, '24小时自助台球厅，深夜也能约朋友来一杆。智能计费、无人打扰，是夜猫子们的快乐星球。', '谈小娱24h自助台球厅藏在杏坛路地下一层，刷脸进门，全程自助。球桌质量专业，台尼平整，还配有智能计费系统，随玩随走。环境干净，有独立包厢，适合小组PK。深夜学习累了，或者周末想放松，这里都是绝佳选择，不用担心打烊时间。', 1, '中式八球体验');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_296', '北京邮电大学海淀校区篮球场', 'entertainment', '', 'place_001', 39.9613162, 116.3531536, '北太平庄街道西土城路10号北京邮电大学篮球场北侧学生餐厅3层', 238, '¥', 0.0, '', 'http://store.is.autonavi.com/showpic/24014bffa13c81e7e90da85c8ada3e83', '["http://store.is.autonavi.com/showpic/24014bffa13c81e7e90da85c8ada3e83"]', '["免费开放", "校园场地", "运动氛围好", "适合组队", "灯光充足"]', 4.0, 0, 0, '北邮校园内的标准篮球场，免费开放，是球友们挥洒汗水的热血主场。课后约场球，活力满满。', '北邮海淀校区篮球场位于学生餐厅三层，是校园里最热闹的运动角落之一。场地为标准塑胶地面，篮筐高度标准，灯光充足，晚上也能打球。完全免费，是学生党的福利。课余时间这里总是充满欢呼声和篮球撞击声，适合班级赛或自由组队。', 0, NULL);
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_297', 'ZT电竞(西直门店)', 'entertainment', '', 'place_001', 39.9501663, 116.3520601, '北京城区索家坟2号20幢四层ZT电竞(西直门店)', 1013, '¥¥', 0.0, '13161335618', 'https://store.is.autonavi.com/showpic/13e2814863cab5d60000002101814165?type=pic', '["https://store.is.autonavi.com/showpic/13e2814863cab5d60000002101814165?type=pic", "https://aos-comment.amap.com/B0M60CMK2B/comment/C4AE2345_DB25_4F92_B64E_AB305A9721D8_L0_001_1080_144_1772700649910_39184832.jpg", "https://store.is.autonavi.com/showpic/5a4cd2f0b10b655c0000000963148667?type=pic"]', '["电竞主题", "设备顶级", "适合开黑", "氛围酷炫", "学生聚集地"]', 4.5, 0, 0, '西直门附近的专业电竞馆，设备顶级，环境酷炫。和兄弟开黑、看比赛直播，这里就是电竞爱好者的天堂。', 'ZT电竞(西直门店)是周边电竞玩家的聚集地。馆内配备高端电脑和外设，网速飞快，座椅舒适。装修充满赛博朋克风，霓虹灯带和电竞椅营造出沉浸式对战氛围。还有独立包间，适合五人开黑。经常举办小型比赛，奖品丰厚。适合想体验专业电竞氛围的学生。', 1, '五黑包间体验');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_298', '北京师范大学网球场', 'entertainment', '', 'place_001', 39.959161, 116.3567045, '新街口外大街19号北京师范大学', 265, '¥', 0.0, '', 'uploads/images/surrounding/北京师范大学网球场.jpg', '[]', '["免费开放", "校园场地", "环境优美", "适合练习", "运动社交"]', 4.0, 0, 0, '北师大校园内的标准网球场，环境优美，是网球爱好者的免费天堂。周末来一场优雅的挥拍，享受运动乐趣。', '北京师范大学网球场坐落在校园内，场地维护良好，四周绿树环绕，打球时心情舒畅。场地为硬地，标准尺寸，免费对师生开放，校外人员也可能有机会。适合网球初学者练球，也适合高手切磋。课后或周末来这里打一场，既能锻炼身体又能结识球友。', 0, NULL);
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_299', '贤合居茶楼(天兆家园店)', 'entertainment', 'gym', 'place_001', 39.9509484, 116.3482633, '天兆家园东南门东南70米', 1024, '¥¥', 79.0, '13263118969', 'http://store.is.autonavi.com/showpic/54fe0f47c2c338fb791436dc29a6ee51', '["http://store.is.autonavi.com/showpic/54fe0f47c2c338fb791436dc29a6ee51", "https://aos-comment.amap.com/B0JKN9LV6I/headerImg/d342a6e52c304773bc13a226f0629f38_2048_2048_80.jpg", "http://store.is.autonavi.com/showpic/7b1ab7684e28c612ec8a70cfef9db30f"]', '["环境雅致", "适合自习", "品茶聊天", "私密包厢", "安静放松"]', 4.5, 0, 0, '天兆家园旁的清雅茶楼，古色古香，是品茶聊天、安静自习的宝藏地。茶香袅袅，时光慢下来。', '贤合居茶楼隐藏在小区东南门，环境雅致，充满中式韵味。店内设有多个包厢，私密性好，适合小组讨论或安静阅读。茶品种类丰富，从龙井到普洱都有，还有精致茶点。服务贴心，可以续水。适合想摆脱图书馆喧嚣、找个安静地方学习或和朋友谈心的学生。', 1, '龙井绿茶');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_300', '四个朋友·自助棋牌(海淀枫蓝国际店)', 'entertainment', '', 'place_001', 39.9515197, 116.3511656, '西直门北大街32号院2号楼5层511', 879, '¥¥', 50.0, '18513806876;4000017788', 'https://store.is.autonavi.com/showpic/718b0d7b36e996150a3385590e26da5f', '["https://store.is.autonavi.com/showpic/718b0d7b36e996150a3385590e26da5f"]', '["自助棋牌", "适合聚会", "私密空间", "性价比高", "桌游友好"]', 4.4, 0, 0, '枫蓝国际里的自助棋牌室，和室友组局搓麻、打狼人杀，欢乐不停。智能计费，私密空间，是聚会首选。', '四个朋友·自助棋牌室位于枫蓝国际五层，装修温馨现代。房间配备自动麻将机、桌游道具等，全程自助，无人打扰。适合4-6人小团体聚会，周末约上同学来搓几圈，或者玩桌游，氛围超棒。价格按小时计费，性价比高，还有学生优惠。', 1, '自动麻将体验');
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_301', '呖咕呖咕 24H 自助棋牌社(西直门店)', 'entertainment', '', 'place_001', 39.9513281, 116.3509231, '北京城区枫蓝国际购物中心B座11层1110室', 905, '¥¥', 42.0, '15601085713', 'https://aos-comment.amap.com/B0LUACJ7D2/comment/content_media_external_file_210448_ss__1756556110458_43855334.jpg', '["https://aos-comment.amap.com/B0LUACJ7D2/comment/content_media_external_file_210448_ss__1756556110458_43855334.jpg", "https://aos-comment.amap.com/B0LUACJ7D2/comment/content_media_external_file_21172_1756556110453_12070747.jpg", "https://aos-comment.amap.com/B0LUACJ7D2/comment/62B206DD_B079_4E01_94A1_D4ED77A3D37B_L0_001_1500_200_1763928426746_65724686.jpg"]', '["24小时营业", "学生友好", "性价比高", "适合聚会"]', 4.4, 0, 0, '呖咕呖咕24H自助棋牌社，西直门学霸们的深夜放松据点！24小时不打烊，随时组局搓麻，环境舒适又私密，人均仅42元，性价比爆棚！', '位于枫蓝国际B座11层，这家棋牌社主打24小时自助服务，让你告别时间束缚。店内装修现代简约，包间宽敞明亮，隔音效果超棒，适合三五好友通宵鏖战。自助扫码开台，全程无打扰，社恐福音！距离北师大仅905米，步行即达，是课后解压、周末小聚的绝佳选择。', 0, NULL);
