INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_305', '北京师范大学体育场', 'entertainment', '', 'place_001', 39.9596635, 116.3577127, '新街口外大街19号北京师范大学', 354, '¥', 0.0, '010-58808044', 'https://store.is.autonavi.com/showpic/a9fadb199f658d55b585ca26f56b2d98', '["https://store.is.autonavi.com/showpic/a9fadb199f658d55b585ca26f56b2d98", "http://store.is.autonavi.com/showpic/32f36c8cc608ac32690f7eca006ce70c"]', '["免费开放", "校园运动", "环境舒适"]', 4.0, 0, 0, '北京师范大学体育场，校园内免费开放的天然草坪操场！跑步、踢球、散步，课后放松的绝佳去处，人均0元享运动快乐。', '就在北师大校园内，距离宿舍区仅354米。体育场拥有标准400米跑道和真草草坪，晨跑夜跑都超舒服。傍晚时分，这里满是跑步的学生和遛弯的教职工，氛围感拉满。适合一个人放空，也适合组队踢足球。完全免费开放，是校园生活最接地气的运动场所。', 0, NULL);
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_306', '小铁24h无人自助台球(北京中海学院派店)', 'entertainment', '', 'place_001', 39.9574398, 116.3460719, '学院南路15号院10号楼2层0201(学院派物美超市上二层)', 671, '¥', 0.0, '13001038187', 'http://store.is.autonavi.com/showpic/538453ce38ab305953dae96e5e5b0805', '["http://store.is.autonavi.com/showpic/538453ce38ab305953dae96e5e5b0805"]', '["24小时营业", "无人自助", "学生友好"]', 4.2, 0, 0, '小铁24h无人自助台球(北京中海学院派店)，24小时不打烊的台球天堂！无人自助超自由，课后随时来一杆，人均0元起！', '位于学院派物美超市二层，这家台球厅主打无人自助模式，扫码开台、全程无干扰。环境现代，球桌保养良好，灯光专业。24小时营业，深夜想打球也能来。距离校园仅671米，步行10分钟。价格按小时计费，学生党也能轻松承担，是台球爱好者的秘密基地。', 1, NULL);
