INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_308', '北京师范大学篮球场', 'entertainment', '', 'place_001', 39.9591461, 116.3580162, '新街口外大街19号北京师范大学', 376, '¥', 0.0, '010-58806183', 'https://store.is.autonavi.com/showpic/eb5baf9129399d45dba27e37e5827a29', '["https://store.is.autonavi.com/showpic/eb5baf9129399d45dba27e37e5827a29", "http://store.is.autonavi.com/showpic/53bb51dca310502a4d1194ba", "http://store.is.autonavi.com/showpic/53bb51dca310502a4d1194be"]', '["免费开放", "校园运动", "适合篮球"]', 4.0, 0, 0, '北京师范大学篮球场，校园内的热血篮球圣地！免费开放，随时约球，课后挥洒汗水的绝佳场地！', '位于北师大校园内，距离宿舍376米。篮球场为标准室外场地，地面平整，篮筐维护良好。傍晚时分灯光亮起，打球氛围超棒。这里经常有学生自发组织的3v3比赛，想加入随时可以。完全免费，自带球即可，是篮球爱好者的日常打卡地。', 0, NULL);
