INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_322', '京师心悦酒店(北师大店)', 'hotel', 'hotel', 'place_001', 39.960063, 116.3648383, '新街口外大街8号综合楼3楼', 963, '¥¥¥', 0.0, '010-88365936;010-88365968', 'https://store.is.autonavi.com/showpic/4ca49fd3446dce2c7c812ffc1ad10951', '["https://store.is.autonavi.com/showpic/4ca49fd3446dce2c7c812ffc1ad10951", "https://store.is.autonavi.com/showpic/5c9b239cb23b3d2d9896ec60c968703d", "https://store.is.autonavi.com/showpic/8527c5f31d4a465140e63c2c1bc075b9"]', '["学生友好", "安静舒适", "高评分", "周边便利"]', 4.8, 0, 0, '京师心悦酒店位于北师大旁，4.8分近乎满分，温馨如家。三楼综合楼位置安静，适合学子临时休息或亲友小住。', '酒店装修简约现代，房间干净无异味，隔音效果好。前台提供免费热水和行李寄存，服务贴心。离北师大东门仅几步之遥，周边小吃摊林立，深夜也能觅食。适合考研党、社团活动后休息或家长探校。', 0, NULL);
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_323', '时宿酒店(北京邮电大学西直门地铁站店)', 'hotel', 'hotel', 'place_001', 39.951859, 116.3548447, '文慧园北路9号今典花园9号楼C座', 823, '¥¥¥', 0.0, '010-87002888;15321037654', 'https://store.is.autonavi.com/showpic/2c181c7aafa7f8782801f0289d4a1eb5', '["https://store.is.autonavi.com/showpic/2c181c7aafa7f8782801f0289d4a1eb5", "https://store.is.autonavi.com/showpic/1a045734442ca1d3512377d767d05512", "https://store.is.autonavi.com/showpic/61e99dbbdcc2242faa215a74f1b0d644"]', '["时尚设计", "交通便利", "智能设施", "学生友好"]', 4.7, 0, 0, '时宿酒店靠近西直门地铁站，4.7分高口碑。房间设计时尚，学生党聚会或假期住宿的好选择，步行到北邮只需十分钟。', '酒店位于今典花园小区内，环境安全安静。客房配有智能马桶和投影仪，年轻人会喜欢。前台提供免费矿泉水，退房快捷。适合小组项目熬夜、毕业季聚会或周末出游中转。附近有超市和奶茶店，生活便利。', 0, NULL);
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_324', '汉庭酒店(北京师范大学店)', 'hotel', '', 'place_001', 39.9530902, 116.3595504, '志强北园小区22号楼', 848, '¥¥¥', 0.0, '010-82582139', 'https://store.is.autonavi.com/showpic/3136b325c74a514a5c83a1d21e483767', '["https://store.is.autonavi.com/showpic/3136b325c74a514a5c83a1d21e483767", "https://store.is.autonavi.com/showpic/8a1ac0ecce19d196cbed61653f5172ea", "https://store.is.autonavi.com/showpic/11aff63f15a6bf952f88ed7a59fe1047"]', '["经济实惠", "连锁品牌", "干净整洁", "24小时服务"]', 4.7, 0, 0, '汉庭酒店北师大店，连锁品质有保障。4.7分，位于志强北园小区，性价比高，是学生和家长的经济之选。', '汉庭一贯的干净整洁，房间虽小但布局合理。前台24小时服务，提供免费WiFi和自助洗衣。小区内安静，适合自习后休息。离北师大西门近，周边有食堂和便利店。适合预算有限的考研党、实习住宿或短期停留。', 0, NULL);
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_325', '如家UP华驿精选酒店(北京北站西直门地铁站店)', 'hotel', '', 'place_001', 39.9541128, 116.3485763, '西直门北大街乙11号', 709, '¥¥¥', 0.0, '010-62253038', 'https://store.is.autonavi.com/showpic/b01d2b614897eb138a8c9b8689a16e9e', '["https://store.is.autonavi.com/showpic/b01d2b614897eb138a8c9b8689a16e9e", "https://store.is.autonavi.com/showpic/45eac861db46ce8b3f54a064473348d3", "https://store.is.autonavi.com/showpic/03c39ed219a4ccb326e427e2edcd89af"]', '["交通枢纽", "便捷入住", "新装修", "学生友好"]', 4.6, 0, 0, '如家UP华驿精选酒店，4.6分，靠近西直门地铁站和北京北站。房间简约实用，学生出游或赶早班车首选。', '酒店刚装修不久，设施较新。房间虽紧凑但干净，配有免费瓶装水和茶包。前台服务效率高，入住退房不拖沓。适合赶火车、考试前夜或社团活动后临时落脚。周边有快餐店和便利店，深夜也能补给。', 0, NULL);
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_326', '北京童话国风民宿(恭王府店)', 'hotel', 'hotel', 'place_001', 39.9510422, 116.3625519, '五月华庭路与文慧园路交叉口西南40米', 1185, '¥¥¥', 0.0, '17812276057', 'https://store.is.autonavi.com/showpic/5df8a455f5631b21a361a6920d93e90a', '["https://store.is.autonavi.com/showpic/5df8a455f5631b21a361a6920d93e90a", "https://store.is.autonavi.com/showpic/04d5e340a52f42f6e4f8916a62c1a54a", "https://store.is.autonavi.com/showpic/f966359917a6e7d25f03c5d2a66e449c"]', '["国风主题", "拍照打卡", "文艺氛围", "高评分", "民宿体验"]', 4.9, 0, 0, '北京童话国风民宿，4.9分近乎满分。国风装修惊艳，适合拍照打卡，给校园生活增添文艺气息。', '民宿以国风为主题，房间内挂有字画、摆放瓷器，氛围感十足。公共区域有茶室和汉服体验区，适合闺蜜聚会或情侣约会。老板热情，会推荐周边胡同游路线。离恭王府景点近，周末可顺便游玩。适合想逃离宿舍、体验别样生活的同学。', 0, NULL);
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_327', '北邮锦江酒店', 'hotel', '', 'place_001', 39.9631707, 116.3490422, '西土城路10号(蓟门桥地铁站D口步行300米)', 588, '¥¥¥', 0.0, '010-52810888;010-62258866', 'http://store.is.autonavi.com/showpic/b9b10d0ec57a9e6d25f370c3bf7896ed', '["http://store.is.autonavi.com/showpic/b9b10d0ec57a9e6d25f370c3bf7896ed", "http://store.is.autonavi.com/showpic/ddbc199d86b91d8e159c33e930bcf251", "http://store.is.autonavi.com/showpic/8b6f6d01fa13efcdcc57e24dae622d09"]', '["高端舒适", "自助早餐", "学术接待", "宽敞房间"]', 4.5, 0, 0, '北邮锦江酒店，与北邮科技大厦同属一片区域，4.5分。定位高端一些，适合重要接待或犒劳自己。', '酒店大堂气派，房间面积大，配有浴缸和落地窗。早餐自助丰富，有中西式选择。服务专业，适合家长来访、毕业典礼或学术会议住宿。离校园极近，步行可达操场和食堂。价格略高但物有所值。', 0, NULL);
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_328', '全季酒店(北京中关村学院南路店)', 'hotel', '', 'place_001', 39.9583757, 116.3449451, '学院南路15号院5号楼', 743, '¥¥¥', 0.0, '010-61196900;17777874087', 'https://store.is.autonavi.com/showpic/953a84004e73b373de5254e365336650', '["https://store.is.autonavi.com/showpic/953a84004e73b373de5254e365336650", "https://store.is.autonavi.com/showpic/a08d26850cf7d2e341eedf58a7629809", "https://store.is.autonavi.com/showpic/8d30ff16118e6e1714a333981287f9fd"]', '["日式简约", "安静舒适", "办公友好", "连锁品质"]', 4.6, 0, 0, '全季酒店中关村学院南路店，4.6分。全季一贯的简约日式风格，干净清爽，学生党自习或实习的好去处。', '房间内原木色装修，配有加厚床垫和独立办公桌。前台提供免费咖啡和茶饮，公共区域有书吧。适合考研冲刺、实习过渡或周末放松。周边有高校聚集，学术氛围浓。交通便利，公交直达中关村。', 0, NULL);
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_329', '启点电竞酒店(西直门北京北站店)', 'hotel', 'hotel', 'place_001', 39.9474954, 116.3495592, '西直门北大街45号时代之光名苑2号楼底商', 1346, '¥¥¥', 0.0, '010-82229668;18601018331', 'https://store.is.autonavi.com/showpic/18b1ddf29bc493776261117e258cd95b', '["https://store.is.autonavi.com/showpic/18b1ddf29bc493776261117e258cd95b", "https://store.is.autonavi.com/showpic/aa43e099c7745d138b8bac1df3f42e85", "https://store.is.autonavi.com/showpic/7d09f602b66c6526be040dee92b29a89"]', '["电竞主题", "开黑圣地", "高配置", "适合聚会", "满分评分"]', 5.0, 0, 0, '启点电竞酒店西直门店，5.0分满分！电竞主题，配备高端电脑，适合宿舍开黑或社团电竞比赛。', '房间内配有RTX 4070显卡和165Hz显示器，电竞椅舒适。双人、三人间可选，支持联机。前台提供零食和饮料售卖，可外卖到房。适合周末通宵、社团团建或生日派对。隔音好，不会吵到别人。注意提前预订，很抢手。', 1, NULL);
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_330', '漫心酒店(北京西直门店)', 'hotel', 'hotel', 'place_001', 39.9495651, 116.3528856, '索家坟20号院5号楼', 1073, '¥¥¥', 0.0, '010-61198158', 'https://store.is.autonavi.com/showpic/a30e70ed118437c965200a7143b13fd6', '["https://store.is.autonavi.com/showpic/a30e70ed118437c965200a7143b13fd6", "https://store.is.autonavi.com/showpic/9962c5462ab274559e6bab16d5a72af3", "https://store.is.autonavi.com/showpic/ca65ebde34c09959d7fb5d26f0678f08"]', '["智能酒店", "设计感", "浪漫氛围", "高评分", "交通便利"]', 4.8, 0, 0, '漫心酒店西直门店，4.8分高评分。设计感强，房间有智能语音控制，给校园生活加点科技感。', '酒店装修现代轻奢，房间内配有智能音箱和电动窗帘。前台服务热情，提供免费欢迎水果。离西直门地铁站不远，交通便利。适合约会、生日庆祝或周末放松。周边有商场和电影院，吃喝玩乐一站式。', 0, NULL);
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_331', '如宜酒店(中关村学院南路店)', 'hotel', '', 'place_001', 39.957298, 116.3465919, '学院南路15号院10号楼2层', 634, '¥¥', 0.0, '010-62269695', 'https://store.is.autonavi.com/showpic/93f75febdddbaab1b753b8f6deec82a7', '["https://store.is.autonavi.com/showpic/93f75febdddbaab1b753b8f6deec82a7", "https://store.is.autonavi.com/showpic/c8f2012a6330bd74c1202ac3c59d7ce2", "https://store.is.autonavi.com/showpic/838e04f8ed6e3a56612f5ad206e88b91"]', '["学生友好", "位置便利", "干净舒适", "性价比高", "适合家长来访"]', 4.5, 0, 0, '紧邻中关村学院南路，如宜酒店以温馨舒适的房间和便捷的地理位置，成为学生和家长探访校园的理想下榻地。干净整洁的环境与贴心服务，让你在忙碌的校园生活外找到一份宁静。', '如宜酒店位于学院南路核心地段，步行几分钟即可到达校园，非常适合学生家长来访或同学聚会后留宿。酒店内部装修简约现代，房间虽不大但布置得十分温馨，床品干净柔软，隔音效果良好。前台服务热情周到，办理入住高效快捷。酒店周边餐饮选择丰富，出门就有便利店和小吃店，生活便利性极高。无论是周末短住还是考试周前的安静复习，这里都能提供舒适的休憩空间。', 0, NULL);
