INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_351', '北京邮电大学海淀校区内部地面停车场', 'transport', '', 'place_001', 39.9613284, 116.352391, '西土城路10号北京邮电大学(海淀校区)', 258, '¥', 0.0, '', 'uploads/images/surrounding/北京邮电大学海淀校区内部地面停车场.jpg', '[]', '["校内停车", "师生便利", "24小时监控", "步行可达"]', 0.0, 0, 0, '校内最方便的停车选择，紧邻教学楼和宿舍区，适合有车一族师生日常停放。', '作为北京邮电大学内部的地面停车场，这里距离教学楼和宿舍区步行仅需几分钟，是校内师生驾车出行的首选。车位相对充足，但早晚高峰时段可能需排队。环境整洁，管理规范，提供24小时监控保障车辆安全。适合日常上课、实验或短时办事停车，也方便周末离校出行。虽然评分暂无，但作为校内配套，实用性和便利性极高。', 0, NULL);
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_352', '杏坛路南口(公交站)', 'transport', '', 'place_001', 39.9571223, 116.3551505, '510路;579路', 266, '¥', 0.0, '', 'https://aos-comment.amap.com/BV10008062/headerImg/e7faaf2e55e0dbfef9c6035fea291c23_2048_2048_80.jpg', '["https://aos-comment.amap.com/BV10008062/headerImg/e7faaf2e55e0dbfef9c6035fea291c23_2048_2048_80.jpg", "https://aos-comment.amap.com/BV10008062/headerImg/a86f3f607234c22c81a9cd0aa6e7d678_2048_2048_80.jpg", "https://aos-comment.amap.com/BV10008062/comment/176672536266_1766725384437_29105592.jpg"]', '["公交枢纽", "班次密集", "通勤便利", "学生友好"]', 0.0, 0, 0, '北邮附近核心公交枢纽，多条线路直达，轻松连接校园与城市各个角落。', '杏坛路南口公交站是北邮学子出行的常用站点，510路、579路等多条线路交汇，可快速前往西直门、动物园等商圈。站台设有电子显示屏，实时更新到站信息，等车不焦虑。早高峰班次密集，适合赶课或实习通勤。虽然距离校园步行约5分钟，但站点位置明显，周边还有共享单车接驳，整体出行体验流畅。', 0, NULL);
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_353', '出租车停车位', 'transport', '', 'place_001', 39.9567894, 116.353806, '学院南路', 269, '¥¥', 0.0, '', 'http://store.is.autonavi.com/showpic/53aa3f32a3106c892e6dd584', '["http://store.is.autonavi.com/showpic/53aa3f32a3106c892e6dd584"]', '["打车便捷", "夜间可用", "学生友好", "位置便利"]', 0.0, 0, 0, '学院南路便捷打车点，随叫随到，适合深夜回校或赶早课时使用。', '位于学院南路的出租车停车位，是北邮周边打车的主要接驳点之一。位置靠近校园西门，步行仅需3分钟，方便携带行李或夜间出行。虽然无固定设施，但车流量较大，早晚高峰和深夜时段容易打到车。适合周末出游、实习下班或紧急出行场景，尤其适合不想挤公交的懒人学生。', 0, NULL);
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_354', '出租车扬招站', 'transport', '', 'place_001', 39.9567813, 116.3538818, '学院南路北侧北京市明光中学门西侧', 270, '¥¥', 0.0, '', 'uploads/images/surrounding/出租车扬招站.jpg', '[]', '["官方站点", "安全可靠", "随叫随到", "学生友好"]', 0.0, 0, 0, '明光中学门西侧的官方扬招站，出租车随停随走，出行省心省力。', '作为官方设立的出租车扬招站，这里标识清晰，出租车停靠规范，避免了随意拦车的不确定性。站点位于学院南路北侧，距北邮校园约5分钟步行，周边有路灯和监控，夜间使用也安全。适合雨天、赶时间或携带重物时使用，尤其适合不想等公交或挤地铁的师生。虽然功能简单，但实用性满分。', 0, NULL);
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_355', '学院南路辅路-路侧停车场', 'transport', '', 'place_001', 39.9567432, 116.3526232, '学院南路与文慧园西路交叉口东60米', 286, '¥', 0.0, '', 'uploads/images/surrounding/学院南路辅路-路侧停车场.jpg', '[]', '["临时停车", "价格实惠", "接送便利", "学生友好"]', 0.0, 0, 0, '学院南路辅路临时停车位，方便接送学生或短时办事，性价比高。', '学院南路辅路的路侧停车场，紧邻北邮校园东侧，提供多个临时停车位。位置临近文慧园西路交叉口，步行到校约4分钟，适合家长接送或短时办事。车位按小时计费，价格亲民，且周边有便利店和餐饮店，停车后步行可达。虽然无专人看管，但路段相对安静，安全性尚可。适合临时停靠而非长期停放。', 0, NULL);
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_356', '北国剧场停车场', 'transport', '', 'place_001', 39.961189, 116.3559356, '新街口外大街19号', 298, '¥¥', 0.0, '', 'uploads/images/surrounding/北国剧场停车场.jpg', '[]', '["剧场配套", "停车便利", "文化活动", "步行可达"]', 0.0, 0, 0, '北国剧场配套停车场，看演出或办事时方便停车，距离校园不远。', '位于新街口外大街19号的北国剧场停车场，是周边文化活动的配套停车设施。距离北邮校园步行约5分钟，适合来剧场看演出或参加活动时使用。车位数量中等，周末或演出日可能紧张，但平时空位较多。环境干净，有专人引导，安全性高。虽然非校内专属，但作为校外补充停车点，对学生和教职工都很实用。', 0, NULL);
INSERT INTO `spot_surrounding` (`id`, `name`, `type`, `sub_type`, `place_id`, `lat`, `lng`, `address`, `distance_meters`, `price_range`, `avg_cost`, `phone`, `image`, `images`, `tags`, `rating`, `rating_count`, `click_count`, `description`, `detail_description`, `student_discount`, `must_try`) VALUES ('sr_001_357', '北京邮电大学南门(公交站)', 'transport', '', 'place_001', 39.9565827, 116.3522838, '16路;331路;620路;645路;92路;专168路', 312, '¥', 0.0, '', 'https://store.is.autonavi.com/showpic/7d51515dae74f4590000002437914614?type=pic', '["https://store.is.autonavi.com/showpic/7d51515dae74f4590000002437914614?type=pic", "https://aos-comment.amap.com/BV09045875/comment/4c52673c8799361731527aadd90e4a11_2048_2048_80.jpg", "https://aos-comment.amap.com/BV09045875/comment/content_media_external_images_media_1000103961_ss__1731972076854_13161896.jpg"]', '["公交枢纽", "线路丰富", "通勤便利", "学生友好"]', 0.0, 0, 0, '北邮南门核心公交站，多条线路直达西直门、蓟门桥等地，出行首选。', '北京邮电大学南门公交站是校园周边最重要的公交枢纽之一，16路、331路、620路、645路、92路、专168路等多条线路在此交汇。站点紧邻南门，出校即可上车，覆盖西直门、动物园、蓟门桥等热门方向。早高峰班次密集，适合通勤上课；晚班车较晚，满足夜间回校需求。候车亭有遮阳棚和座椅，等车体验舒适。', 0, NULL);
